CREATE OR REPLACE FUNCTION "public"."_mercury_raw_debit_card_id_lower"("p_raw" "jsonb") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT nullif(
    lower(trim(coalesce(
      p_raw #>> '{details,debitCardInfo,id}',
      p_raw #>> '{debitCardInfo,id}',
      ''
    ))),
    ''
  );
$$;


