--
-- Name: _pay_staff_bulk_insert_user_time_off_row("uuid", "date", "date", "text", "date", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_pay_staff_bulk_insert_user_time_off_row"("p_uid" "uuid", "p_start_date" "date", "p_end_date" "date", "p_note" "text", "p_today" "date", "p_should_sync" boolean) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sync_err text;
BEGIN
  INSERT INTO public.user_time_off (user_id, start_date, end_date, kind, note)
  VALUES (p_uid, p_start_date, p_end_date, 'unpaid', p_note);

  IF p_should_sync THEN
    BEGIN
      PERFORM public.sync_salary_clock_sessions_for_user_day(p_uid, p_today);
    EXCEPTION
      WHEN OTHERS THEN
        v_sync_err := SQLERRM;
    END;
  END IF;

  IF v_sync_err IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'sync_warning', v_sync_err);
  END IF;
  RETURN jsonb_build_object('ok', true);
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'message', SQLERRM);
END;
$$;


