--
-- Name: _replace_mercury_transaction_invoice_links("uuid", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_replace_mercury_transaction_invoice_links"("p_mercury_transaction_id" "uuid", "p_invoice_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
  v_ids uuid[] := COALESCE(p_invoice_ids, ARRAY[]::uuid[]);
BEGIN
  -- Validate every invoice exists before mutating.
  FOREACH v_id IN ARRAY v_ids LOOP
    IF NOT EXISTS (SELECT 1 FROM public.supply_house_invoices si WHERE si.id = v_id) THEN
      RAISE EXCEPTION '_replace_mercury_transaction_invoice_links: invalid invoice %', v_id;
    END IF;
  END LOOP;

  DELETE FROM public.mercury_transaction_supply_house_invoice_links
  WHERE mercury_transaction_id = p_mercury_transaction_id;

  IF array_length(v_ids, 1) IS NULL THEN
    RETURN;
  END IF;

  INSERT INTO public.mercury_transaction_supply_house_invoice_links (
    mercury_transaction_id,
    invoice_id,
    created_by
  )
  SELECT p_mercury_transaction_id, d.invoice_id, auth.uid()
  FROM (SELECT DISTINCT unnest(v_ids) AS invoice_id) d;
END;
$$;


ALTER FUNCTION "public"."_replace_mercury_transaction_invoice_links"("p_mercury_transaction_id" "uuid", "p_invoice_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: add_collect_payment_fixture_from_job_book("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."add_collect_payment_fixture_from_job_book"("p_job_id" "uuid", "p_job_book_entry_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
  v_entry record;
  v_job_st uuid;
  v_next_seq int;
  v_rev numeric;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('error', 'not_authenticated');
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = v_uid;
  IF v_role IS NULL OR v_role NOT IN ('subcontractor', 'helpers') THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger_team_members jtm
    INNER JOIN public.jobs_ledger jl ON jl.id = jtm.job_id
    WHERE jtm.user_id = v_uid
      AND jl.id = p_job_id
      AND jl.status = 'ready_to_bill'
  ) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  SELECT b.service_type_id INTO v_job_st
  FROM public.jobs_ledger jl
  LEFT JOIN public.bids b ON b.id = jl.bid_id
  WHERE jl.id = p_job_id;

  SELECT jbe.id, jbe.work_label, jbe.unit_cost, jbe.service_type_id
  INTO v_entry
  FROM public.job_book_entries jbe
  WHERE jbe.id = p_job_book_entry_id;

  IF v_entry.id IS NULL THEN
    RETURN jsonb_build_object('error', 'job_book_entry_not_found');
  END IF;

  IF v_entry.service_type_id IS NOT NULL
     AND (v_job_st IS DISTINCT FROM v_entry.service_type_id) THEN
    RETURN jsonb_build_object('error', 'job_book_entry_service_type_mismatch');
  END IF;

  SELECT COALESCE(MAX(f.sequence_order), -1) + 1 INTO v_next_seq
  FROM public.jobs_ledger_fixtures f
  WHERE f.job_id = p_job_id;

  INSERT INTO public.jobs_ledger_fixtures (
    job_id,
    name,
    count,
    line_unit_price,
    line_description,
    sequence_order
  ) VALUES (
    p_job_id,
    trim(v_entry.work_label),
    1,
    ROUND(v_entry.unit_cost::numeric, 2),
    NULL,
    v_next_seq
  );

  SELECT ROUND(COALESCE(SUM(
    CASE
      WHEN trim(COALESCE(f.name, '')) = '' THEN 0::numeric
      ELSE
        (CASE WHEN f.count > 0 THEN f.count::numeric ELSE 1::numeric END)
        * COALESCE(f.line_unit_price, 0::numeric)
    END
  ), 0::numeric), 2)
  INTO v_rev
  FROM public.jobs_ledger_fixtures f
  WHERE f.job_id = p_job_id;

  UPDATE public.jobs_ledger jl
  SET revenue = v_rev
  WHERE jl.id = p_job_id;

  RETURN jsonb_build_object('ok', true, 'revenue', v_rev);
END;
$$;


ALTER FUNCTION "public"."add_collect_payment_fixture_from_job_book"("p_job_id" "uuid", "p_job_book_entry_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "add_collect_payment_fixture_from_job_book"("p_job_id" "uuid", "p_job_book_entry_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
