--
-- Name: approve_clock_sessions("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."approve_clock_sessions"("p_session_ids" "uuid"[]) RETURNS TABLE("approved_count" integer, "error_message" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_approved int := 0;
  v_session RECORD;
  v_hours numeric;
  v_to_sync RECORD;
  v_pay boolean;
  v_person_id uuid;
BEGIN
  v_pay :=
    public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant();

  FOR v_session IN
    SELECT cs.id, cs.user_id, cs.clocked_in_at, cs.clocked_out_at, cs.work_date, trim(u.name) AS person_name, cs.job_ledger_id, cs.bid_id
    FROM public.clock_sessions cs
    JOIN public.users u ON u.id = cs.user_id
    WHERE cs.id = ANY(p_session_ids)
      AND cs.clocked_out_at IS NOT NULL
      AND cs.approved_at IS NULL
      AND cs.rejected_at IS NULL
  LOOP
    IF NOT v_pay THEN
      IF NOT public.is_team_lead_for_member(auth.uid(), v_session.user_id) THEN
        RETURN QUERY SELECT 0, 'Access denied'::text;
        RETURN;
      END IF;
    END IF;

    IF v_session.person_name IS NULL OR v_session.person_name = '' THEN
      RETURN QUERY SELECT 0, ('User has no name for session ' || v_session.id::text)::text;
      RETURN;
    END IF;

    v_hours := EXTRACT(EPOCH FROM (v_session.clocked_out_at - v_session.clocked_in_at)) / 3600.0;
    IF v_hours <= 0 THEN
      CONTINUE;
    END IF;

    v_person_id := public.resolve_pay_person_id_from_clock_user(v_session.user_id, v_session.person_name);

    INSERT INTO public.people_hours (person_name, work_date, hours, entered_by, person_id)
    VALUES (v_session.person_name, v_session.work_date, v_hours, auth.uid(), v_person_id)
    ON CONFLICT (person_name, work_date) DO UPDATE SET
      hours = public.people_hours.hours + EXCLUDED.hours,
      entered_by = EXCLUDED.entered_by,
      person_id = COALESCE(public.people_hours.person_id, EXCLUDED.person_id);

    UPDATE public.clock_sessions
    SET approved_at = NOW(), approved_by = auth.uid(),
        revoked_at = NULL, revoked_by = NULL
    WHERE id = v_session.id;

    v_approved := v_approved + 1;
  END LOOP;

  FOR v_to_sync IN
    SELECT DISTINCT trim(u.name) AS person_name, cs.work_date
    FROM public.clock_sessions cs
    JOIN public.users u ON u.id = cs.user_id
    WHERE cs.id = ANY(p_session_ids)
      AND cs.job_ledger_id IS NOT NULL
      AND trim(u.name) IS NOT NULL
      AND trim(u.name) != ''
  LOOP
    PERFORM public.sync_crew_jobs_from_clock(v_to_sync.person_name, v_to_sync.work_date);
  END LOOP;

  FOR v_to_sync IN
    SELECT DISTINCT trim(u.name) AS person_name, cs.work_date
    FROM public.clock_sessions cs
    JOIN public.users u ON u.id = cs.user_id
    WHERE cs.id = ANY(p_session_ids)
      AND cs.bid_id IS NOT NULL
      AND trim(u.name) IS NOT NULL
      AND trim(u.name) != ''
  LOOP
    PERFORM public.sync_crew_bids_from_clock(v_to_sync.person_name, v_to_sync.work_date);
  END LOOP;

  RETURN QUERY SELECT v_approved, NULL::text;
END;
$$;


ALTER FUNCTION "public"."approve_clock_sessions"("p_session_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "approve_clock_sessions"("p_session_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."approve_clock_sessions"("p_session_ids" "uuid"[]) IS 'Approve clock sessions and merge hours. Pay access OR team leader for session user. Writes people_hours.person_id when resolvable.';


--
-- Name: approve_collect_payment_for_terminal("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."approve_collect_payment_for_terminal"("p_job_id" "uuid", "p_jobs_ledger_invoice_id" "uuid", "p_dispatch_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
  v_inv RECORD;
  v_flow RECORD;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('error', 'not_authenticated');
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = v_uid;
  IF v_role IS NULL OR v_role NOT IN ('dev', 'master_technician', 'assistant') THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  SELECT * INTO v_flow FROM public.job_collect_payment_flows WHERE job_id = p_job_id FOR UPDATE;
  IF NOT FOUND OR v_flow.status IS DISTINCT FROM 'pending_dispatch' THEN
    RETURN jsonb_build_object('error', 'No pending collect payment request for this job.');
  END IF;

  SELECT i.id, i.job_id, i.status, i.stripe_invoice_id
  INTO v_inv
  FROM public.jobs_ledger_invoices i
  INNER JOIN public.jobs_ledger j ON j.id = i.job_id
  WHERE i.id = p_jobs_ledger_invoice_id
    AND i.job_id = p_job_id
    AND i.status = 'billed'
    AND i.stripe_invoice_id IS NOT NULL
    AND trim(i.stripe_invoice_id) <> ''
    AND (
      j.master_user_id = v_uid
      OR public.is_dev()
      OR v_role IN ('assistant', 'master_technician')
      OR EXISTS (
        SELECT 1 FROM public.master_assistants
        WHERE master_id = v_uid AND assistant_id = j.master_user_id
      )
      OR EXISTS (
        SELECT 1 FROM public.master_assistants
        WHERE master_id = j.master_user_id AND assistant_id = v_uid
      )
      OR public.assistants_share_master(v_uid, j.master_user_id)
    );

  IF v_inv.id IS NULL THEN
    RETURN jsonb_build_object(
      'error',
      'Invoice must be Billed with a Stripe invoice id, and you must have job access.'
    );
  END IF;

  UPDATE public.job_collect_payment_flows
  SET
    status = 'approved_for_terminal',
    jobs_ledger_invoice_id = v_inv.id,
    stripe_invoice_id = trim(v_inv.stripe_invoice_id),
    dispatch_reviewed_at = now(),
    dispatch_reviewed_by = v_uid,
    dispatch_notes = NULLIF(trim(COALESCE(p_dispatch_notes, '')), ''),
    stripe_payment_intent_id = NULL,
    last_error = NULL
  WHERE job_id = p_job_id;

  RETURN jsonb_build_object(
    'ok', true,
    'status', 'approved_for_terminal',
    'stripe_invoice_id', trim(v_inv.stripe_invoice_id),
    'jobs_ledger_invoice_id', v_inv.id
  );
END;
$$;


ALTER FUNCTION "public"."approve_collect_payment_for_terminal"("p_job_id" "uuid", "p_jobs_ledger_invoice_id" "uuid", "p_dispatch_notes" "text") OWNER TO "postgres";

