-- Name: FUNCTION "approve_collect_payment_for_terminal"("p_job_id" "uuid", "p_jobs_ledger_invoice_id" "uuid", "p_dispatch_notes" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."approve_collect_payment_for_terminal"("p_job_id" "uuid", "p_jobs_ledger_invoice_id" "uuid", "p_dispatch_notes" "text") IS 'Office: approve field collect payment after Stripe invoice exists (billed + stripe_invoice_id).';


--
-- Name: assert_caller_can_merge_customer_pair("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."assert_caller_can_merge_customer_pair"("p_survivor_master_user_id" "uuid", "p_victim_master_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.users
    WHERE id = auth.uid()
      AND role IN ('dev', 'master_technician')
  ) THEN
    RETURN;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.users
    WHERE id = auth.uid()
      AND role = 'assistant'
  ) THEN
    IF p_survivor_master_user_id IS NULL OR p_victim_master_user_id IS NULL THEN
      RAISE EXCEPTION 'Not allowed to merge customers';
    END IF;
    IF NOT EXISTS (
      SELECT 1 FROM public.master_assistants
      WHERE assistant_id = auth.uid()
        AND master_id = p_survivor_master_user_id
    ) THEN
      RAISE EXCEPTION 'Not allowed to merge customers';
    END IF;
    IF NOT EXISTS (
      SELECT 1 FROM public.master_assistants
      WHERE assistant_id = auth.uid()
        AND master_id = p_victim_master_user_id
    ) THEN
      RAISE EXCEPTION 'Not allowed to merge customers';
    END IF;
    RETURN;
  END IF;

  RAISE EXCEPTION 'Not allowed to merge customers';
END;
$$;


ALTER FUNCTION "public"."assert_caller_can_merge_customer_pair"("p_survivor_master_user_id" "uuid", "p_victim_master_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "assert_caller_can_merge_customer_pair"("p_survivor_master_user_id" "uuid", "p_victim_master_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."assert_caller_can_merge_customer_pair"("p_survivor_master_user_id" "uuid", "p_victim_master_user_id" "uuid") IS 'Merge auth: dev/master always; assistant only if adopted by both customers'' masters.';


--
-- Name: assistants_share_master("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."assistants_share_master"("assistant_a" "uuid", "assistant_b" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.master_assistants ma_a
    JOIN public.master_assistants ma_b ON ma_b.master_id = ma_a.master_id
    WHERE ma_a.assistant_id = assistants_share_master.assistant_a
    AND ma_b.assistant_id = assistants_share_master.assistant_b
  );
$$;


