COMMENT ON FUNCTION "public"."assistants_share_master"("assistant_a" "uuid", "assistant_b" "uuid") IS 'Returns true if both assistants are adopted by the same master. Uses SECURITY DEFINER to bypass RLS on master_assistants.';


