--
-- Name: auto_clock_out_eod_if_due(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."auto_clock_out_eod_if_due"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_hour integer;
  v_minute integer;
BEGIN
  v_hour := EXTRACT(HOUR FROM (clock_timestamp() AT TIME ZONE 'America/Chicago'))::integer;
  v_minute := EXTRACT(MINUTE FROM (clock_timestamp() AT TIME ZONE 'America/Chicago'))::integer;

  IF v_hour = 23 AND v_minute = 59 THEN
    PERFORM public.auto_clock_out_open_sessions_eod();
  END IF;
END;
$$;


ALTER FUNCTION "public"."auto_clock_out_eod_if_due"() OWNER TO "postgres";

--
-- Name: FUNCTION "auto_clock_out_eod_if_due"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."auto_clock_out_eod_if_due"() IS 'Definer: when America/Chicago local time is 23:59, call auto_clock_out_open_sessions_eod. Invoked every minute by pg_cron; no-op other minutes.';


--
-- Name: auto_clock_out_open_sessions_eod(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."auto_clock_out_open_sessions_eod"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_today date;
BEGIN
  v_today := (clock_timestamp() AT TIME ZONE 'America/Chicago')::date;

  UPDATE public.clock_sessions cs
  SET clocked_out_at = GREATEST(
    ((cs.work_date + interval '1 day')::timestamp AT TIME ZONE 'America/Chicago') - interval '1 microsecond',
    cs.clocked_in_at + interval '1 millisecond'
  )
  WHERE cs.clocked_out_at IS NULL
    AND cs.rejected_at IS NULL
    AND cs.revoked_at IS NULL
    AND cs.work_date <= v_today;
END;
$$;


ALTER FUNCTION "public"."auto_clock_out_open_sessions_eod"() OWNER TO "postgres";

--
-- Name: FUNCTION "auto_clock_out_open_sessions_eod"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."auto_clock_out_open_sessions_eod"() IS 'Definer: set clocked_out_at to end of cs.work_date in America/Chicago (last microsecond before next calendar day) for all open sessions with work_date <= today (Chicago). Stale rows get end-of-that-day; same-day rows get tonight''s EOD. clocked_out_at is strictly after clocked_in_at. Service role only; idempotent.';


--
-- Name: backfill_mercury_auto_attributions_for_debit_card("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."backfill_mercury_auto_attributions_for_debit_card"("p_mercury_debit_card_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_cnt int;
  v_user_id uuid;
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant')
  ) THEN
    RAISE EXCEPTION 'backfill_mercury_auto_attributions_for_debit_card: not authorized';
  END IF;

  SELECT l.auto_assign_user_id INTO v_user_id
  FROM public.mercury_debit_card_user_links l
  WHERE l.mercury_debit_card_id = p_mercury_debit_card_id;

  IF v_user_id IS NULL THEN
    RETURN 0;
  END IF;

  WITH ins AS (
    INSERT INTO public.mercury_transaction_attributions (mercury_transaction_id, person_id, user_id)
    SELECT
      t.id,
      NULL,
      v_user_id
    FROM public.mercury_transactions t
    WHERE public.mercury_debit_card_id_from_raw(t.raw) = p_mercury_debit_card_id
      AND (
        NOT EXISTS (
          SELECT 1
          FROM public.mercury_transaction_attributions a
          WHERE a.mercury_transaction_id = t.id
        )
        OR EXISTS (
          SELECT 1
          FROM public.mercury_transaction_attributions a2
          WHERE a2.mercury_transaction_id = t.id
            AND a2.user_id IS NULL
            AND a2.person_id IS NULL
        )
      )
    ON CONFLICT (mercury_transaction_id) DO UPDATE
    SET user_id = EXCLUDED.user_id
    WHERE public.mercury_transaction_attributions.user_id IS NULL
      AND public.mercury_transaction_attributions.person_id IS NULL
    RETURNING 1
  )
  SELECT coalesce((SELECT count(*)::int FROM ins), 0) INTO v_cnt;

  RETURN v_cnt;
END;
$$;


ALTER FUNCTION "public"."backfill_mercury_auto_attributions_for_debit_card"("p_mercury_debit_card_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "backfill_mercury_auto_attributions_for_debit_card"("p_mercury_debit_card_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."backfill_mercury_auto_attributions_for_debit_card"("p_mercury_debit_card_id" "uuid") IS 'Applies link.auto_assign_user_id to all unattributed Mercury rows for a debit card (staff only).';


--
-- Name: bids_clear_working_board_archive_on_progress(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."bids_clear_working_board_archive_on_progress"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.bid_date_sent IS NOT NULL THEN
    NEW.working_board_archived_at := NULL;
    NEW.working_board_archived_by := NULL;
  ELSIF NEW.outcome IS NOT NULL AND NEW.outcome IN ('won', 'lost', 'started_or_complete') THEN
    NEW.working_board_archived_at := NULL;
    NEW.working_board_archived_by := NULL;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."bids_clear_working_board_archive_on_progress"() OWNER TO "postgres";

--
-- Name: bulk_approve_accounting_label_suggestions("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."bulk_approve_accounting_label_suggestions"("p_items" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_n_payload integer;
  v_n_valid integer;
  v_updated integer;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated' USING ERRCODE = '28000';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.users u
    WHERE u.id = v_uid
      AND u.role IN ('dev', 'master_technician', 'assistant')
  ) THEN
    RAISE EXCEPTION 'Not allowed' USING ERRCODE = '42501';
  END IF;

  IF p_items IS NULL OR jsonb_typeof(p_items) IS DISTINCT FROM 'array' THEN
    RAISE EXCEPTION 'p_items must be a JSON array';
  END IF;

  SELECT count(*)::integer INTO v_n_payload FROM jsonb_array_elements(p_items) AS _;

  IF v_n_payload = 0 THEN
    RETURN 0;
  END IF;

  IF v_n_payload > 500 THEN
    RAISE EXCEPTION 'At most 500 suggestions per request';
  END IF;

  CREATE TEMP TABLE _approve_acct_payload ON COMMIT DROP AS
  SELECT
    (elem->>'suggestion_id')::uuid AS suggestion_id,
    (elem->>'mercury_transaction_id')::uuid AS mercury_transaction_id,
    (elem->>'label_id')::uuid AS label_id
  FROM jsonb_array_elements(p_items) AS t(elem);

  IF EXISTS (
    SELECT 1 FROM _approve_acct_payload p
    WHERE p.suggestion_id IS NULL
       OR p.mercury_transaction_id IS NULL
       OR p.label_id IS NULL
  ) THEN
    RAISE EXCEPTION 'Each item must include suggestion_id, mercury_transaction_id, and label_id';
  END IF;

  SELECT count(*)::integer INTO v_n_valid
  FROM _approve_acct_payload p
  INNER JOIN public.mercury_accounting_label_suggestions s
    ON s.id = p.suggestion_id
   AND s.mercury_transaction_id = p.mercury_transaction_id
   AND s.status = 'pending';

  IF v_n_valid IS DISTINCT FROM v_n_payload THEN
    RAISE EXCEPTION 'One or more suggestions are missing, not pending, or transaction id mismatch';
  END IF;

  INSERT INTO public.mercury_transaction_drag_sort_assignments (mercury_transaction_id, label_id)
  SELECT p.mercury_transaction_id, p.label_id
  FROM _approve_acct_payload p
  ON CONFLICT (mercury_transaction_id) DO UPDATE SET
    label_id = EXCLUDED.label_id,
    assigned_at = now();

  UPDATE public.mercury_accounting_label_suggestions s
  SET
    status = 'approved',
    final_label_id = p.label_id,
    resolved_at = now(),
    resolved_by = v_uid
  FROM _approve_acct_payload p
  WHERE s.id = p.suggestion_id
    AND s.status = 'pending';

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."bulk_approve_accounting_label_suggestions"("p_items" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "bulk_approve_accounting_label_suggestions"("p_items" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."bulk_approve_accounting_label_suggestions"("p_items" "jsonb") IS 'Banking staff: atomically upsert drag-sort assignments and mark accounting label suggestions approved (max 500).';


--
-- Name: bulk_insert_accounting_label_suggestions("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."bulk_insert_accounting_label_suggestions"("p_rows" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_n_payload integer;
  v_inserted integer;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated' USING ERRCODE = '28000';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.users u
    WHERE u.id = v_uid
      AND u.role IN ('dev', 'master_technician', 'assistant')
  ) THEN
    RAISE EXCEPTION 'Not allowed' USING ERRCODE = '42501';
  END IF;

  IF p_rows IS NULL OR jsonb_typeof(p_rows) IS DISTINCT FROM 'array' THEN
    RAISE EXCEPTION 'p_rows must be a JSON array';
  END IF;

  SELECT count(*)::integer INTO v_n_payload FROM jsonb_array_elements(p_rows) AS _;

  IF v_n_payload = 0 THEN
    RETURN 0;
  END IF;

  IF v_n_payload > 2000 THEN
    RAISE EXCEPTION 'At most 2000 suggestion rows per request';
  END IF;

  INSERT INTO public.mercury_accounting_label_suggestions (
    mercury_transaction_id,
    rule_id,
    suggested_label_id,
    status
  )
  SELECT
    (elem->>'mercury_transaction_id')::uuid,
    (elem->>'rule_id')::uuid,
    (elem->>'suggested_label_id')::uuid,
    'pending'::text
  FROM jsonb_array_elements(p_rows) AS t(elem)
  WHERE (elem->>'mercury_transaction_id') IS NOT NULL
    AND (elem->>'rule_id') IS NOT NULL
    AND (elem->>'suggested_label_id') IS NOT NULL
  ON CONFLICT (mercury_transaction_id) WHERE (status = 'pending') DO NOTHING;

  GET DIAGNOSTICS v_inserted = ROW_COUNT;
  RETURN v_inserted;
END;
$$;


ALTER FUNCTION "public"."bulk_insert_accounting_label_suggestions"("p_rows" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "bulk_insert_accounting_label_suggestions"("p_rows" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."bulk_insert_accounting_label_suggestions"("p_rows" "jsonb") IS 'Banking staff: insert pending accounting label suggestions in bulk; skips conflicts (max 2000).';


--
-- Name: bump_user_app_activity(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."bump_user_app_activity"("p_seconds" integer DEFAULT 60) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_sec integer;
  v_date date;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN;
  END IF;

  v_sec := LEAST(GREATEST(COALESCE(p_seconds, 0), 0), 300);
  v_date := (timezone('UTC', now()))::date;

  INSERT INTO public.user_app_activity_daily (user_id, activity_date, first_seen_at, last_seen_at, active_seconds)
  VALUES (v_uid, v_date, now(), now(), LEAST(v_sec, 86400))
  ON CONFLICT (user_id, activity_date) DO UPDATE SET
    active_seconds = LEAST(user_app_activity_daily.active_seconds + EXCLUDED.active_seconds, 86400),
    first_seen_at = COALESCE(user_app_activity_daily.first_seen_at, EXCLUDED.first_seen_at),
    last_seen_at = now();
END;
$$;


ALTER FUNCTION "public"."bump_user_app_activity"("p_seconds" integer) OWNER TO "postgres";

--
-- Name: can_access_bid_for_pricing("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_access_bid_for_pricing"("bid_id_param" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  bid_rec RECORD;
  user_role_val TEXT;
BEGIN
  SELECT b.created_by, b.customer_id, b.gc_builder_id
  INTO bid_rec
  FROM public.bids b
  WHERE b.id = bid_id_param;

  IF bid_rec.created_by IS NULL THEN
    RETURN false;
  END IF;

  SELECT role INTO user_role_val FROM public.users WHERE id = auth.uid();

  IF bid_rec.created_by = auth.uid() THEN
    RETURN true;
  END IF;
  IF user_role_val IN ('dev', 'assistant', 'estimator', 'master_technician', 'primary') THEN
    RETURN true;
  END IF;
  IF user_role_val = 'superintendent' THEN
    IF bid_rec.created_by = auth.uid() THEN
      RETURN true;
    END IF;
    IF bid_rec.customer_id IS NOT NULL AND EXISTS (
      SELECT 1 FROM public.customers c
      JOIN public.master_superintendents ms ON ms.master_id = c.master_user_id AND ms.superintendent_id = auth.uid()
      WHERE c.id = bid_rec.customer_id
    ) THEN
      RETURN true;
    END IF;
    IF EXISTS (SELECT 1 FROM public.master_superintendents ms WHERE ms.master_id = bid_rec.created_by AND ms.superintendent_id = auth.uid()) THEN
      RETURN true;
    END IF;
    IF bid_rec.gc_builder_id IS NOT NULL AND EXISTS (
      SELECT 1 FROM public.bids_gc_builders bgb
      JOIN public.master_superintendents ms ON ms.master_id = bgb.created_by AND ms.superintendent_id = auth.uid()
      WHERE bgb.id = bid_rec.gc_builder_id
    ) THEN
      RETURN true;
    END IF;
    RETURN false;
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."can_access_bid_for_pricing"("bid_id_param" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "can_access_bid_for_pricing"("bid_id_param" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."can_access_bid_for_pricing"("bid_id_param" "uuid") IS 'Checks if the current user can access a bid (owner, dev, assistant, estimator, master, primary, or superintendent via adoption).';


--
-- Name: can_access_project("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_access_project"("project_id_param" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  project_master_id UUID;
  user_role_val TEXT;
BEGIN
  SELECT p.master_user_id, u.role
  INTO project_master_id, user_role_val
  FROM public.projects p
  LEFT JOIN public.users u ON u.id = auth.uid()
  WHERE p.id = project_id_param;

  IF project_master_id IS NULL THEN
    RETURN false;
  END IF;

  RETURN (
    project_master_id = auth.uid()
    OR public.is_dev()
    OR user_role_val = 'master_technician'
    OR public.master_adopted_current_user(project_master_id)
    OR public.master_shared_current_user(project_master_id)
  );
END;
$$;


ALTER FUNCTION "public"."can_access_project"("project_id_param" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "can_access_project"("project_id_param" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."can_access_project"("project_id_param" "uuid") IS 'Checks if the current user can access a project (owner/dev/master/adopted/shared). Uses SECURITY DEFINER to optimize RLS.';


--
-- Name: can_access_project_row("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_access_project_row"("project_id_param" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  proj_master_id UUID;
  proj_customer_id UUID;
  cust_master_id UUID;
  user_role_val TEXT;
BEGIN
  SELECT p.master_user_id, p.customer_id
  INTO proj_master_id, proj_customer_id
  FROM public.projects p
  WHERE p.id = project_id_param;

  IF proj_master_id IS NULL THEN
    RETURN false;
  END IF;

  SELECT role INTO user_role_val FROM public.users WHERE id = auth.uid();

  -- Superintendents: ONLY project-level assignment (project_superintendents), NOT adoption
  IF user_role_val = 'superintendent' THEN
    RETURN EXISTS (SELECT 1 FROM public.project_superintendents WHERE project_id = project_id_param AND superintendent_id = auth.uid());
  END IF;

  -- Direct access: owner, dev, master, adopted, shared
  IF proj_master_id = auth.uid() THEN
    RETURN true;
  END IF;
  IF user_role_val IN ('dev', 'master_technician') THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = proj_master_id AND assistant_id = auth.uid()) THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = proj_master_id AND primary_id = auth.uid()) THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_shares WHERE sharing_master_id = proj_master_id AND viewing_master_id = auth.uid()) THEN
    RETURN true;
  END IF;

  -- Access via customer: if project has customer_id, check customer access
  IF proj_customer_id IS NOT NULL THEN
    SELECT master_user_id INTO cust_master_id FROM public.customers WHERE id = proj_customer_id;
    IF cust_master_id IS NOT NULL THEN
      IF cust_master_id = auth.uid() THEN
        RETURN true;
      END IF;
      IF user_role_val IN ('dev', 'master_technician') THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = cust_master_id AND assistant_id = auth.uid()) THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = cust_master_id AND primary_id = auth.uid()) THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_shares WHERE sharing_master_id = cust_master_id AND viewing_master_id = auth.uid()) THEN
        RETURN true;
      END IF;
    END IF;
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."can_access_project_row"("project_id_param" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "can_access_project_row"("project_id_param" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."can_access_project_row"("project_id_param" "uuid") IS 'Checks if the current user can access a project. Superintendents: assigned projects only (project_superintendents). Others: owner/dev/master/adopted/shared. SECURITY DEFINER.';


--
-- Name: can_access_project_row("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_access_project_row"("project_id_param" "uuid", "proj_master_id" "uuid", "proj_customer_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  cust_master_id UUID;
  user_role_val TEXT;
BEGIN
  IF proj_master_id IS NULL THEN
    RETURN false;
  END IF;

  SELECT role INTO user_role_val FROM public.users WHERE id = auth.uid();

  -- Direct access: owner, dev, master, adopted, shared
  IF proj_master_id = auth.uid() THEN
    RETURN true;
  END IF;
  IF user_role_val IN ('dev', 'master_technician') THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = proj_master_id AND assistant_id = auth.uid()) THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = proj_master_id AND primary_id = auth.uid()) THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_superintendents WHERE master_id = proj_master_id AND superintendent_id = auth.uid()) THEN
    RETURN true;
  END IF;
  IF EXISTS (SELECT 1 FROM public.master_shares WHERE sharing_master_id = proj_master_id AND viewing_master_id = auth.uid()) THEN
    RETURN true;
  END IF;

  -- Project-level assignment: use SECURITY DEFINER helper to avoid project_superintendents
  -- RLS (which calls can_access_project_row) from triggering projects RLS recursion
  IF public.user_assigned_to_project_as_superintendent(project_id_param) THEN
    RETURN true;
  END IF;

  -- Access via customer: if project has customer_id, check customer access
  IF proj_customer_id IS NOT NULL THEN
    SELECT master_user_id INTO cust_master_id FROM public.customers WHERE id = proj_customer_id;
    IF cust_master_id IS NOT NULL THEN
      IF cust_master_id = auth.uid() THEN
        RETURN true;
      END IF;
      IF user_role_val IN ('dev', 'master_technician') THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = cust_master_id AND assistant_id = auth.uid()) THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = cust_master_id AND primary_id = auth.uid()) THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_superintendents WHERE master_id = cust_master_id AND superintendent_id = auth.uid()) THEN
        RETURN true;
      END IF;
      IF EXISTS (SELECT 1 FROM public.master_shares WHERE sharing_master_id = cust_master_id AND viewing_master_id = auth.uid()) THEN
        RETURN true;
      END IF;
    END IF;
  END IF;

  RETURN false;
END;
$$;


