COMMENT ON FUNCTION "public"."can_access_project_row"("project_id_param" "uuid", "proj_master_id" "uuid", "proj_customer_id" "uuid") IS 'Checks project access using passed master_user_id and customer_id. Used by projects RLS to avoid recursion (no projects table read).';


