-- Name: can_access_project_row_for_user("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_access_project_row_for_user"("project_id_param" "uuid", "viewer_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  proj_master_id UUID;
  proj_customer_id UUID;
