--
-- Name: cascade_customer_master_to_projects(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cascade_customer_master_to_projects"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  -- Only proceed if master_user_id actually changed
  IF OLD.master_user_id IS DISTINCT FROM NEW.master_user_id THEN
    -- Update all projects belonging to this customer
    UPDATE projects
    SET 
      master_user_id = NEW.master_user_id,
      updated_at = NOW()
    WHERE customer_id = NEW.id;
    
    -- Log the number of updated projects for debugging
    RAISE NOTICE 'Cascaded master_user_id change from customer % to % projects', 
      NEW.id, 
      (SELECT COUNT(*) FROM projects WHERE customer_id = NEW.id);
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."cascade_customer_master_to_projects"() OWNER TO "postgres";

--
-- Name: FUNCTION "cascade_customer_master_to_projects"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."cascade_customer_master_to_projects"() IS 'Automatically updates master_user_id on all projects when their customer''s master_user_id changes. Maintains data consistency between customers and projects.';


--
-- Name: check_out_project("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_out_project"("p_project_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_can_check_out boolean;
  v_updated int;
begin
  if v_uid is null then
    return jsonb_build_object('ok', false, 'error', 'Not authenticated');
  end if;

  select exists (
    select 1 from public.projects p
    where p.id = p_project_id
    and (
      p.user_id = v_uid
      or exists (select 1 from public.project_shares ps where ps.project_id = p.id and ps.user_id = v_uid and ps.role = 'editor')
      or exists (select 1 from public.profiles pr where pr.user_id = v_uid and pr.is_admin = true)
    )
  ) into v_can_check_out;

  if not v_can_check_out then
    return jsonb_build_object('ok', false, 'error', 'No permission to check out');
  end if;

  -- Lock must be free or expired (30 minutes inactivity)
  update public.projects
  set checked_out_by = v_uid, checked_out_at = now()
  where id = p_project_id
  and (checked_out_by is null or checked_out_at < now() - interval '30 minutes');

  get diagnostics v_updated = row_count;
  if v_updated = 0 then
    return jsonb_build_object('ok', false, 'error', 'Project is checked out by someone else');
  end if;

  return jsonb_build_object('ok', true);
end;
$$;


ALTER FUNCTION "public"."check_out_project"("p_project_id" "uuid") OWNER TO "postgres";

