-- Name: clear_mercury_transaction_duplicate("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."clear_mercury_transaction_duplicate"("p_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  uid uuid := auth.uid();
begin
  if uid is null then
    raise exception 'clear_mercury_transaction_duplicate: not authenticated';
  end if;
  if not exists (
    select 1 from public.users u
    where u.id = uid and u.role in ('dev', 'master_technician', 'assistant')
  ) then
    raise exception 'clear_mercury_transaction_duplicate: not authorized';
  end if;
  update public.mercury_transactions
    set duplicate_of_transaction_id = null
    where id = p_id;
end;
$$;


