--
-- Name: clock_sessions_promote_job_waiting_to_working(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."clock_sessions_promote_job_waiting_to_working"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_promoted integer := 0;
BEGIN
  -- Only act when this row represents real, clocked-out work on a job.
  IF NEW.clocked_out_at IS NULL
     OR NEW.job_ledger_id IS NULL
     OR NEW.rejected_at IS NOT NULL
     OR NEW.revoked_at IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- On UPDATE, only proceed when clocked_out_at actually transitioned
  -- (ignores notes/job edits on an already-closed session re-touching the column).
  IF TG_OP = 'UPDATE' AND OLD.clocked_out_at IS NOT DISTINCT FROM NEW.clocked_out_at THEN
    RETURN NEW;
  END IF;

  UPDATE public.jobs_ledger jl
  SET status = 'working', updated_at = NOW()
  WHERE jl.id = NEW.job_ledger_id
    AND jl.status = 'waiting';
  GET DIAGNOSTICS v_promoted = ROW_COUNT;

  IF v_promoted = 1 THEN
    INSERT INTO public.job_status_events (job_id, from_status, to_status, changed_by_user_id)
    VALUES (NEW.job_ledger_id, 'waiting', 'working', NEW.user_id);
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."clock_sessions_promote_job_waiting_to_working"() OWNER TO "postgres";

--
-- Name: FUNCTION "clock_sessions_promote_job_waiting_to_working"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."clock_sessions_promote_job_waiting_to_working"() IS 'After a clock session is clocked out (non-rejected/revoked, linked to a job), auto-promote that job from waiting to working and log a job_status_events row. Idempotent via status=waiting guard.';


--
-- Name: clock_sessions_sync_crew_assignments_after_job_bid(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."clock_sessions_sync_crew_assignments_after_job_bid"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_person_name text;
BEGIN
  IF NEW.approved_at IS NULL OR NEW.rejected_at IS NOT NULL OR NEW.revoked_at IS NOT NULL THEN
    RETURN NEW;
  END IF;

  IF OLD.job_ledger_id IS NOT DISTINCT FROM NEW.job_ledger_id
     AND OLD.bid_id IS NOT DISTINCT FROM NEW.bid_id THEN
    RETURN NEW;
  END IF;

  SELECT trim(u.name) INTO v_person_name
  FROM public.users u
  WHERE u.id = NEW.user_id;

  IF v_person_name IS NULL OR v_person_name = '' THEN
    RETURN NEW;
  END IF;

  PERFORM public.sync_crew_jobs_from_clock(v_person_name, NEW.work_date);
  PERFORM public.sync_crew_bids_from_clock(v_person_name, NEW.work_date);
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."clock_sessions_sync_crew_assignments_after_job_bid"() OWNER TO "postgres";

