--

COMMENT ON FUNCTION "public"."clock_sessions_sync_crew_assignments_after_job_bid"() IS 'After job/bid link changes on an approved session, resync crew assignment rows from clock hours.';


--
-- Name: complete_job_collect_payment_flow_for_invoice("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_job_collect_payment_flow_for_invoice"("p_stripe_invoice_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sid text := NULLIF(trim(COALESCE(p_stripe_invoice_id, '')), '');
  v_updated int;
BEGIN
  IF v_sid IS NULL OR v_sid = '' THEN
    RETURN jsonb_build_object('error', 'missing stripe invoice id');
  END IF;

  UPDATE public.job_collect_payment_flows
  SET
    status = 'terminal_completed',
    last_error = NULL
  WHERE trim(stripe_invoice_id) = v_sid
    AND status = 'approved_for_terminal';

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  IF v_updated = 0 THEN
    RETURN jsonb_build_object('error', 'no matching flow', 'applied', false);
  END IF;

  RETURN jsonb_build_object('ok', true, 'applied', true);
END;
$$;


ALTER FUNCTION "public"."complete_job_collect_payment_flow_for_invoice"("p_stripe_invoice_id" "text") OWNER TO "postgres";

