--
-- Name: count_mercury_transactions_for_bank_payments("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."count_mercury_transactions_for_bank_payments"("p_filter" "jsonb" DEFAULT NULL::"jsonb") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_kinds text[] := array[]::text[];
  v_account_ids text[] := array[]::text[];
  v_debit_ids text[] := array[]::text[];
  v_start_ymd text;
  v_exclude_cp text[] := array[]::text[];
  v_exclude_note text[] := array[]::text[];
  v_include_hidden boolean := false;
  o jsonb;
  v_count bigint;
begin
  if auth.uid() is null then
    raise exception 'count_mercury_transactions_for_bank_payments: not authenticated';
  end if;

  if not exists (
    select 1 from public.users u
    where u.id = auth.uid()
      and u.role in ('dev', 'master_technician', 'assistant', 'primary')
  ) then
    raise exception 'count_mercury_transactions_for_bank_payments: not authorized';
  end if;

  if p_filter is not null and jsonb_typeof(p_filter) = 'object' then
    o := p_filter;
    if o ? 'kinds' and jsonb_typeof(o->'kinds') = 'array' then
      select coalesce(array_agg(value::text), array[]::text[])
      into v_kinds
      from jsonb_array_elements_text(o->'kinds');
    end if;
    if o ? 'accountIds' and jsonb_typeof(o->'accountIds') = 'array' then
      select coalesce(array_agg(value::text), array[]::text[])
      into v_account_ids
      from jsonb_array_elements_text(o->'accountIds');
    end if;
    if o ? 'debitCardIds' and jsonb_typeof(o->'debitCardIds') = 'array' then
      select coalesce(array_agg(lower(trim(value::text))), array[]::text[])
      into v_debit_ids
      from jsonb_array_elements_text(o->'debitCardIds');
    end if;
    if o ? 'startDateYmd' and jsonb_typeof(o->'startDateYmd') = 'string' then
      v_start_ymd := trim(o->>'startDateYmd');
    end if;
    if o ? 'excludeCounterpartyContains' and jsonb_typeof(o->'excludeCounterpartyContains') = 'array' then
      with elements as (
        select left(btrim(value), 120) as p
        from jsonb_array_elements_text(o->'excludeCounterpartyContains')
        where length(btrim(value)) > 0
        limit 50
      )
      select coalesce(array_agg(p order by p), array[]::text[])
      into v_exclude_cp
      from elements;
    end if;
    if o ? 'excludeNoteContains' and jsonb_typeof(o->'excludeNoteContains') = 'array' then
      with elements as (
        select left(btrim(value), 120) as p
        from jsonb_array_elements_text(o->'excludeNoteContains')
        where length(btrim(value)) > 0
        limit 50
      )
      select coalesce(array_agg(p order by p), array[]::text[])
      into v_exclude_note
      from elements;
    end if;
    if o ? 'includeHiddenArDeposits' and jsonb_typeof(o->'includeHiddenArDeposits') = 'boolean' then
      v_include_hidden := (o->>'includeHiddenArDeposits')::boolean;
    elsif o ? 'includeFullyApplied' and jsonb_typeof(o->'includeFullyApplied') = 'boolean' then
      v_include_hidden := (o->>'includeFullyApplied')::boolean;
    end if;
  end if;

  if v_start_ymd is null or v_start_ymd !~ '^\d{4}-\d{2}-\d{2}$' then
    v_start_ymd := to_char((current_timestamp at time zone 'America/Chicago')::date - 90, 'YYYY-MM-DD');
  end if;

  select count(*)::bigint
  into v_count
  from public.mercury_transactions t
  where t.posted_at is not null
    and t.duplicate_of_transaction_id is null
    and to_char((t.posted_at at time zone 'America/Chicago')::date, 'YYYY-MM-DD') >= v_start_ymd
    and (cardinality(v_kinds) = 0 or t.kind = any (v_kinds))
    and (cardinality(v_account_ids) = 0 or t.mercury_account_id::text = any (v_account_ids))
    and (
      cardinality(v_debit_ids) = 0
      or public._mercury_raw_debit_card_id_lower(t.raw) = any (v_debit_ids)
    )
    and abs(t.amount) > 0
    and (
      v_include_hidden
      or (
        abs(t.amount) - coalesce((
          select sum(p.amount)
          from public.jobs_ledger_payments p
          where p.mercury_transaction_id = t.id
        ), 0)
      ) > 0.0005
    )
    and (
      v_include_hidden
      or not exists (
        select 1
        from public.mercury_transaction_ar_returned r2
        where r2.mercury_transaction_id = t.id
          and r2.returned
      )
    )
    and not (
      cardinality(v_exclude_cp) > 0
      and exists (
        select 1
        from unnest(v_exclude_cp) as x(pat)
        where position(lower(x.pat) in lower(coalesce(t.counterparty_name, ''))) > 0
      )
    )
    and not (
      cardinality(v_exclude_note) > 0
      and exists (
        select 1
        from unnest(v_exclude_note) as x(pat)
        where position(lower(x.pat) in lower(coalesce(t.note, ''))) > 0
      )
    );

  return coalesce(v_count, 0);
end;
$_$;


ALTER FUNCTION "public"."count_mercury_transactions_for_bank_payments"("p_filter" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "count_mercury_transactions_for_bank_payments"("p_filter" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."count_mercury_transactions_for_bank_payments"("p_filter" "jsonb") IS 'Count of Mercury transactions for Jobs AR (same p_filter and visibility as list_mercury_transactions_for_bank_payments). Dev/master/assistant/primary only.';


--
-- Name: count_unlinked_mercury_transactions_for_tally(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."count_unlinked_mercury_transactions_for_tally"() RETURNS bigint
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.uid() is null then
    raise exception 'count_unlinked_mercury_transactions_for_tally: not authenticated';
  end if;

  return (
    select count(*)::bigint
    from public.mercury_transactions t
    inner join public.mercury_debit_card_user_links l
      on l.user_id = auth.uid()
      and l.mercury_debit_card_id = public.mercury_debit_card_id_from_raw(t.raw)
    where t.duplicate_of_transaction_id is null
    and not exists (
      select 1
      from public.mercury_transaction_job_allocations m
      where m.mercury_transaction_id = t.id
    )
    and not exists (
      select 1
      from public.mercury_transaction_supply_house_invoice_links il
      where il.mercury_transaction_id = t.id
    )
  );
end;
$$;


ALTER FUNCTION "public"."count_unlinked_mercury_transactions_for_tally"() OWNER TO "postgres";

--
-- Name: FUNCTION "count_unlinked_mercury_transactions_for_tally"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."count_unlinked_mercury_transactions_for_tally"() IS 'Count of Mercury transactions on the caller''s linked debit card(s) with no job allocations and no supply-house invoice links (matches Job Tally Show unlinked).';


--
-- Name: count_unlinked_mercury_transactions_for_tally_stale(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."count_unlinked_mercury_transactions_for_tally_stale"("min_age_days" integer DEFAULT 2) RETURNS bigint
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  floor_ymd text;
  use_floor boolean;
  age_int integer;
begin
  if auth.uid() is null then
    raise exception 'count_unlinked_mercury_transactions_for_tally_stale: not authenticated';
  end if;

  age_int := greatest(0, min_age_days);

  select nullif(trim(both from value_text), '') into floor_ymd
  from public.app_settings
  where key = 'job_tally_min_posted_ymd';

  use_floor := floor_ymd is not null and floor_ymd ~ '^\d{4}-\d{2}-\d{2}$';

  return (
    select count(*)::bigint
    from public.mercury_transactions t
    inner join public.mercury_debit_card_user_links l
      on l.user_id = auth.uid()
      and l.mercury_debit_card_id = public.mercury_debit_card_id_from_raw(t.raw)
    where t.duplicate_of_transaction_id is null
    and not exists (
      select 1
      from public.mercury_transaction_job_allocations m
      where m.mercury_transaction_id = t.id
    )
    and not exists (
      select 1
      from public.mercury_transaction_supply_house_invoice_links il
      where il.mercury_transaction_id = t.id
    )
    and (
      not use_floor
      or (
        t.posted_at is not null
        and to_char(t.posted_at at time zone 'America/Chicago', 'YYYY-MM-DD') >= floor_ymd
      )
    )
    and t.posted_at is not null
    and (
      (now() at time zone 'America/Chicago')::date
      - (t.posted_at at time zone 'America/Chicago')::date
    ) > age_int
  );
end;
$_$;


ALTER FUNCTION "public"."count_unlinked_mercury_transactions_for_tally_stale"("min_age_days" integer) OWNER TO "postgres";

--
-- Name: FUNCTION "count_unlinked_mercury_transactions_for_tally_stale"("min_age_days" integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."count_unlinked_mercury_transactions_for_tally_stale"("min_age_days" integer) IS 'Subset of count_unlinked_mercury_transactions_for_tally (no job allocations and no invoice links): only rows where posted_at Chicago calendar date is more than min_age_days before today (Chicago).';


--
-- Name: create_job_from_estimate("uuid", "text", "text", "text", numeric, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_job_from_estimate"("p_estimate_id" "uuid", "p_hcp_number" "text", "p_job_name" "text" DEFAULT NULL::"text", "p_job_address" "text" DEFAULT NULL::"text", "p_revenue" numeric DEFAULT NULL::numeric, "p_customer_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  e public.estimates%ROWTYPE;
  v_master uuid;
  v_override text;
  v_job_id uuid;
  v_link_rows int;
  v_existing_link uuid;
  v_hcp text;
  v_cust_id uuid;
  v_cust_name text;
  v_cust_email text;
  v_cust_phone text;
  j_name text;
  j_addr text;
  rev numeric(12, 2);
  crec RECORD;
  ci jsonb;
  v_service_type_id uuid;
BEGIN
  SELECT st.id INTO v_service_type_id
  FROM public.service_types st
  WHERE st.name = 'Plumbing'
  LIMIT 1;
  IF v_service_type_id IS NULL THEN
    RAISE EXCEPTION 'service_types missing Plumbing row';
  END IF;

  v_hcp := trim(COALESCE(p_hcp_number, ''));
  IF v_hcp = '' THEN
    RAISE EXCEPTION 'hcp_number is required';
  END IF;

  SELECT * INTO e FROM public.estimates WHERE id = p_estimate_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'estimate not found';
  END IF;

  IF e.job_ledger_id IS NOT NULL THEN
    RETURN e.job_ledger_id;
  END IF;

  IF e.status IS DISTINCT FROM 'customer_accepted' THEN
    RAISE EXCEPTION 'estimate must be customer_accepted';
  END IF;

  IF NOT (
    public.user_can_access_estimate(e) OR public.superintendent_can_access_estimate(e)
  ) THEN
    RAISE EXCEPTION 'not authorized to create job for this estimate';
  END IF;

  IF e.project_id IS NOT NULL THEN
    SELECT p.master_user_id INTO v_master FROM public.projects p WHERE p.id = e.project_id;
    IF v_master IS NULL THEN
      RAISE EXCEPTION 'project not found';
    END IF;
  ELSE
    SELECT s.value_text INTO v_override
    FROM public.app_settings s
    WHERE s.key = 'job_owner_override_' || auth.uid()::text;
    IF v_override IS NOT NULL AND trim(v_override) != '' THEN
      v_master := trim(v_override)::uuid;
    ELSE
      v_master := auth.uid();
    END IF;
  END IF;

  v_cust_id := COALESCE(p_customer_id, e.customer_id);

  IF v_cust_id IS NOT NULL THEN
    SELECT c.name, c.contact_info, c.master_user_id
    INTO crec
    FROM public.customers c
    WHERE c.id = v_cust_id;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'customer not found';
    END IF;
    IF crec.master_user_id IS DISTINCT FROM v_master THEN
      RAISE EXCEPTION 'customer does not belong to job owner';
    END IF;
    v_cust_name := crec.name;
    ci := COALESCE(crec.contact_info::jsonb, '{}'::jsonb);
    v_cust_email := NULLIF(trim(ci->>'email'), '');
    v_cust_phone := NULLIF(trim(ci->>'phone'), '');
  ELSE
    v_cust_name := NULL;
    v_cust_email := NULLIF(trim(COALESCE(e.customer_email, '')), '');
    v_cust_phone := NULL;
  END IF;

  j_name := COALESCE(NULLIF(trim(p_job_name), ''), NULLIF(trim(e.title), ''), '');
  j_addr := COALESCE(
    NULLIF(trim(p_job_address), ''),
    NULLIF(trim(e.for_address), ''),
    ''
  );
  rev := COALESCE(p_revenue, (e.total_cents::numeric / 100.0));

  INSERT INTO public.jobs_ledger (
    master_user_id,
    hcp_number,
    job_name,
    job_address,
    customer_id,
    customer_name,
    customer_email,
    customer_phone,
    project_id,
    revenue,
    payments_made,
    service_type_id
  ) VALUES (
    v_master,
    v_hcp,
    j_name,
    j_addr,
    v_cust_id,
    v_cust_name,
    v_cust_email,
    v_cust_phone,
    e.project_id,
    rev,
    0,
    v_service_type_id
  )
  RETURNING id INTO v_job_id;

  UPDATE public.estimates
  SET job_ledger_id = v_job_id
  WHERE id = e.id AND job_ledger_id IS NULL;
  GET DIAGNOSTICS v_link_rows = ROW_COUNT;
  IF v_link_rows = 0 THEN
    SELECT el.job_ledger_id INTO v_existing_link FROM public.estimates el WHERE el.id = e.id;
    IF v_existing_link IS NOT NULL THEN
      DELETE FROM public.jobs_ledger WHERE id = v_job_id;
      RETURN v_existing_link;
    END IF;
    RAISE EXCEPTION 'could not link estimate to job';
  END IF;

  RETURN v_job_id;
END;
$$;


ALTER FUNCTION "public"."create_job_from_estimate"("p_estimate_id" "uuid", "p_hcp_number" "text", "p_job_name" "text", "p_job_address" "text", "p_revenue" numeric, "p_customer_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "create_job_from_estimate"("p_estimate_id" "uuid", "p_hcp_number" "text", "p_job_name" "text", "p_job_address" "text", "p_revenue" numeric, "p_customer_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."create_job_from_estimate"("p_estimate_id" "uuid", "p_hcp_number" "text", "p_job_name" "text", "p_job_address" "text", "p_revenue" numeric, "p_customer_id" "uuid") IS 'Creates jobs_ledger from customer_accepted estimate and sets estimates.job_ledger_id (idempotent if already linked).';


--
-- Name: create_job_from_estimate("uuid", "text", "text", "text", numeric, "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_job_from_estimate"("p_estimate_id" "uuid", "p_hcp_number" "text", "p_job_name" "text" DEFAULT NULL::"text", "p_job_address" "text" DEFAULT NULL::"text", "p_revenue" numeric DEFAULT NULL::numeric, "p_customer_id" "uuid" DEFAULT NULL::"uuid", "p_fixtures" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  e public.estimates%ROWTYPE;
  v_master uuid;
  v_override text;
  v_job_id uuid;
  v_link_rows int;
  v_existing_link uuid;
  v_hcp text;
  v_cust_id uuid;
  v_cust_name text;
  v_cust_email text;
  v_cust_phone text;
  j_name text;
  j_addr text;
  rev numeric(12, 2);
  crec RECORD;
  ci jsonb;
  fname text;
  fcount numeric;
  fprice numeric(12, 2);
  fdesc text;
  fseq int;
  v_fixture_inserts int := 0;
  v_fixture_rev numeric(12, 2) := 0;
  v_row_ext numeric(12, 2);
  fixture_el jsonb;
  idx int;
  v_len int;
  v_service_type_id uuid;
BEGIN
  SELECT st.id INTO v_service_type_id
  FROM public.service_types st
  WHERE st.name = 'Plumbing'
  LIMIT 1;
  IF v_service_type_id IS NULL THEN
    RAISE EXCEPTION 'service_types missing Plumbing row';
  END IF;

  v_hcp := trim(COALESCE(p_hcp_number, ''));
  IF v_hcp = '' THEN
    RAISE EXCEPTION 'hcp_number is required';
  END IF;

  SELECT * INTO e FROM public.estimates WHERE id = p_estimate_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'estimate not found';
  END IF;

  IF e.job_ledger_id IS NOT NULL THEN
    RETURN e.job_ledger_id;
  END IF;

  IF e.status IS DISTINCT FROM 'customer_accepted' THEN
    RAISE EXCEPTION 'estimate must be customer_accepted';
  END IF;

  IF NOT (
    public.user_can_access_estimate(e) OR public.superintendent_can_access_estimate(e)
  ) THEN
    RAISE EXCEPTION 'not authorized to create job for this estimate';
  END IF;

  IF e.project_id IS NOT NULL THEN
    SELECT p.master_user_id INTO v_master FROM public.projects p WHERE p.id = e.project_id;
    IF v_master IS NULL THEN
      RAISE EXCEPTION 'project not found';
    END IF;
  ELSE
    SELECT s.value_text INTO v_override
    FROM public.app_settings s
    WHERE s.key = 'job_owner_override_' || auth.uid()::text;
    IF v_override IS NOT NULL AND trim(v_override) != '' THEN
      v_master := trim(v_override)::uuid;
    ELSE
      v_master := auth.uid();
    END IF;
  END IF;

  v_cust_id := COALESCE(p_customer_id, e.customer_id);

  IF v_cust_id IS NOT NULL THEN
    SELECT c.name, c.contact_info, c.master_user_id
    INTO crec
    FROM public.customers c
    WHERE c.id = v_cust_id;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'customer not found';
    END IF;
    IF crec.master_user_id IS DISTINCT FROM v_master THEN
      RAISE EXCEPTION 'customer does not belong to job owner';
    END IF;
    v_cust_name := crec.name;
    ci := COALESCE(crec.contact_info::jsonb, '{}'::jsonb);
    v_cust_email := NULLIF(trim(ci->>'email'), '');
    v_cust_phone := NULLIF(trim(ci->>'phone'), '');
  ELSE
    v_cust_name := NULL;
    v_cust_email := NULLIF(trim(COALESCE(e.customer_email, '')), '');
    v_cust_phone := NULL;
  END IF;

  j_name := COALESCE(NULLIF(trim(p_job_name), ''), NULLIF(trim(e.title), ''), '');
  j_addr := COALESCE(
    NULLIF(trim(p_job_address), ''),
    NULLIF(trim(e.for_address), ''),
    ''
  );
  rev := COALESCE(p_revenue, (e.total_cents::numeric / 100.0));

  INSERT INTO public.jobs_ledger (
    master_user_id,
    hcp_number,
    job_name,
    job_address,
    customer_id,
    customer_name,
    customer_email,
    customer_phone,
    project_id,
    revenue,
    payments_made,
    service_type_id
  ) VALUES (
    v_master,
    v_hcp,
    j_name,
    j_addr,
    v_cust_id,
    v_cust_name,
    v_cust_email,
    v_cust_phone,
    e.project_id,
    rev,
    0,
    v_service_type_id
  )
  RETURNING id INTO v_job_id;

  UPDATE public.estimates
  SET job_ledger_id = v_job_id
  WHERE id = e.id AND job_ledger_id IS NULL;
  GET DIAGNOSTICS v_link_rows = ROW_COUNT;
  IF v_link_rows = 0 THEN
    SELECT el.job_ledger_id INTO v_existing_link FROM public.estimates el WHERE el.id = e.id;
    IF v_existing_link IS NOT NULL THEN
      DELETE FROM public.jobs_ledger WHERE id = v_job_id;
      RETURN v_existing_link;
    END IF;
    RAISE EXCEPTION 'could not link estimate to job';
  END IF;

  IF p_fixtures IS NOT NULL AND jsonb_typeof(p_fixtures) = 'array' THEN
    v_len := jsonb_array_length(p_fixtures);
    IF v_len IS NOT NULL AND v_len > 0 THEN
      FOR idx IN 0 .. v_len - 1 LOOP
        fixture_el := p_fixtures->idx;
        BEGIN
          fname := NULLIF(trim(COALESCE(fixture_el->>'name', '')), '');
          IF fname IS NULL OR fname = '' THEN
            CONTINUE;
          END IF;

          fcount := 1;
          IF fixture_el ? 'count' AND fixture_el->>'count' IS NOT NULL AND btrim(fixture_el->>'count') != '' THEN
            fcount := (fixture_el->>'count')::numeric;
          END IF;
          IF fcount IS NULL OR fcount <= 0 THEN
            fcount := 1;
          END IF;

          fprice := NULL;
          IF fixture_el ? 'line_unit_price' AND fixture_el->>'line_unit_price' IS NOT NULL AND btrim(fixture_el->>'line_unit_price') != '' THEN
            fprice := round((fixture_el->>'line_unit_price')::numeric, 2);
          END IF;

          fdesc := NULLIF(trim(COALESCE(fixture_el->>'line_description', '')), '');

          fseq := 0;
          IF fixture_el ? 'sequence_order' AND fixture_el->>'sequence_order' IS NOT NULL AND btrim(fixture_el->>'sequence_order') != '' THEN
            fseq := (fixture_el->>'sequence_order')::int;
          END IF;

          INSERT INTO public.jobs_ledger_fixtures (
            job_id,
            name,
            count,
            line_unit_price,
            line_description,
            sequence_order
          ) VALUES (
            v_job_id,
            fname,
            fcount,
            fprice,
            fdesc,
            fseq
          );

          v_fixture_inserts := v_fixture_inserts + 1;
          v_row_ext := round(fcount * COALESCE(fprice, 0::numeric), 2);
          v_fixture_rev := round(v_fixture_rev + v_row_ext, 2);
        EXCEPTION
          WHEN OTHERS THEN
            CONTINUE;
        END;
      END LOOP;
    END IF;
  END IF;

  IF v_fixture_inserts > 0 THEN
    UPDATE public.jobs_ledger
    SET revenue = v_fixture_rev
    WHERE id = v_job_id;
  END IF;

  RETURN v_job_id;
END;
$$;


