--
-- Name: create_po_from_job_tally("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_po_from_job_tally"("p_job_id" "uuid", "p_entries" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_hcp text;
  v_master_id uuid;
  v_service_type_id uuid;
  v_po_name text;
  v_po_id uuid;
  v_entry jsonb;
  v_part_id uuid;
  v_qty numeric;
  v_merged jsonb := '{}'::jsonb;
  v_part_key text;
  v_total_qty numeric;
  v_price numeric;
  v_supply_house_id uuid;
  v_seq int := 0;
  v_first_part_id uuid;
BEGIN
  IF p_entries IS NULL OR jsonb_array_length(p_entries) = 0 THEN
    RETURN jsonb_build_object('error', 'No entries provided');
  END IF;

  -- 1. Get job hcp_number and master_user_id
  SELECT COALESCE(hcp_number, 'NoHCP'), master_user_id
  INTO v_hcp, v_master_id
  FROM public.jobs_ledger
  WHERE id = p_job_id;

  IF v_master_id IS NULL THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  -- 2. Get service_type_id from first part with part_id (fallback: first service_type)
  FOR v_entry IN SELECT * FROM jsonb_array_elements(p_entries)
  LOOP
    v_first_part_id := (v_entry->>'part_id')::uuid;
    IF v_first_part_id IS NOT NULL THEN
      EXIT;
    END IF;
  END LOOP;
  IF v_first_part_id IS NOT NULL THEN
    SELECT service_type_id INTO v_service_type_id
    FROM public.material_parts
    WHERE id = v_first_part_id;
  END IF;
  IF v_service_type_id IS NULL THEN
    SELECT id INTO v_service_type_id
    FROM public.service_types
    ORDER BY sequence_order ASC
    LIMIT 1;
  END IF;
  IF v_service_type_id IS NULL THEN
    RETURN jsonb_build_object('error', 'No service type available');
  END IF;

  -- 3. Build PO name: "Job Parts [HCP#] [YYYY-MM-DD]"
  v_po_name := 'Job Parts ' || v_hcp || ' ' || to_char(now(), 'YYYY-MM-DD');

  -- 4. Insert purchase_orders
  INSERT INTO public.purchase_orders (name, created_by, service_type_id, status, supply_house_id)
  VALUES (v_po_name, v_master_id, v_service_type_id, 'draft', null)
  RETURNING id INTO v_po_id;

  -- 5. Merge entries by part_id (sum quantities), skip entries where part_id is null (fixture-only)
  FOR v_entry IN SELECT * FROM jsonb_array_elements(p_entries)
  LOOP
    v_part_id := (v_entry->>'part_id')::uuid;
    IF v_part_id IS NULL THEN
      CONTINUE;
    END IF;
    v_qty := (v_entry->>'quantity')::numeric;
    v_part_key := v_part_id::text;
    v_total_qty := COALESCE((v_merged->v_part_key->>'quantity')::numeric, 0) + v_qty;
    v_merged := v_merged || jsonb_build_object(v_part_key, jsonb_build_object('part_id', v_part_id, 'quantity', v_total_qty));
  END LOOP;

  -- 6. Insert purchase_order_items for each merged part
  FOR v_part_key, v_entry IN SELECT * FROM jsonb_each(v_merged)
  LOOP
    v_part_id := (v_entry->>'part_id')::uuid;
    v_total_qty := (v_entry->>'quantity')::numeric;

    -- Get best price (lowest) for this part
    SELECT price, supply_house_id INTO v_price, v_supply_house_id
    FROM public.material_part_prices
    WHERE part_id = v_part_id
    ORDER BY price ASC
    LIMIT 1;

    v_price := COALESCE(v_price, 0);
    v_seq := v_seq + 1;

    INSERT INTO public.purchase_order_items (
      purchase_order_id, part_id, quantity, price_at_time,
      sequence_order, selected_supply_house_id
    )
    VALUES (v_po_id, v_part_id, v_total_qty, v_price, v_seq, v_supply_house_id);
  END LOOP;

  RETURN jsonb_build_object('po_id', v_po_id);
END;
$$;


ALTER FUNCTION "public"."create_po_from_job_tally"("p_job_id" "uuid", "p_entries" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "create_po_from_job_tally"("p_job_id" "uuid", "p_entries" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."create_po_from_job_tally"("p_job_id" "uuid", "p_entries" "jsonb") IS 'Creates a Purchase Order from Job Tally entries. Called when user saves on Job Tally. PO name: Job Parts [HCP#] [date time]. SECURITY DEFINER so subs can trigger.';


--
-- Name: create_project_with_template("text", "uuid", "text", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_project_with_template"("p_name" "text", "p_customer_id" "uuid", "p_address" "text", "p_master_user_id" "uuid", "p_template_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_project_id UUID;
  v_workflow_id UUID;
  v_workflow_name TEXT;
  v_template_step RECORD;
BEGIN
  -- 1. Insert the project
  INSERT INTO projects (
    name,
    customer_id,
    address,
    master_user_id,
    status,
    notes,
    created_at,
    updated_at
  )
  VALUES (
    p_name,
    p_customer_id,
    p_address,
    p_master_user_id,
    'active',
    p_notes,
    NOW(),
    NOW()
  )
  RETURNING id INTO v_project_id;

  -- 2. If template specified, create workflow and steps
  IF p_template_id IS NOT NULL THEN
    v_workflow_name := p_name || ' workflow';
    
    -- Create the workflow
    INSERT INTO project_workflows (
      project_id,
      template_id,
      name,
      created_at,
      updated_at
    )
    VALUES (
      v_project_id,
      p_template_id,
      v_workflow_name,
      NOW(),
      NOW()
    )
    RETURNING id INTO v_workflow_id;

    -- Create all steps from the template
    FOR v_template_step IN
      SELECT id, sequence_order, name, step_type, required_skill
      FROM workflow_template_steps
      WHERE template_id = p_template_id
      ORDER BY sequence_order
    LOOP
      INSERT INTO project_workflow_steps (
        workflow_id,
        template_step_id,
        sequence_order,
        name,
        step_type,
        assigned_skill,
        status,
        created_at,
        updated_at
      )
      VALUES (
        v_workflow_id,
        v_template_step.id,
        v_template_step.sequence_order,
        v_template_step.name,
        v_template_step.step_type,
        v_template_step.required_skill,
        'pending',
        NOW(),
        NOW()
      );
    END LOOP;
    
    RETURN jsonb_build_object(
      'project_id', v_project_id,
      'workflow_id', v_workflow_id,
      'success', true
    );
  ELSE
    RETURN jsonb_build_object(
      'project_id', v_project_id,
      'workflow_id', NULL,
      'success', true
    );
  END IF;

EXCEPTION
  WHEN OTHERS THEN
    -- Transaction automatically rolls back on exception
    RAISE EXCEPTION 'Failed to create project with template: %', SQLERRM;
END;
$$;


ALTER FUNCTION "public"."create_project_with_template"("p_name" "text", "p_customer_id" "uuid", "p_address" "text", "p_master_user_id" "uuid", "p_template_id" "uuid", "p_notes" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "create_project_with_template"("p_name" "text", "p_customer_id" "uuid", "p_address" "text", "p_master_user_id" "uuid", "p_template_id" "uuid", "p_notes" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."create_project_with_template"("p_name" "text", "p_customer_id" "uuid", "p_address" "text", "p_master_user_id" "uuid", "p_template_id" "uuid", "p_notes" "text") IS 'Creates a project with optional workflow from template. All operations are transactional - if any step fails, all changes are rolled back.';


--
-- Name: create_takeoff_entry_with_items("uuid", "text", "jsonb", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_takeoff_entry_with_items"("p_bid_id" "uuid", "p_page" "text", "p_entry_data" "jsonb", "p_items" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_entry_id UUID;
  v_item JSONB;
  v_items_created INTEGER := 0;
BEGIN
  -- 1. Create the entry
  INSERT INTO takeoff_book_entries (
    bid_id,
    page,
    item_type,
    item_size,
    fitting_type,
    created_at,
    updated_at
  )
  VALUES (
    p_bid_id,
    p_page,
    p_entry_data->>'item_type',
    p_entry_data->>'item_size',
    p_entry_data->>'fitting_type',
    NOW(),
    NOW()
  )
  RETURNING id INTO v_entry_id;

  -- 2. Create all items
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    INSERT INTO takeoff_book_entry_items (
      entry_id,
      quantity,
      location,
      notes,
      created_at,
      updated_at
    )
    VALUES (
      v_entry_id,
      (v_item->>'quantity')::INTEGER,
      v_item->>'location',
      v_item->>'notes',
      NOW(),
      NOW()
    );
    
    v_items_created := v_items_created + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'entry_id', v_entry_id,
    'items_created', v_items_created,
    'success', true
  );

EXCEPTION
  WHEN OTHERS THEN
    -- Transaction automatically rolls back on exception
    RAISE EXCEPTION 'Failed to create takeoff entry with items: %', SQLERRM;
END;
$$;


ALTER FUNCTION "public"."create_takeoff_entry_with_items"("p_bid_id" "uuid", "p_page" "text", "p_entry_data" "jsonb", "p_items" "jsonb") OWNER TO "postgres";

