--
-- Name: delete_billed_invoice_on_send_back("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."delete_billed_invoice_on_send_back"("p_invoice_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_job_id uuid;
  v_status text;
  v_deleted uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not authenticated');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not authorized');
  END IF;

  SELECT i.job_id, i.status INTO v_job_id, v_status
  FROM public.jobs_ledger_invoices i
  WHERE i.id = p_invoice_id;

  IF v_job_id IS NULL THEN
    RETURN jsonb_build_object('ok', true, 'deleted', false);
  END IF;

  IF v_status IS DISTINCT FROM 'billed' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Invoice is not Billed Awaiting Payment');
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.jobs_ledger_payments p WHERE p.invoice_id = p_invoice_id
  ) THEN
    RETURN jsonb_build_object(
      'ok',
      false,
      'error',
      'This invoice has recorded payments. Adjust or unlink those payments before sending back.'
    );
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger j
    WHERE j.id = v_job_id
      AND (
        j.master_user_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.users u WHERE u.id = auth.uid() AND u.role = 'primary')
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = auth.uid() AND assistant_id = j.master_user_id
        )
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = j.master_user_id AND assistant_id = auth.uid()
        )
        OR public.assistants_share_master(auth.uid(), j.master_user_id)
      )
  ) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not authorized');
  END IF;

  DELETE FROM public.jobs_ledger_invoices
  WHERE id = p_invoice_id
    AND status = 'billed'
  RETURNING id INTO v_deleted;

  IF v_deleted IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'deleted', true);
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.jobs_ledger_invoices WHERE id = p_invoice_id) THEN
    RETURN jsonb_build_object('ok', true, 'deleted', false);
  END IF;

  RETURN jsonb_build_object('ok', false, 'error', 'Could not delete invoice');
END;
$$;


ALTER FUNCTION "public"."delete_billed_invoice_on_send_back"("p_invoice_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "delete_billed_invoice_on_send_back"("p_invoice_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."delete_billed_invoice_on_send_back"("p_invoice_id" "uuid") IS 'Deletes a jobs_ledger_invoices row only when status is billed and caller has job access; blocks if jobs_ledger_payments references the invoice. Idempotent: missing row returns ok=true deleted=false.';


--
-- Name: delete_ready_to_bill_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."delete_ready_to_bill_invoice"("p_invoice_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_job_id uuid;
  v_status text;
  v_deleted uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not authenticated');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not authorized');
  END IF;

  SELECT i.job_id, i.status INTO v_job_id, v_status
  FROM public.jobs_ledger_invoices i
  WHERE i.id = p_invoice_id;

  IF v_job_id IS NULL THEN
    RETURN jsonb_build_object('ok', true, 'deleted', false);
  END IF;

  IF v_status IS DISTINCT FROM 'ready_to_bill' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Invoice is not a Ready to Bill draft');
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger j
    WHERE j.id = v_job_id
      AND (
        j.master_user_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.users u WHERE u.id = auth.uid() AND u.role = 'primary')
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = auth.uid() AND assistant_id = j.master_user_id
        )
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = j.master_user_id AND assistant_id = auth.uid()
        )
        OR public.assistants_share_master(auth.uid(), j.master_user_id)
      )
  ) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Not authorized');
  END IF;

  DELETE FROM public.jobs_ledger_invoices
  WHERE id = p_invoice_id
    AND status = 'ready_to_bill'
  RETURNING id INTO v_deleted;

  IF v_deleted IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'deleted', true);
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.jobs_ledger_invoices WHERE id = p_invoice_id) THEN
    RETURN jsonb_build_object('ok', true, 'deleted', false);
  END IF;

  RETURN jsonb_build_object('ok', false, 'error', 'Could not delete invoice');
END;
$$;


ALTER FUNCTION "public"."delete_ready_to_bill_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "delete_ready_to_bill_invoice"("p_invoice_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."delete_ready_to_bill_invoice"("p_invoice_id" "uuid") IS 'Deletes a jobs_ledger_invoices row only when status is ready_to_bill and caller has job access. Idempotent: missing row returns ok=true deleted=false.';


--
-- Name: dev_reset_estimates_for_testing(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."dev_reset_estimates_for_testing"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  uid uuid := auth.uid();
  deleted_count int;
  max_en int;
BEGIN
  IF uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT public.is_dev() THEN
    RAISE EXCEPTION 'Only dev users may reset estimates';
  END IF;

  DELETE FROM public.estimates WHERE true;

  GET DIAGNOSTICS deleted_count = ROW_COUNT;

  SELECT MAX(estimate_number) INTO max_en FROM public.estimates;
  IF max_en IS NULL THEN
    PERFORM setval('public.estimates_estimate_number_seq', 1, false);
  ELSE
    PERFORM setval('public.estimates_estimate_number_seq', max_en, true);
  END IF;

  RETURN deleted_count;
END;
$$;


ALTER FUNCTION "public"."dev_reset_estimates_for_testing"() OWNER TO "postgres";

--
-- Name: FUNCTION "dev_reset_estimates_for_testing"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."dev_reset_estimates_for_testing"() IS 'Dev only: DELETE all estimates (WHERE true for pg_safeupdate); resets sequence: empty table -> setval(1,false), else MAX+1 via is_called true.';


--
-- Name: dismiss_mercury_duplicate_pair("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."dismiss_mercury_duplicate_pair"("p_id_a" "uuid", "p_id_b" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  uid uuid := auth.uid();
  v_lo uuid;
  v_hi uuid;
begin
  if uid is null then
    raise exception 'dismiss_mercury_duplicate_pair: not authenticated';
  end if;
  if not exists (
    select 1 from public.users u
    where u.id = uid and u.role in ('dev', 'master_technician', 'assistant')
  ) then
    raise exception 'dismiss_mercury_duplicate_pair: not authorized';
  end if;
  if p_id_a = p_id_b then
    raise exception 'dismiss_mercury_duplicate_pair: need two distinct transactions';
  end if;
  v_lo := least(p_id_a, p_id_b);
  v_hi := greatest(p_id_a, p_id_b);
  insert into public.mercury_transaction_duplicate_dismissals (id_lo, id_hi, dismissed_by)
  values (v_lo, v_hi, uid)
  on conflict (id_lo, id_hi) do nothing;
end;
$$;


ALTER FUNCTION "public"."dismiss_mercury_duplicate_pair"("p_id_a" "uuid", "p_id_b" "uuid") OWNER TO "postgres";

