CREATE OR REPLACE FUNCTION "public"."dispatch_inbox_note_stats"("p_request_ids" "uuid"[]) RETURNS TABLE("request_id" "uuid", "note_count" bigint, "last_note_at" timestamp with time zone)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT n.request_id,
         count(*)::bigint AS note_count,
         max(n.created_at) AS last_note_at
