--
-- Name: dispatch_requests_guard_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."dispatch_requests_guard_update"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF OLD.from_user_id IS DISTINCT FROM NEW.from_user_id
     OR OLD.title IS DISTINCT FROM NEW.title
     OR OLD.links IS DISTINCT FROM NEW.links
     OR OLD.created_at IS DISTINCT FROM NEW.created_at
     OR OLD.job_ledger_id IS DISTINCT FROM NEW.job_ledger_id
     OR OLD.bid_id IS DISTINCT FROM NEW.bid_id
     OR OLD.reference_summary IS DISTINCT FROM NEW.reference_summary
     OR OLD.location_lat IS DISTINCT FROM NEW.location_lat
     OR OLD.location_lng IS DISTINCT FROM NEW.location_lng
  THEN
    IF NOT public.is_dev() THEN
      RAISE EXCEPTION 'Cannot modify dispatch request content';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."dispatch_requests_guard_update"() OWNER TO "postgres";

--
-- Name: duplicate_bid_to_service_type("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."duplicate_bid_to_service_type"("p_source_bid_id" "uuid", "p_target_service_type_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_new_bid_id uuid;
  v_src public.bids%ROWTYPE;
  v_new_count_id uuid;
  v_old_ce_id uuid;
  v_new_ce_id uuid;
  r_count RECORD;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  SELECT * INTO v_src FROM public.bids WHERE id = p_source_bid_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Source bid not found';
  END IF;

  IF v_src.service_type_id = p_target_service_type_id THEN
    RAISE EXCEPTION 'Target service type must differ from source bid';
  END IF;

  DROP TABLE IF EXISTS _dup_bid_count_row_map;
  CREATE TEMP TABLE _dup_bid_count_row_map (
    old_id uuid PRIMARY KEY,
    new_id uuid NOT NULL
  ) ON COMMIT DROP;

  INSERT INTO public.bids (
    created_by,
    service_type_id,
    customer_id,
    gc_builder_id,
    project_name,
    address,
    drive_link,
    plans_link,
    count_tooling_link,
    bid_submission_link,
    design_drawing_plan_date,
    plan_pages,
    gc_contact_name,
    gc_contact_phone,
    gc_contact_email,
    estimator_id,
    account_manager_id,
    bid_due_date,
    submitted_to,
    notes,
    distance_from_office,
    selected_takeoff_book_version_id,
    selected_labor_book_version_id,
    selected_price_book_version_id,
    materials_model
  )
  VALUES (
    v_uid,
    p_target_service_type_id,
    v_src.customer_id,
    v_src.gc_builder_id,
    v_src.project_name,
    v_src.address,
    v_src.drive_link,
    v_src.plans_link,
    v_src.count_tooling_link,
    v_src.bid_submission_link,
    v_src.design_drawing_plan_date,
    v_src.plan_pages,
    v_src.gc_contact_name,
    v_src.gc_contact_phone,
    v_src.gc_contact_email,
    v_src.estimator_id,
    v_src.account_manager_id,
    v_src.bid_due_date,
    v_src.submitted_to,
    v_src.notes,
    v_src.distance_from_office,
    v_src.selected_takeoff_book_version_id,
    v_src.selected_labor_book_version_id,
    v_src.selected_price_book_version_id,
    v_src.materials_model
  )
  RETURNING id INTO v_new_bid_id;

  FOR r_count IN
    SELECT id, fixture, count, group_tag, page, sequence_order
    FROM public.bids_count_rows
    WHERE bid_id = p_source_bid_id
    ORDER BY sequence_order, id
  LOOP
    INSERT INTO public.bids_count_rows (
      bid_id, fixture, count, group_tag, page, sequence_order
    )
    VALUES (
      v_new_bid_id,
      r_count.fixture,
      r_count.count,
      r_count.group_tag,
      r_count.page,
      r_count.sequence_order
    )
    RETURNING id INTO v_new_count_id;

    INSERT INTO _dup_bid_count_row_map (old_id, new_id)
    VALUES (r_count.id, v_new_count_id);
  END LOOP;

  INSERT INTO public.bid_count_row_custom_prices (
    bid_id, count_row_id, price_book_version_id, unit_price
  )
  SELECT
    v_new_bid_id,
    m.new_id,
    c.price_book_version_id,
    c.unit_price
  FROM public.bid_count_row_custom_prices c
  INNER JOIN _dup_bid_count_row_map m ON m.old_id = c.count_row_id
  WHERE c.bid_id = p_source_bid_id;

  INSERT INTO public.bid_count_row_submission_hides (
    bid_id,
    count_row_id,
    price_book_version_id
  )
  SELECT
    v_new_bid_id,
    m.new_id,
    h.price_book_version_id
  FROM public.bid_count_row_submission_hides h
  INNER JOIN _dup_bid_count_row_map m ON m.old_id = h.count_row_id
  WHERE h.bid_id = p_source_bid_id;

  INSERT INTO public.bid_pricing_assignments (
    bid_id,
    count_row_id,
    is_fixed_price,
    price_book_entry_id,
    price_book_version_id,
    unit_price_override
  )
  SELECT
    v_new_bid_id,
    m.new_id,
    p.is_fixed_price,
    p.price_book_entry_id,
    p.price_book_version_id,
    p.unit_price_override
  FROM public.bid_pricing_assignments p
  INNER JOIN _dup_bid_count_row_map m ON m.old_id = p.count_row_id
  WHERE p.bid_id = p_source_bid_id;

  INSERT INTO public.bids_takeoff_rough_part_lines (
    bid_id,
    count_row_id,
    part_id,
    quantity,
    sequence_order,
    source_material_part_price_id,
    source_template_id,
    unit_price
  )
  SELECT
    v_new_bid_id,
    m.new_id,
    t.part_id,
    t.quantity,
    t.sequence_order,
    t.source_material_part_price_id,
    t.source_template_id,
    t.unit_price
  FROM public.bids_takeoff_rough_part_lines t
  INNER JOIN _dup_bid_count_row_map m ON m.old_id = t.count_row_id
  WHERE t.bid_id = p_source_bid_id;

  INSERT INTO public.bids_takeoff_template_mappings (
    bid_id,
    count_row_id,
    quantity,
    sequence_order,
    stage,
    template_id
  )
  SELECT
    v_new_bid_id,
    m.new_id,
    tm.quantity,
    tm.sequence_order,
    tm.stage,
    tm.template_id
  FROM public.bids_takeoff_template_mappings tm
  INNER JOIN _dup_bid_count_row_map m ON m.old_id = tm.count_row_id
  WHERE tm.bid_id = p_source_bid_id;

  SELECT id INTO v_old_ce_id
  FROM public.cost_estimates
  WHERE bid_id = p_source_bid_id
  LIMIT 1;

  IF v_old_ce_id IS NOT NULL THEN
    INSERT INTO public.cost_estimates (
      bid_id,
      driving_cost_rate,
      estimator_cost_flat_amount,
      estimator_cost_per_count,
      hours_per_trip,
      labor_rate
    )
    SELECT
      v_new_bid_id,
      driving_cost_rate,
      estimator_cost_flat_amount,
      estimator_cost_per_count,
      hours_per_trip,
      labor_rate
    FROM public.cost_estimates
    WHERE id = v_old_ce_id
    RETURNING id INTO v_new_ce_id;

    INSERT INTO public.cost_estimate_labor_rows (
      cost_estimate_id,
      count,
      fixture,
      is_fixed,
      rough_in_hrs_per_unit,
      sequence_order,
      top_out_hrs_per_unit,
      trim_set_hrs_per_unit
    )
    SELECT
      v_new_ce_id,
      lr.count,
      lr.fixture,
      lr.is_fixed,
      lr.rough_in_hrs_per_unit,
      lr.sequence_order,
      lr.top_out_hrs_per_unit,
      lr.trim_set_hrs_per_unit
    FROM public.cost_estimate_labor_rows lr
    WHERE lr.cost_estimate_id = v_old_ce_id;
  END IF;

  RETURN v_new_bid_id;
END;
$$;


ALTER FUNCTION "public"."duplicate_bid_to_service_type"("p_source_bid_id" "uuid", "p_target_service_type_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "duplicate_bid_to_service_type"("p_source_bid_id" "uuid", "p_target_service_type_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."duplicate_bid_to_service_type"("p_source_bid_id" "uuid", "p_target_service_type_id" "uuid") IS 'Creates a new bid copying counts, pricing (incl. submission hides), takeoff, and cost estimate from the source with a new service_type_id; resets status/financial/sent fields.';


--
-- Name: duplicate_purchase_order("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."duplicate_purchase_order"("p_source_po_id" "uuid", "p_created_by" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_new_po_id UUID;
  v_source_po RECORD;
  v_item RECORD;
  v_items_copied INTEGER := 0;
BEGIN
  -- 1. Load source PO
  SELECT * INTO v_source_po
  FROM purchase_orders
  WHERE id = p_source_po_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Source purchase order not found: %', p_source_po_id;
  END IF;

  -- 2. Create new draft PO
  INSERT INTO purchase_orders (
    name,
    status,
    created_by,
    notes,
    created_at,
    updated_at
  )
  VALUES (
    'Copy of ' || v_source_po.name,
    'draft',
    p_created_by,
    v_source_po.notes,
    NOW(),
    NOW()
  )
  RETURNING id INTO v_new_po_id;

  -- 3. Copy all items from source PO
  FOR v_item IN
    SELECT 
      part_id,
      quantity,
      selected_supply_house_id,
      price_at_time,
      sequence_order,
      notes,
      source_template_id
    FROM purchase_order_items
    WHERE purchase_order_id = p_source_po_id
    ORDER BY sequence_order
  LOOP
    INSERT INTO purchase_order_items (
      purchase_order_id,
      part_id,
      quantity,
      selected_supply_house_id,
      price_at_time,
      sequence_order,
      notes,
      source_template_id,
      created_at,
      updated_at
    )
    VALUES (
      v_new_po_id,
      v_item.part_id,
      v_item.quantity,
      v_item.selected_supply_house_id,
      v_item.price_at_time,
      v_item.sequence_order,
      v_item.notes,
      v_item.source_template_id,
      NOW(),
      NOW()
    );
    
    v_items_copied := v_items_copied + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'new_po_id', v_new_po_id,
    'items_copied', v_items_copied,
    'success', true
  );

EXCEPTION
  WHEN OTHERS THEN
    -- Transaction automatically rolls back on exception
    RAISE EXCEPTION 'Failed to duplicate purchase order: %', SQLERRM;
END;
$$;


ALTER FUNCTION "public"."duplicate_purchase_order"("p_source_po_id" "uuid", "p_created_by" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "duplicate_purchase_order"("p_source_po_id" "uuid", "p_created_by" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."duplicate_purchase_order"("p_source_po_id" "uuid", "p_created_by" "uuid") IS 'Duplicates a purchase order with all its items as a new draft. Transactional - all or nothing.';


--
-- Name: enforce_customers_estimator_update_immutable_fields(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enforce_customers_estimator_update_immutable_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role = 'estimator'
  ) THEN
    RETURN NEW;
  END IF;

  IF NEW.master_user_id IS DISTINCT FROM OLD.master_user_id THEN
    RAISE EXCEPTION 'Estimators cannot change customer owner (master).';
  END IF;

  IF NEW.stripe_customer_id IS DISTINCT FROM OLD.stripe_customer_id THEN
    RAISE EXCEPTION 'Estimators cannot change Stripe customer link.';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."enforce_customers_estimator_update_immutable_fields"() OWNER TO "postgres";

--
-- Name: FUNCTION "enforce_customers_estimator_update_immutable_fields"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."enforce_customers_estimator_update_immutable_fields"() IS 'Before UPDATE on customers: if caller is estimator, forbid changing master_user_id or stripe_customer_id.';


--
-- Name: enforce_people_labels_same_master(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enforce_people_labels_same_master"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  p_master uuid;
  l_master uuid;
BEGIN
  SELECT master_user_id INTO p_master FROM public.people WHERE id = NEW.person_id;
  SELECT master_user_id INTO l_master FROM public.labels WHERE id = NEW.label_id;
  IF p_master IS NULL THEN
    RAISE EXCEPTION 'people_labels: person not found for person_id %', NEW.person_id;
  END IF;
  IF l_master IS NULL THEN
    RAISE EXCEPTION 'people_labels: label not found for label_id %', NEW.label_id;
  END IF;
  IF p_master IS DISTINCT FROM l_master THEN
    RAISE EXCEPTION 'people_labels: person and label must belong to the same master';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."enforce_people_labels_same_master"() OWNER TO "postgres";

--
-- Name: enforce_user_app_activity_viewer_role(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enforce_user_app_activity_viewer_role"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  r text;
BEGIN
  SELECT role INTO r FROM public.users WHERE id = NEW.viewer_user_id;
  IF r IS NULL THEN
    RAISE EXCEPTION 'viewer_user_id must reference an existing user';
  END IF;
  IF r NOT IN ('assistant', 'master_technician', 'primary') THEN
    RAISE EXCEPTION 'Activity viewer must be assistant, master_technician, or primary';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."enforce_user_app_activity_viewer_role"() OWNER TO "postgres";

--
-- Name: enforce_user_labels_scope_master(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."enforce_user_labels_scope_master"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  l_master uuid;
  u_role text;
  u_email text;
BEGIN
  SELECT master_user_id INTO l_master FROM public.labels WHERE id = NEW.label_id;
  IF l_master IS NULL THEN
    RAISE EXCEPTION 'user_labels: label not found for label_id %', NEW.label_id;
  END IF;

  SELECT role::text, email INTO u_role, u_email FROM public.users WHERE id = NEW.user_id;
  IF u_role IS NULL THEN
    RAISE EXCEPTION 'user_labels: user not found for user_id %', NEW.user_id;
  END IF;

  IF u_role IN ('master_technician', 'dev') AND NEW.user_id = l_master THEN
    RETURN NEW;
  END IF;

  IF u_role = 'assistant' AND EXISTS (
    SELECT 1 FROM public.master_assistants
    WHERE assistant_id = NEW.user_id AND master_id = l_master
  ) THEN
    RETURN NEW;
  END IF;

  IF u_role = 'superintendent' AND EXISTS (
    SELECT 1 FROM public.master_superintendents
    WHERE superintendent_id = NEW.user_id AND master_id = l_master
  ) THEN
    RETURN NEW;
  END IF;

  IF u_email IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.people p
    WHERE p.master_user_id = l_master
      AND p.archived_at IS NULL
      AND lower(trim(p.email)) = lower(trim(u_email))
  ) THEN
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.user_tag_org uto
    WHERE uto.user_id = NEW.user_id AND uto.master_user_id = l_master
  ) THEN
    RETURN NEW;
  END IF;

  RAISE EXCEPTION 'user_labels: user % is not in scope for label master %', NEW.user_id, l_master;
END;
$$;


ALTER FUNCTION "public"."enforce_user_labels_scope_master"() OWNER TO "postgres";

--
-- Name: ensure_job_team_member_from_schedule_block(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."ensure_job_team_member_from_schedule_block"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.job_id IS NULL OR NEW.assignee_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.jobs_ledger_team_members (job_id, user_id)
  VALUES (NEW.job_id, NEW.assignee_user_id)
  ON CONFLICT (job_id, user_id) DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."ensure_job_team_member_from_schedule_block"() OWNER TO "postgres";

--
-- Name: FUNCTION "ensure_job_team_member_from_schedule_block"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."ensure_job_team_member_from_schedule_block"() IS 'AFTER INSERT on job_schedule_blocks: add assignee to jobs ledger team (additive; complements UI Add to job). Bypasses roster INSERT RLS.';


--
-- Name: ensure_single_ready_to_bill_invoice_for_job("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."ensure_single_ready_to_bill_invoice_for_job"("p_job_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  j RECORD;
  v_allocated numeric(12, 2);
  v_unalloc numeric(12, 2);
  v_primary_count integer;
  v_rtb_count integer;
  v_max_seq integer;
  v_inv_id uuid;
  v_inv_amount numeric(12, 2);
  v_stripe_id text;
  v_hosted text;
  v_est date;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('error', 'Not authenticated');
  END IF;

  SELECT jl.id,
         jl.status,
         jl.revenue,
         jl.payments_made,
         jl.last_bill_date,
         jl.master_user_id
  INTO j
  FROM public.jobs_ledger jl
  WHERE jl.id = p_job_id;

  IF j.id IS NULL THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  IF j.status IS DISTINCT FROM 'ready_to_bill' THEN
    RETURN jsonb_build_object('error', 'Job must be in Ready to Bill');
  END IF;

  IF NOT (
    EXISTS (
      SELECT 1 FROM public.users u
      WHERE u.id = auth.uid()
        AND u.role IN ('dev', 'master_technician', 'assistant', 'primary')
    )
    AND (
      j.master_user_id = auth.uid()
      OR public.is_dev()
      OR EXISTS (SELECT 1 FROM public.users u WHERE u.id = auth.uid() AND u.role = 'primary')
      OR EXISTS (
        SELECT 1 FROM public.master_assistants ma
        WHERE ma.master_id = auth.uid() AND ma.assistant_id = j.master_user_id
      )
      OR EXISTS (
        SELECT 1 FROM public.master_assistants ma
        WHERE ma.master_id = j.master_user_id AND ma.assistant_id = auth.uid()
      )
      OR public.assistants_share_master(auth.uid(), j.master_user_id)
    )
  ) THEN
    RETURN jsonb_build_object('error', 'Not authorized');
  END IF;

  SELECT COALESCE(SUM(i.amount), 0)::numeric(12, 2)
  INTO v_allocated
  FROM public.jobs_ledger_invoices i
  WHERE i.job_id = p_job_id
    AND i.status IN ('ready_to_bill', 'billed');

  v_unalloc := GREATEST(
    0::numeric(12, 2),
    COALESCE(j.revenue, 0)::numeric(12, 2)
      - COALESCE(j.payments_made, 0)::numeric(12, 2)
      - v_allocated
  );

  SELECT COUNT(*)::integer
  INTO v_primary_count
  FROM public.jobs_ledger_invoices i
  WHERE i.job_id = p_job_id
    AND i.status = 'ready_to_bill'
    AND i.is_primary_rtb_bundle IS TRUE;

  IF v_primary_count > 1 THEN
    RETURN jsonb_build_object(
      'error',
      'Multiple primary remainder Ready-to-Bill rows exist for this job; fix is_primary_rtb_bundle so only one is true.'
    );
  END IF;

  IF v_primary_count = 0 THEN
    IF v_unalloc > 0::numeric(12, 2) THEN
      SELECT COUNT(*)::integer
      INTO v_rtb_count
      FROM public.jobs_ledger_invoices i
      WHERE i.job_id = p_job_id
        AND i.status = 'ready_to_bill';

      IF v_rtb_count = 1 THEN
        SELECT i.id, i.amount, i.stripe_invoice_id, i.hosted_invoice_url
        INTO v_inv_id, v_inv_amount, v_stripe_id, v_hosted
        FROM public.jobs_ledger_invoices i
        WHERE i.job_id = p_job_id
          AND i.status = 'ready_to_bill'
        LIMIT 1;

        IF v_inv_amount = v_unalloc THEN
          IF v_stripe_id IS NOT NULL AND trim(v_stripe_id) <> '' AND v_hosted IS NOT NULL AND trim(v_hosted) <> '' THEN
            UPDATE public.jobs_ledger_invoices
            SET is_primary_rtb_bundle = true
            WHERE id = v_inv_id;

            RETURN jsonb_build_object(
              'ok', true,
              'invoice_id', v_inv_id,
              'amount', v_inv_amount,
              'created', false
            );
          END IF;

          UPDATE public.jobs_ledger_invoices
          SET amount = v_unalloc,
              is_primary_rtb_bundle = true
          WHERE id = v_inv_id;

          RETURN jsonb_build_object(
            'ok', true,
            'invoice_id', v_inv_id,
            'amount', v_unalloc,
            'created', false
          );
        END IF;
      END IF;

      SELECT COALESCE(MAX(i.sequence_order), -1) + 1
      INTO v_max_seq
      FROM public.jobs_ledger_invoices i
      WHERE i.job_id = p_job_id;

      v_est := NULL;
      IF j.last_bill_date IS NOT NULL AND trim(j.last_bill_date::text) <> '' THEN
        BEGIN
          v_est := j.last_bill_date::date;
        EXCEPTION WHEN OTHERS THEN
          v_est := NULL;
        END;
      END IF;

      INSERT INTO public.jobs_ledger_invoices (
        job_id,
        amount,
        status,
        sequence_order,
        estimated_bill_date,
        is_primary_rtb_bundle
      )
      VALUES (
        p_job_id,
        v_unalloc,
        'ready_to_bill',
        v_max_seq,
        v_est,
        true
      )
      RETURNING id INTO v_inv_id;

      RETURN jsonb_build_object(
        'ok', true,
        'invoice_id', v_inv_id,
        'amount', v_unalloc,
        'created', true
      );
    END IF;

    SELECT COUNT(*)::integer
    INTO v_rtb_count
    FROM public.jobs_ledger_invoices i
    WHERE i.job_id = p_job_id
      AND i.status = 'ready_to_bill';

    IF v_rtb_count > 0 THEN
      RETURN jsonb_build_object(
        'error',
        'No remainder to bill on the job bundle; use Bill Customer from a partial invoice row or adjust amounts.'
      );
    END IF;

    RETURN jsonb_build_object('error', 'Nothing left to bill for this job');
  END IF;

  SELECT i.id, i.amount, i.stripe_invoice_id, i.hosted_invoice_url
  INTO v_inv_id, v_inv_amount, v_stripe_id, v_hosted
  FROM public.jobs_ledger_invoices i
  WHERE i.job_id = p_job_id
    AND i.status = 'ready_to_bill'
    AND i.is_primary_rtb_bundle IS TRUE
  LIMIT 1;

  IF v_stripe_id IS NOT NULL AND trim(v_stripe_id) <> '' AND v_hosted IS NOT NULL AND trim(v_hosted) <> '' THEN
    RETURN jsonb_build_object(
      'ok', true,
      'invoice_id', v_inv_id,
      'amount', v_inv_amount,
      'created', false
    );
  END IF;

  UPDATE public.jobs_ledger_invoices
  SET amount = v_unalloc,
      is_primary_rtb_bundle = true
  WHERE id = v_inv_id;

  IF v_unalloc > 0::numeric(12, 2) THEN
    RETURN jsonb_build_object(
      'ok', true,
      'invoice_id', v_inv_id,
      'amount', v_unalloc,
      'created', false
    );
  END IF;

  RETURN jsonb_build_object('error', 'Nothing left to bill; invoice amount would be zero');
END;
$$;


ALTER FUNCTION "public"."ensure_single_ready_to_bill_invoice_for_job"("p_job_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "ensure_single_ready_to_bill_invoice_for_job"("p_job_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."ensure_single_ready_to_bill_invoice_for_job"("p_job_id" "uuid") IS 'Syncs the single primary remainder ready_to_bill row (is_primary_rtb_bundle true) to unallocated job balance. Partial RTB rows stay fixed; never updates their amounts. Creates the primary row when missing and balance remains. Errors if more than one primary RTB row.';


--
-- Name: estimate_accept_notify_filter_eligible_user_ids("uuid", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimate_accept_notify_filter_eligible_user_ids"("p_master_user_id" "uuid", "p_candidate_ids" "uuid"[]) RETURNS "uuid"[]
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT COALESCE(
    (
      SELECT array_agg(s.uid ORDER BY s.uid)
      FROM (
        SELECT DISTINCT c.sub AS uid
        FROM unnest(COALESCE(p_candidate_ids, ARRAY[]::uuid[])) AS c(sub)
        JOIN public.users u ON u.id = c.sub
        WHERE u.archived_at IS NULL
          AND u.email IS NOT NULL
          AND length(trim(u.email)) > 0
          AND (
            u.id = p_master_user_id
            OR EXISTS (
              SELECT 1 FROM public.master_assistants ma
              WHERE ma.master_id = p_master_user_id AND ma.assistant_id = u.id
            )
            OR EXISTS (
              SELECT 1 FROM public.master_assistants ma
              WHERE ma.master_id = u.id AND ma.assistant_id = p_master_user_id
            )
            OR public.assistants_share_master(u.id, p_master_user_id)
            OR u.role = 'dev'::public.user_role
            OR u.role = 'primary'::public.user_role
          )
      ) AS s
    ),
    ARRAY[]::uuid[]
  );
$$;


ALTER FUNCTION "public"."estimate_accept_notify_filter_eligible_user_ids"("p_master_user_id" "uuid", "p_candidate_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "estimate_accept_notify_filter_eligible_user_ids"("p_master_user_id" "uuid", "p_candidate_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."estimate_accept_notify_filter_eligible_user_ids"("p_master_user_id" "uuid", "p_candidate_ids" "uuid"[]) IS 'Service role / Edge: intersect candidate user ids with org scope of estimate master_user_id; requires non-null non-empty email.';


