    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.estimate_number IS NULL THEN
    NEW.estimate_number := nextval('public.estimates_estimate_number_seq');
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."estimates_assign_estimate_number"() OWNER TO "postgres";

--
-- Name: estimates_audit_customer_accepted_row(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimates_audit_customer_accepted_row"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE'
     AND OLD.status IS DISTINCT FROM NEW.status
     AND OLD.status = 'sent'
     AND NEW.status = 'customer_accepted'
  THEN
    INSERT INTO public.estimate_customer_events (
      estimate_id,
      event_type,
      source,
      client_ip,
      user_agent,
      metadata
    )
    VALUES (
      NEW.id,
      'public_accept_submitted',
      'accept-estimate',
      NULLIF(btrim(COALESCE(NEW.acceptor_ip, '')), ''),
      NULLIF(btrim(COALESCE(NEW.acceptor_user_agent, '')), ''),
      jsonb_strip_nulls(
        jsonb_build_object(
          'had_signature',
          NEW.acceptor_signature_storage_path IS NOT NULL
          AND btrim(COALESCE(NEW.acceptor_signature_storage_path, '')) <> ''
        )
      )
    );
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."estimates_audit_customer_accepted_row"() OWNER TO "postgres";

--
-- Name: FUNCTION "estimates_audit_customer_accepted_row"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."estimates_audit_customer_accepted_row"() IS 'Appends estimate_customer_events on sent -> customer_accepted; aligns with accept-estimate Edge.';


