--
-- Name: estimates_thread_note_stats("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimates_thread_note_stats"("p_estimate_ids" "uuid"[]) RETURNS TABLE("estimate_id" "uuid", "note_count" bigint, "last_note_at" timestamp with time zone, "last_note_body" "text", "last_note_author_name" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH ranked AS (
    SELECT
      n.estimate_id,
      n.created_at,
      left(n.body, 400) AS body_prev,
      u.name AS author_nm,
      count(*) OVER (PARTITION BY n.estimate_id) AS note_count_val,
      row_number() OVER (PARTITION BY n.estimate_id ORDER BY n.created_at DESC) AS rn
    FROM public.estimates_thread_notes n
    LEFT JOIN public.users u ON u.id = n.author_user_id
    WHERE n.estimate_id = ANY(p_estimate_ids)
  )
  SELECT
    r.estimate_id,
    r.note_count_val::bigint AS note_count,
    r.created_at AS last_note_at,
    r.body_prev AS last_note_body,
    r.author_nm AS last_note_author_name
  FROM ranked r
  WHERE r.rn = 1;
$$;


ALTER FUNCTION "public"."estimates_thread_note_stats"("p_estimate_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "estimates_thread_note_stats"("p_estimate_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."estimates_thread_note_stats"("p_estimate_ids" "uuid"[]) IS 'Per-estimate thread aggregates for Estimates Stages: count, last note time, preview body (400 chars), author display name; estimates with ≥1 note only. Single-scan aggregation.';


--
-- Name: estimator_can_access_service_type("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimator_can_access_service_type"("p_service_type_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid()
    AND (
      u.role != 'estimator'
      OR u.estimator_service_type_ids IS NULL
      OR cardinality(u.estimator_service_type_ids) = 0
      OR p_service_type_id = ANY(u.estimator_service_type_ids)
    )
  )
$$;


ALTER FUNCTION "public"."estimator_can_access_service_type"("p_service_type_id" "uuid") OWNER TO "postgres";

--
-- Name: estimator_group_members_enforce_roles(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimator_group_members_enforce_roles"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = NEW.user_id AND u.role::text IN ('assistant', 'estimator')
  ) THEN
    RAISE EXCEPTION 'Estimator inbox group may only include users with role assistant or estimator';
  END IF;
  RETURN NEW;
END;
$$;


