--
-- Name: estimator_inbox_note_stats("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimator_inbox_note_stats"("p_request_ids" "uuid"[]) RETURNS TABLE("request_id" "uuid", "note_count" bigint, "last_note_at" timestamp with time zone)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT n.request_id,
         count(*)::bigint AS note_count,
         max(n.created_at) AS last_note_at
  FROM public.estimator_request_notes n
  WHERE n.request_id = ANY(p_request_ids)
  GROUP BY n.request_id
$$;


