-- Name: FUNCTION "estimator_inbox_note_stats"("p_request_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."estimator_inbox_note_stats"("p_request_ids" "uuid"[]) IS 'Aggregates thread notes for dashboard estimator inbox cards; empty input returns no rows.';


--
-- Name: estimator_requests_guard_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."estimator_requests_guard_update"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF OLD.from_user_id IS DISTINCT FROM NEW.from_user_id
     OR OLD.title IS DISTINCT FROM NEW.title
     OR OLD.links IS DISTINCT FROM NEW.links
     OR OLD.created_at IS DISTINCT FROM NEW.created_at
     OR OLD.job_ledger_id IS DISTINCT FROM NEW.job_ledger_id
     OR OLD.bid_id IS DISTINCT FROM NEW.bid_id
     OR OLD.reference_summary IS DISTINCT FROM NEW.reference_summary
     OR OLD.location_lat IS DISTINCT FROM NEW.location_lat
     OR OLD.location_lng IS DISTINCT FROM NEW.location_lng
  THEN
    IF NOT public.is_dev() THEN
      RAISE EXCEPTION 'Cannot modify estimator request content';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."estimator_requests_guard_update"() OWNER TO "postgres";

--
-- Name: find_possible_duplicate_mercury_transactions(integer, boolean, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."find_possible_duplicate_mercury_transactions"("p_window_days" integer DEFAULT 3, "p_manual_only" boolean DEFAULT true, "p_limit" integer DEFAULT 500) RETURNS TABLE("a_id" "uuid", "a_amount" numeric, "a_counterparty_name" "text", "a_posted_at" timestamp with time zone, "a_created_at" timestamp with time zone, "a_kind" "text", "a_mercury_account_id" "uuid", "a_source" "text", "a_raw" "jsonb", "b_id" "uuid", "b_amount" numeric, "b_counterparty_name" "text", "b_posted_at" timestamp with time zone, "b_created_at" timestamp with time zone, "b_kind" "text", "b_mercury_account_id" "uuid", "b_source" "text", "b_raw" "jsonb", "manual_involved" boolean, "days_apart" integer)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with base as (
    select
      t.id, t.amount, t.source,
      lower(btrim(coalesce(t.counterparty_name, ''))) as cpn,
      coalesce(t.posted_at, t.created_at) as ts
    from public.mercury_transactions t
    where t.kind <> 'internalTransfer'
      and t.duplicate_of_transaction_id is null
      and lower(btrim(coalesce(t.counterparty_name, ''))) <> ''
  ),
  seeds as (
    select * from base where (not p_manual_only or source = 'manual')
  ),
  cand as (
    select distinct least(s.id, t.id) as lo, greatest(s.id, t.id) as hi
    from seeds s
    join base t
      on t.amount = s.amount
     and t.cpn = s.cpn
     and t.id <> s.id
     and abs(extract(epoch from (s.ts - t.ts))) <= (greatest(p_window_days, 0) * 86400)
  )
  select
    a.id, a.amount, a.counterparty_name, a.posted_at, a.created_at, a.kind, a.mercury_account_id, a.source, a.raw,
    b.id, b.amount, b.counterparty_name, b.posted_at, b.created_at, b.kind, b.mercury_account_id, b.source, b.raw,
    (a.source = 'manual' or b.source = 'manual') as manual_involved,
    (abs(extract(epoch from (coalesce(a.posted_at, a.created_at) - coalesce(b.posted_at, b.created_at)))) / 86400)::int as days_apart
  from cand c
  join public.mercury_transactions a on a.id = c.lo
  join public.mercury_transactions b on b.id = c.hi
  where not exists (
      select 1 from public.mercury_transaction_duplicate_dismissals d
      where d.id_lo = c.lo and d.id_hi = c.hi
    )
  order by manual_involved desc, coalesce(a.posted_at, a.created_at) desc, a.id
  limit greatest(p_limit, 0);
$$;


ALTER FUNCTION "public"."find_possible_duplicate_mercury_transactions"("p_window_days" integer, "p_manual_only" boolean, "p_limit" integer) OWNER TO "postgres";

--
-- Name: get_archived_user_names(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_archived_user_names"() RETURNS SETOF "text"
