CREATE TABLE IF NOT EXISTS "public"."project_workflow_steps" (
    "id" "uuid" DEFAULT "extensions"."uuid_generate_v4"() NOT NULL,
    "workflow_id" "uuid" NOT NULL,
    "template_step_id" "uuid",
    "sequence_order" integer NOT NULL,
    "name" "text" NOT NULL,
    "step_type" "public"."step_type",
    "assigned_to_name" "text",
    "assigned_skill" "text",
    "inspector_name" "text",
    "scheduled_start_date" "date",
    "scheduled_end_date" "date",
    "status" "public"."step_status" DEFAULT 'pending'::"public"."step_status" NOT NULL,
    "inspection_notes" "text",
    "rejection_reason" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "started_at" timestamp with time zone,
    "ended_at" timestamp with time zone,
    "notify_assigned_when_started" boolean DEFAULT false,
    "notify_assigned_when_complete" boolean DEFAULT false,
    "notify_assigned_when_reopened" boolean DEFAULT false,
    "notes" "text",
    "approved_by" "text",
    "approved_at" timestamp with time zone,
