--
-- Name: get_collect_payment_certify_payload("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_collect_payment_certify_payload"("p_job_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
  v_fixtures jsonb;
  v_invoice jsonb;
  v_flow jsonb;
  v_collect_invoice jsonb;
  v_billing_customer jsonb;
  v_job_service_type_id uuid;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('error', 'not_authenticated');
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = v_uid;
  IF v_role IS NULL OR v_role NOT IN ('subcontractor', 'helpers') THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger_team_members jtm
    INNER JOIN public.jobs_ledger jl ON jl.id = jtm.job_id
    WHERE jtm.user_id = v_uid
      AND jl.id = p_job_id
      AND jl.status = 'ready_to_bill'
  ) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  SELECT b.service_type_id INTO v_job_service_type_id
  FROM public.jobs_ledger jl
  LEFT JOIN public.bids b ON b.id = jl.bid_id
  WHERE jl.id = p_job_id;

  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'id', sf.id,
        'name', sf.name,
        'count', sf.count,
        'line_unit_price', sf.line_unit_price,
        'line_description', sf.line_description,
        'sequence_order', sf.sequence_order
      )
      ORDER BY sf.sequence_order
    ),
    '[]'::jsonb
  )
  INTO v_fixtures
  FROM public.jobs_ledger_fixtures sf
  WHERE sf.job_id = p_job_id;

  SELECT jsonb_build_object(
    'id', i.id,
    'amount', i.amount,
    'status', i.status,
    'sequence_order', i.sequence_order,
    'estimated_bill_date', i.estimated_bill_date
  )
  INTO v_invoice
  FROM public.jobs_ledger_invoices i
  WHERE i.job_id = p_job_id
    AND i.status = 'ready_to_bill'
  ORDER BY i.created_at DESC NULLS LAST
  LIMIT 1;

  SELECT to_jsonb(f.*)
  INTO v_flow
  FROM public.job_collect_payment_flows f
  WHERE f.job_id = p_job_id;

  SELECT jsonb_build_object(
    'id', i.id,
    'amount', i.amount,
    'status', i.status,
    'hosted_invoice_url', i.hosted_invoice_url,
    'stripe_invoice_id', i.stripe_invoice_id,
    'sent_to_customer_at', i.sent_to_customer_at
  )
  INTO v_collect_invoice
  FROM public.jobs_ledger_invoices i
  INNER JOIN public.job_collect_payment_flows f2
    ON f2.jobs_ledger_invoice_id = i.id
   AND f2.job_id = p_job_id
  LIMIT 1;

  SELECT jsonb_build_object(
    'email', NULLIF(trim(COALESCE(jl.customer_email, '')), ''),
    'name', NULLIF(trim(COALESCE(jl.customer_name, '')), '')
  )
  INTO v_billing_customer
  FROM public.jobs_ledger jl
  WHERE jl.id = p_job_id;

  RETURN jsonb_build_object(
    'fixtures', COALESCE(v_fixtures, '[]'::jsonb),
    'invoice', v_invoice,
    'flow', v_flow,
    'collect_invoice', v_collect_invoice,
    'billing_customer', COALESCE(
      v_billing_customer,
      jsonb_build_object('email', NULL, 'name', NULL)
    ),
    'job_service_type_id', v_job_service_type_id
  );
END;
$$;


ALTER FUNCTION "public"."get_collect_payment_certify_payload"("p_job_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "get_collect_payment_certify_payload"("p_job_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."get_collect_payment_certify_payload"("p_job_id" "uuid") IS 'Helpers/subcontractor: billable fixtures + RTB invoice + flow + collect_invoice + billing_customer + job_service_type_id.';


--
-- Name: get_invoice_allocation_lines_for_jobs("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_invoice_allocation_lines_for_jobs"("p_job_ids" "uuid"[]) RETURNS TABLE("job_id" "uuid", "invoice_id" "uuid", "allocated_amount" numeric, "invoice_number" "text", "invoice_date" "date", "invoice_total_amount" numeric, "supply_house_name" "text", "website_url" "text", "invoice_link" "text", "pct" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH visible_jobs AS (
    SELECT jl.id
    FROM public.jobs_ledger jl
    WHERE jl.id = ANY(p_job_ids)
    AND (
      EXISTS (
        SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant')
        AND (
          jl.master_user_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = jl.master_user_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = jl.master_user_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), jl.master_user_id)
        )
      )
      OR (
        EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
        AND EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = jl.master_user_id AND primary_id = auth.uid())
      )
      OR (
        public.auth_uid_is_helpers_or_subcontractor()
        AND EXISTS (SELECT 1 FROM public.jobs_ledger_team_members jtm WHERE jtm.job_id = jl.id AND jtm.user_id = auth.uid())
      )
    )
  )
  SELECT
    a.job_id,
    a.invoice_id,
    (i.amount * a.pct / 100)::numeric AS allocated_amount,
    i.invoice_number::text,
    i.invoice_date::date AS invoice_date,
    i.amount::numeric AS invoice_total_amount,
    COALESCE(sh.name, '')::text AS supply_house_name,
    sh.website_url::text AS website_url,
    i.link::text AS invoice_link,
    a.pct
  FROM public.supply_house_invoice_job_allocations a
  INNER JOIN public.supply_house_invoices i ON i.id = a.invoice_id
  INNER JOIN public.supply_houses sh ON sh.id = i.supply_house_id
  INNER JOIN visible_jobs v ON v.id = a.job_id
  ORDER BY a.job_id, i.invoice_date DESC NULLS LAST, i.invoice_number;
$$;


ALTER FUNCTION "public"."get_invoice_allocation_lines_for_jobs"("p_job_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "get_invoice_allocation_lines_for_jobs"("p_job_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."get_invoice_allocation_lines_for_jobs"("p_job_ids" "uuid"[]) IS 'Per-invoice lines allocated to jobs for Job Summary Parts Cost. Includes supply_houses.website_url and supply_house_invoices.link (document URL). Visibility matches helpers/subcontractors on team and get_invoice_amounts_for_jobs.';


--
-- Name: get_invoice_amounts_for_jobs("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_invoice_amounts_for_jobs"("p_job_ids" "uuid"[]) RETURNS TABLE("job_id" "uuid", "invoice_amount" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH visible_jobs AS (
    SELECT jl.id
    FROM public.jobs_ledger jl
    WHERE jl.id = ANY(p_job_ids)
    AND (
      EXISTS (
        SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant')
        AND (
          jl.master_user_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = jl.master_user_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = jl.master_user_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), jl.master_user_id)
        )
      )
      OR (
        EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
        AND EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = jl.master_user_id AND primary_id = auth.uid())
      )
      OR (
        public.auth_uid_is_helpers_or_subcontractor()
        AND EXISTS (SELECT 1 FROM public.jobs_ledger_team_members jtm WHERE jtm.job_id = jl.id AND jtm.user_id = auth.uid())
      )
    )
  )
  SELECT
    a.job_id,
    COALESCE(SUM(i.amount * a.pct / 100), 0)::numeric AS invoice_amount
  FROM public.supply_house_invoice_job_allocations a
  INNER JOIN public.supply_house_invoices i ON i.id = a.invoice_id
  INNER JOIN visible_jobs v ON v.id = a.job_id
  GROUP BY a.job_id;
$$;


ALTER FUNCTION "public"."get_invoice_amounts_for_jobs"("p_job_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "get_invoice_amounts_for_jobs"("p_job_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."get_invoice_amounts_for_jobs"("p_job_ids" "uuid"[]) IS 'Returns allocated invoice amount per job for Jobs Parts tab. Visibility matches list_tally_parts_with_po.';


