--
-- Name: get_supply_house_price_counts(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_supply_house_price_counts"() RETURNS TABLE("supply_house_id" "uuid", "supply_house_name" "text", "price_count" bigint)
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    sh.id as supply_house_id,
    sh.name as supply_house_name,
    COALESCE(COUNT(mpp.id), 0) as price_count
  FROM supply_houses sh
  LEFT JOIN material_part_prices mpp ON mpp.supply_house_id = sh.id
  GROUP BY sh.id, sh.name
  ORDER BY price_count DESC, sh.name;
END;
$$;


ALTER FUNCTION "public"."get_supply_house_price_counts"() OWNER TO "postgres";

--
-- Name: get_supply_house_stats_by_service_type(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_supply_house_stats_by_service_type"() RETURNS TABLE("service_type_id" "uuid", "service_type_name" "text", "total_parts" bigint, "parts_with_prices" bigint, "parts_with_multiple_prices" bigint, "supply_house_id" "uuid", "supply_house_name" "text", "price_count" bigint)
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
  RETURN QUERY
  WITH service_type_stats AS (
    SELECT 
      mp.service_type_id,
      COUNT(DISTINCT mp.id) as total_parts,
      COUNT(DISTINCT CASE WHEN EXISTS(
        SELECT 1 FROM material_part_prices mpp WHERE mpp.part_id = mp.id
      ) THEN mp.id END) as parts_with_prices,
      COUNT(DISTINCT CASE WHEN (
        SELECT COUNT(*) FROM material_part_prices mpp WHERE mpp.part_id = mp.id
      ) >= 2 THEN mp.id END) as parts_with_multiple_prices
    FROM material_parts mp
    GROUP BY mp.service_type_id
  ),
  supply_house_prices_per_service AS (
    SELECT
      mp.service_type_id,
      mpp.supply_house_id,
      COUNT(mpp.id) as price_count
    FROM material_parts mp
    INNER JOIN material_part_prices mpp ON mpp.part_id = mp.id
    GROUP BY mp.service_type_id, mpp.supply_house_id
  )
  SELECT 
    st.id as service_type_id,
    st.name as service_type_name,
    COALESCE(sts.total_parts, 0) as total_parts,
    COALESCE(sts.parts_with_prices, 0) as parts_with_prices,
    COALESCE(sts.parts_with_multiple_prices, 0) as parts_with_multiple_prices,
    sh.id as supply_house_id,
    sh.name as supply_house_name,
    COALESCE(shp.price_count, 0) as price_count
  FROM service_types st
  CROSS JOIN supply_houses sh
  LEFT JOIN service_type_stats sts ON sts.service_type_id = st.id
  LEFT JOIN supply_house_prices_per_service shp 
    ON shp.service_type_id = st.id 
    AND shp.supply_house_id = sh.id
  ORDER BY st.sequence_order, sh.name;
END;
$$;


ALTER FUNCTION "public"."get_supply_house_stats_by_service_type"() OWNER TO "postgres";

--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  r public.user_role;
BEGIN
  IF (NEW.raw_user_meta_data->>'invited_role') IN ('owner','master','assistant','subcontractor') THEN
    r := (NEW.raw_user_meta_data->>'invited_role')::public.user_role;
  ELSE
    r := 'master'::public.user_role;
  END IF;
  INSERT INTO public.users (id, email, name, role)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'name', NEW.email),
    r
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";

--
-- Name: insert_accounting_label_suggestion_service("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."insert_accounting_label_suggestion_service"("p_rows" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_inserted integer;
BEGIN
  IF p_rows IS NULL OR jsonb_typeof(p_rows) IS DISTINCT FROM 'array' THEN
    RAISE EXCEPTION 'p_rows must be a JSON array';
  END IF;

  INSERT INTO public.mercury_accounting_label_suggestions (
    mercury_transaction_id,
    rule_id,
    suggested_label_id,
    status
  )
  SELECT
    (elem->>'mercury_transaction_id')::uuid,
    (elem->>'rule_id')::uuid,
    (elem->>'suggested_label_id')::uuid,
    'pending'::text
  FROM jsonb_array_elements(p_rows) AS t(elem)
  WHERE (elem->>'mercury_transaction_id') IS NOT NULL
    AND (elem->>'rule_id') IS NOT NULL
    AND (elem->>'suggested_label_id') IS NOT NULL
  ON CONFLICT (mercury_transaction_id) WHERE (status = 'pending') DO NOTHING;

  GET DIAGNOSTICS v_inserted = ROW_COUNT;
  RETURN v_inserted;
END;
$$;


ALTER FUNCTION "public"."insert_accounting_label_suggestion_service"("p_rows" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "insert_accounting_label_suggestion_service"("p_rows" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."insert_accounting_label_suggestion_service"("p_rows" "jsonb") IS 'service_role only: insert pending accounting label suggestions from Edge (mercury-webhook). No auth.uid() check; skips conflicts via the one-pending-per-tx unique index.';


--
-- Name: insert_material_po_generator_entry("uuid", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."insert_material_po_generator_entry"("p_job_ledger_id" "uuid", "p_for_user_id" "uuid", "p_supply_house_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("out_id" "uuid", "out_po_code" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_attempt int;
  v_code int;
  v_new_id uuid;
  v_inserted_code int;
BEGIN
  IF auth.uid () IS NULL THEN
    RAISE EXCEPTION 'not authenticated';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.users u
    WHERE u.id = auth.uid ()
      AND u.role IN ('dev', 'master_technician', 'assistant')
  ) THEN
    RAISE EXCEPTION 'not allowed';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger jl
    WHERE jl.id = p_job_ledger_id
      AND (
        jl.master_user_id = auth.uid ()
        OR public.is_dev ()
        OR EXISTS (
          SELECT 1
          FROM public.master_assistants ma
          WHERE ma.master_id = auth.uid ()
            AND ma.assistant_id = jl.master_user_id
        )
        OR EXISTS (
          SELECT 1
          FROM public.master_assistants ma
          WHERE ma.master_id = jl.master_user_id
            AND ma.assistant_id = auth.uid ()
        )
        OR public.assistants_share_master (auth.uid (), jl.master_user_id)
      )
  ) THEN
    RAISE EXCEPTION 'job not accessible';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.users WHERE id = p_for_user_id) THEN
    RAISE EXCEPTION 'user not found';
  END IF;

  IF p_supply_house_id IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM public.supply_houses WHERE id = p_supply_house_id) THEN
    RAISE EXCEPTION 'supply house not found';
  END IF;

  FOR v_attempt IN 1..50 LOOP
    v_code := 10000 + floor(random() * 90000)::integer;
    BEGIN
      INSERT INTO public.material_po_generator_entries (
        po_code,
        job_ledger_id,
        for_user_id,
        supply_house_id,
        notes,
        created_by
      )
      VALUES (
        v_code,
        p_job_ledger_id,
        p_for_user_id,
        p_supply_house_id,
        NULLIF (trim(p_notes), ''),
        auth.uid ()
      )
      RETURNING
        material_po_generator_entries.id,
        material_po_generator_entries.po_code
        INTO v_new_id,
        v_inserted_code;

      RETURN QUERY
      SELECT
        v_new_id,
        v_inserted_code;

      RETURN;
    EXCEPTION
      WHEN unique_violation THEN
        NULL;
    END;
  END LOOP;

  RAISE EXCEPTION 'could not allocate unique PO code';
END;
$$;


ALTER FUNCTION "public"."insert_material_po_generator_entry"("p_job_ledger_id" "uuid", "p_for_user_id" "uuid", "p_supply_house_id" "uuid", "p_notes" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "insert_material_po_generator_entry"("p_job_ledger_id" "uuid", "p_for_user_id" "uuid", "p_supply_house_id" "uuid", "p_notes" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."insert_material_po_generator_entry"("p_job_ledger_id" "uuid", "p_for_user_id" "uuid", "p_supply_house_id" "uuid", "p_notes" "text") IS 'Materials PO Generator: inserts one ledger row with a unique random 5-digit po_code; optional supply_house_id; enforces job access for dev/master/assistant.';


--
-- Name: insert_report("uuid", "jsonb", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  IF NOT public.is_estimator() THEN
    RAISE EXCEPTION 'Only estimators can use insert_report';
  END IF;
  IF (p_job_ledger_id IS NOT NULL AND p_project_id IS NOT NULL)
     OR (p_job_ledger_id IS NULL AND p_project_id IS NULL) THEN
    RAISE EXCEPTION 'Exactly one of job_ledger_id or project_id must be set';
  END IF;

  INSERT INTO public.reports (template_id, created_by_user_id, field_values, job_ledger_id, project_id)
  VALUES (p_template_id, auth.uid(), COALESCE(p_field_values, '{}'::jsonb), p_job_ledger_id, p_project_id)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid") IS 'Inserts a report. SECURITY DEFINER bypasses RLS. Only estimators. Used when direct insert fails.';


--
-- Name: insert_report("uuid", "jsonb", "uuid", "uuid", numeric, numeric, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid", "p_reported_at_lat" numeric DEFAULT NULL::numeric, "p_reported_at_lng" numeric DEFAULT NULL::numeric, "p_bid_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
  n int;
BEGIN
  IF NOT public.is_estimator() THEN
    RAISE EXCEPTION 'Only estimators can use insert_report';
  END IF;
  n := 0;
  IF p_job_ledger_id IS NOT NULL THEN n := n + 1; END IF;
  IF p_project_id IS NOT NULL THEN n := n + 1; END IF;
  IF p_bid_id IS NOT NULL THEN n := n + 1; END IF;
  IF n <> 1 THEN
    RAISE EXCEPTION 'Exactly one of job_ledger_id, project_id, or bid_id must be set';
  END IF;

  INSERT INTO public.reports (
    template_id, created_by_user_id, field_values,
    job_ledger_id, project_id, bid_id,
    reported_at_lat, reported_at_lng
  )
  VALUES (
    p_template_id,
    auth.uid(),
    COALESCE(p_field_values, '{}'::jsonb),
    p_job_ledger_id,
    p_project_id,
    p_bid_id,
    p_reported_at_lat,
    p_reported_at_lng
  )
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid", "p_reported_at_lat" numeric, "p_reported_at_lng" numeric, "p_bid_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid", "p_reported_at_lat" numeric, "p_reported_at_lng" numeric, "p_bid_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
