COMMENT ON FUNCTION "public"."insert_report"("p_template_id" "uuid", "p_field_values" "jsonb", "p_job_ledger_id" "uuid", "p_project_id" "uuid", "p_reported_at_lat" numeric, "p_reported_at_lng" numeric, "p_bid_id" "uuid") IS 'Inserts a report. SECURITY DEFINER. Only estimators. Exactly one of job, project, or bid.';


