--
-- Name: jobs_ledger_invoices_billed_at_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."jobs_ledger_invoices_billed_at_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.status = 'billed' THEN
      NEW.billed_at := COALESCE(NEW.billed_at, now());
    ELSE
      NEW.billed_at := NULL;
    END IF;
  ELSIF TG_OP = 'UPDATE' THEN
    IF NEW.status = 'billed' AND OLD.status IS DISTINCT FROM 'billed' THEN
      NEW.billed_at := COALESCE(NEW.billed_at, now());
    ELSIF NEW.status <> 'billed' THEN
      NEW.billed_at := NULL;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."jobs_ledger_invoices_billed_at_fn"() OWNER TO "postgres";

--
-- Name: jobs_ledger_project_master_match_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."jobs_ledger_project_master_match_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.project_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.projects p
      WHERE p.id = NEW.project_id AND p.master_user_id = NEW.master_user_id
    ) THEN
      RAISE EXCEPTION 'Job master_user_id must match project owner when project_id is set';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


