--
-- Name: jobs_ledger_row_visible_for_tally_assign("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."jobs_ledger_row_visible_for_tally_assign"("p_job_id" "uuid", "p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    SET "row_security" TO 'off'
    AS $$
DECLARE
  v_role text;
BEGIN
  IF p_job_id IS NULL OR p_user_id IS NULL THEN
    RETURN false;
  END IF;

  SELECT u.role::text INTO v_role FROM public.users u WHERE u.id = p_user_id;
  IF v_role IS NULL THEN
    RETURN false;
  END IF;

  IF v_role IN ('subcontractor', 'helpers') THEN
    RETURN EXISTS (
      SELECT 1 FROM public.jobs_ledger_team_members jtm
      WHERE jtm.job_id = p_job_id AND jtm.user_id = p_user_id
    );
  END IF;

  IF v_role NOT IN ('dev', 'master_technician', 'assistant', 'primary') THEN
    RETURN false;
  END IF;

  RETURN EXISTS (
    SELECT 1
    FROM public.jobs_ledger jl
    WHERE jl.id = p_job_id
      AND (
        jl.master_user_id = p_user_id
        OR v_role = 'dev'
        OR v_role = 'primary'
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = p_user_id AND assistant_id = jl.master_user_id
        )
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = jl.master_user_id AND assistant_id = p_user_id
        )
        OR public.assistants_share_master(p_user_id, jl.master_user_id)
      )
  )
  OR EXISTS (
    SELECT 1
    FROM public.clock_sessions cs
    WHERE cs.job_ledger_id = p_job_id
      AND public.is_team_lead_for_member(p_user_id, cs.user_id)
  );
END;
$$;


ALTER FUNCTION "public"."jobs_ledger_row_visible_for_tally_assign"("p_job_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "jobs_ledger_row_visible_for_tally_assign"("p_job_id" "uuid", "p_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."jobs_ledger_row_visible_for_tally_assign"("p_job_id" "uuid", "p_user_id" "uuid") IS 'Whether p_user_id may read this jobs_ledger row for tally Mercury assign search (helpers/subcontractors: team-only; row_security off).';


--
-- Name: jobs_ledger_thread_note_stats("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."jobs_ledger_thread_note_stats"("p_job_ids" "uuid"[]) RETURNS TABLE("job_id" "uuid", "note_count" bigint, "last_note_at" timestamp with time zone, "last_note_body" "text", "last_note_author_name" "text", "report_count" bigint, "last_report_at" timestamp with time zone, "last_report_author_name" "text", "last_report_template_name" "text", "last_report_preview" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $_$
  WITH ranked AS (
    SELECT
      n.job_id,
      n.created_at,
      left(n.body, 400) AS body_prev,
      u.name AS author_nm,
      count(*) OVER (PARTITION BY n.job_id) AS note_count_val,
      row_number() OVER (PARTITION BY n.job_id ORDER BY n.created_at DESC) AS rn
    FROM public.jobs_ledger_thread_notes n
    LEFT JOIN public.users u ON u.id = n.author_user_id
    WHERE p_job_ids IS NOT NULL
      AND n.job_id = ANY (p_job_ids)
  ),
  note_one AS (
    SELECT
      r.job_id,
      r.note_count_val::bigint AS note_count,
      r.created_at AS last_note_at,
      r.body_prev AS last_note_body,
      r.author_nm AS last_note_author_name
    FROM ranked r
    WHERE r.rn = 1
  ),
  rep_counts AS (
    SELECT r.job_ledger_id AS job_id, count(*)::bigint AS cnt
    FROM public.reports r
    WHERE p_job_ids IS NOT NULL
      AND r.job_ledger_id = ANY (p_job_ids)
    GROUP BY r.job_ledger_id
  ),
  rep_latest AS (
    SELECT DISTINCT ON (r.job_ledger_id)
      r.job_ledger_id AS job_id,
      r.created_at AS last_report_at,
      u.name AS last_report_author_name,
      rt.name AS last_report_template_name,
      (
        WITH
        has_new_completion_key AS (
          SELECT EXISTS(
            SELECT 1
            FROM jsonb_each_text(COALESCE(r.field_values, '{}'::jsonb)) AS e(key, val)
            WHERE e.key = 'How complete is the job?'
          ) AS v
        ),
        pairs AS (
          SELECT
            t.key,
            btrim(t.val) AS bval
          FROM jsonb_each_text(COALESCE(r.field_values, '{}'::jsonb)) AS t(key, val)
          WHERE t.val IS NOT NULL
            AND btrim(t.val) <> ''
        )
        SELECT (
          SELECT left(z.d, 200)
          FROM (
            SELECT
              CASE
                WHEN p.key = 'Who was on the job?'
                  AND (SELECT h.v FROM has_new_completion_key h)
                  THEN NULL::text
                WHEN
                  p.key IN ('How complete is the job?', 'Who was on the job?')
                  AND p.bval ~ '^[0-9]{1,3}$'
                  AND (p.bval::int) >= 0
                  AND (p.bval::int) <= 100
                  THEN
                    'I think the job is ' || p.bval::int::text || '% complete'
                ELSE left(p.bval, 200)
              END AS d
            FROM pairs p
          ) z
          WHERE z.d IS NOT NULL
          LIMIT 1
        )
      ) AS last_report_preview
    FROM public.reports r
    JOIN public.users u ON u.id = r.created_by_user_id
    JOIN public.report_templates rt ON rt.id = r.template_id
    WHERE p_job_ids IS NOT NULL
      AND r.job_ledger_id = ANY (p_job_ids)
    ORDER BY r.job_ledger_id, r.created_at DESC
  ),
  eligible AS (
    SELECT n.job_id FROM note_one n
    UNION
    SELECT rc.job_id FROM rep_counts rc
  )
  SELECT
    e.job_id,
    coalesce(n.note_count, 0::bigint) AS note_count,
    n.last_note_at,
    n.last_note_body,
    n.last_note_author_name,
    coalesce(rc.cnt, 0::bigint) AS report_count,
    l.last_report_at,
    l.last_report_author_name,
    l.last_report_template_name,
    l.last_report_preview
  FROM eligible e
  LEFT JOIN note_one n ON n.job_id = e.job_id
  LEFT JOIN rep_counts rc ON rc.job_id = e.job_id
  LEFT JOIN rep_latest l ON l.job_id = e.job_id;
$_$;


ALTER FUNCTION "public"."jobs_ledger_thread_note_stats"("p_job_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "jobs_ledger_thread_note_stats"("p_job_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."jobs_ledger_thread_note_stats"("p_job_ids" "uuid"[]) IS 'Per-job Stages activity: note_count + last note fields; report_count + last report (template, author, field preview) for RLS-visible reports. One row per job with ≥1 note or ≥1 report.';


--
-- Name: leader_replace_clock_session_cluster_mixed("uuid"[], "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."leader_replace_clock_session_cluster_mixed"("p_session_ids" "uuid"[], "p_segments" "jsonb") RETURNS TABLE("inserted_ids" "uuid"[], "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_tz text := 'America/Chicago';
  v_today date;
  v_week_start date;
  v_week_end date;
  v_prev_week_start date;
  v_prev_week_end date;
  v_cnt int;
  v_first public.clock_sessions%ROWTYPE;
  v_last public.clock_sessions%ROWTYPE;
  v_prev public.clock_sessions%ROWTYPE;
  v_rec public.clock_sessions%ROWTYPE;
  v_first_iter boolean := true;
  v_gap_ok boolean;
  v_n int;
  v_i int;
  v_elem jsonb;
  v_in timestamptz;
  v_out timestamptz;
  v_out_null boolean;
  v_notes text;
  v_person_name text;
  v_hours numeric;
  v_new_hours numeric;
  v_eps double precision := 1.0;
  v_min_h numeric := 0.01;
  v_prev_out timestamptz;
  v_is_open_block boolean;
  v_ids uuid[] := ARRAY[]::uuid[];
  v_new_id uuid;
  v_work date;
  v_seg_job uuid;
  v_seg_bid uuid;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Not authenticated'::text;
    RETURN;
  END IF;

  IF p_session_ids IS NULL OR array_length(p_session_ids, 1) IS NULL OR array_length(p_session_ids, 1) < 1 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least one session id'::text;
    RETURN;
  END IF;

  IF jsonb_typeof(p_segments) <> 'array' OR jsonb_array_length(p_segments) < 1 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least one segment'::text;
    RETURN;
  END IF;

  SELECT count(DISTINCT x)::int INTO v_cnt FROM unnest(p_session_ids) AS x;
  IF v_cnt <> array_length(p_session_ids, 1) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Duplicate session ids'::text;
    RETURN;
  END IF;

  SELECT count(*)::int INTO v_cnt FROM public.clock_sessions WHERE id = ANY (p_session_ids);
  IF v_cnt <> array_length(p_session_ids, 1) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'One or more sessions not found'::text;
    RETURN;
  END IF;

  v_today := (now() AT TIME ZONE v_tz)::date;
  v_week_start := v_today - EXTRACT(DOW FROM v_today)::integer;
  v_week_end := v_week_start + 6;
  v_prev_week_start := v_week_start - 7;
  v_prev_week_end := v_week_end - 7;

  v_prev := NULL;
  FOR v_rec IN
    SELECT * FROM public.clock_sessions
    WHERE id = ANY (p_session_ids)
    ORDER BY clocked_in_at ASC
    FOR UPDATE
  LOOP
    IF NOT public.can_edit_clock_sessions_for_user(v_rec.user_id) THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Access denied'::text;
      RETURN;
    END IF;
    IF v_rec.rejected_at IS NOT NULL THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Rejected sessions cannot be split'::text;
      RETURN;
    END IF;
    IF v_rec.revoked_at IS NOT NULL THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Revoked sessions cannot be split'::text;
      RETURN;
    END IF;

    IF NOT (
      (v_rec.work_date >= v_week_start AND v_rec.work_date <= v_week_end)
      OR (v_rec.work_date >= v_prev_week_start AND v_rec.work_date <= v_prev_week_end)
    ) THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Session is outside the editable this or last week (America/Chicago)'::text;
      RETURN;
    END IF;

    IF v_first_iter THEN
      v_first := v_rec;
      v_first_iter := false;
    ELSE
      IF v_prev.user_id IS DISTINCT FROM v_rec.user_id THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Cluster sessions must belong to the same user'::text;
        RETURN;
      END IF;
      IF v_prev.clocked_out_at IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final session in a cluster may be open'::text;
        RETURN;
      END IF;
      v_gap_ok := v_rec.clocked_in_at <= v_prev.clocked_out_at + interval '1 second';
      IF NOT v_gap_ok THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Sessions in cluster must be contiguous'::text;
        RETURN;
      END IF;
    END IF;
    v_prev := v_rec;
    v_last := v_rec;
  END LOOP;

  IF EXISTS (
    SELECT 1 FROM public.clock_sessions cs
    WHERE cs.id = ANY (p_session_ids)
      AND (cs.origin IS DISTINCT FROM v_first.origin
           OR cs.salary_segment_index IS DISTINCT FROM v_first.salary_segment_index)
  ) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Cluster sessions must share the same origin and salary segment index'::text;
    RETURN;
  END IF;

  v_is_open_block := v_last.clocked_out_at IS NULL;
  v_n := jsonb_array_length(p_segments);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    IF v_elem IS NULL OR jsonb_typeof(v_elem) <> 'object' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Invalid segment payload'::text;
      RETURN;
    END IF;

    IF v_elem->>'clocked_in_at' IS NULL OR v_elem->>'clocked_in_at' = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment needs clocked_in_at'::text;
      RETURN;
    END IF;

    v_in := (v_elem->>'clocked_in_at')::timestamptz;

    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;

    v_notes := trim(both from coalesce(v_elem->>'notes', ''));
    IF v_notes = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Notes are required for each segment'::text;
      RETURN;
    END IF;

    IF v_i = 0 THEN
      IF abs(EXTRACT(EPOCH FROM (v_in - v_first.clocked_in_at))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'First segment must start at the original clock-in time'::text;
        RETURN;
      END IF;
    ELSE
      IF v_prev_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the last segment may be open (no clock-out)'::text;
        RETURN;
      END IF;
      IF abs(EXTRACT(EPOCH FROM (v_in - v_prev_out))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Segments must be contiguous'::text;
        RETURN;
      END IF;
    END IF;

    IF NOT v_is_open_block THEN
      IF v_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'All segments must be closed for a closed block'::text;
        RETURN;
      END IF;
      IF v_in >= v_out THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment must have clock-out after clock-in'::text;
        RETURN;
      END IF;
      IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
        RETURN;
      END IF;
      IF v_out > now() THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
        RETURN;
      END IF;
      v_prev_out := v_out;
    ELSE
      IF v_i < v_n - 1 THEN
        IF v_out IS NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final segment may be open for an open block'::text;
          RETURN;
        END IF;
        IF v_in >= v_out THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each closed part must have clock-out after clock-in'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
          RETURN;
        END IF;
        IF v_out > now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
          RETURN;
        END IF;
        v_prev_out := v_out;
      ELSE
        IF v_out IS NOT NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Final segment of an open block must stay open'::text;
          RETURN;
        END IF;
        IF v_in >= now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must start before now'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (now() - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must be at least 0.01 hours so far'::text;
          RETURN;
        END IF;
        v_prev_out := NULL;
      END IF;
    END IF;
  END LOOP;

  IF NOT v_is_open_block THEN
    IF abs(EXTRACT(EPOCH FROM (v_prev_out - v_last.clocked_out_at))) > v_eps THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Last segment must end at the original clock-out time'::text;
      RETURN;
    END IF;
  END IF;

  IF v_first.origin = 'salary_schedule' AND v_n >= 2 AND v_first.salary_segment_index IS NOT NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Cannot split a single salary segment into multiple clock rows; merge or replace the full day''s salary sessions instead.'::text;
    RETURN;
  END IF;

  FOR v_rec IN
    SELECT * FROM public.clock_sessions
    WHERE id = ANY (p_session_ids)
    ORDER BY clocked_in_at ASC
  LOOP
    IF v_rec.approved_at IS NOT NULL AND v_rec.clocked_out_at IS NOT NULL THEN
      SELECT trim(both from u.name) INTO v_person_name
      FROM public.users u
      WHERE u.id = v_rec.user_id;

      IF v_person_name IS NULL OR v_person_name = '' THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'User has no name'::text;
        RETURN;
      END IF;

      v_hours := EXTRACT(EPOCH FROM (v_rec.clocked_out_at - v_rec.clocked_in_at)) / 3600.0;
      IF v_hours > 0 THEN
        UPDATE public.people_hours
        SET hours = hours - v_hours,
            entered_by = v_uid
        WHERE person_name = v_person_name
          AND work_date = v_rec.work_date
        RETURNING hours INTO v_new_hours;

        IF FOUND THEN
          IF v_new_hours <= 0 THEN
            DELETE FROM public.people_hours
            WHERE person_name = v_person_name
              AND work_date = v_rec.work_date;
          END IF;
        END IF;
      END IF;

      IF v_rec.job_ledger_id IS NOT NULL THEN
        PERFORM public.sync_crew_jobs_from_clock(v_person_name, v_rec.work_date);
      END IF;
      IF v_rec.bid_id IS NOT NULL THEN
        PERFORM public.sync_crew_bids_from_clock(v_person_name, v_rec.work_date);
      END IF;
    END IF;
  END LOOP;

  DELETE FROM public.clock_sessions WHERE id = ANY (p_session_ids);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    v_in := (v_elem->>'clocked_in_at')::timestamptz;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;
    v_notes := trim(both from coalesce(v_elem->>'notes', ''));

    v_seg_job := NULL;
    v_seg_bid := NULL;
    IF v_elem ? 'job_ledger_id' AND v_elem->>'job_ledger_id' IS NOT NULL AND btrim(v_elem->>'job_ledger_id') <> '' THEN
      v_seg_job := (v_elem->>'job_ledger_id')::uuid;
    END IF;
    IF v_elem ? 'bid_id' AND v_elem->>'bid_id' IS NOT NULL AND btrim(v_elem->>'bid_id') <> '' THEN
      v_seg_bid := (v_elem->>'bid_id')::uuid;
    END IF;

    v_work := (v_in AT TIME ZONE v_tz)::date;

    INSERT INTO public.clock_sessions (
      user_id,
      clocked_in_at,
      clocked_out_at,
      work_date,
      notes,
      job_ledger_id,
      bid_id,
      origin,
      salary_segment_index,
      clock_in_lat,
      clock_in_lng,
      clock_out_lat,
      clock_out_lng
    )
    VALUES (
      v_first.user_id,
      v_in,
      v_out,
      v_work,
      v_notes,
      v_seg_job,
      v_seg_bid,
      v_first.origin,
      CASE
        WHEN v_first.origin = 'salary_schedule' AND v_n >= 2 AND v_first.salary_segment_index IS NULL
          THEN (v_i + 1)::smallint
        ELSE v_first.salary_segment_index
      END,
      NULL,
      NULL,
      NULL,
      NULL
    )
    RETURNING id INTO v_new_id;

    v_ids := array_append(v_ids, v_new_id);
  END LOOP;

  UPDATE public.clock_sessions
  SET clock_in_lat = v_first.clock_in_lat,
      clock_in_lng = v_first.clock_in_lng
  WHERE id = v_ids[1];

  FOR v_i IN REVERSE (v_n - 1) .. 0 LOOP
    v_elem := p_segments -> v_i;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      UPDATE public.clock_sessions
      SET clock_out_lat = v_last.clock_out_lat,
          clock_out_lng = v_last.clock_out_lng
      WHERE id = v_ids[v_i + 1];
      EXIT;
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_ids, NULL::text;
END;
$$;


ALTER FUNCTION "public"."leader_replace_clock_session_cluster_mixed"("p_session_ids" "uuid"[], "p_segments" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "leader_replace_clock_session_cluster_mixed"("p_session_ids" "uuid"[], "p_segments" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."leader_replace_clock_session_cluster_mixed"("p_session_ids" "uuid"[], "p_segments" "jsonb") IS 'Like replace_own_clock_session_cluster_mixed for self, team lead, or pay access.';


--
-- Name: leader_split_clock_session_cluster("uuid"[], "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."leader_split_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb") RETURNS TABLE("inserted_ids" "uuid"[], "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_tz text := 'America/Chicago';
  v_today date;
  v_week_start date;
  v_week_end date;
  v_prev_week_start date;
  v_prev_week_end date;
  v_cnt int;
  v_first public.clock_sessions%ROWTYPE;
  v_last public.clock_sessions%ROWTYPE;
  v_prev public.clock_sessions%ROWTYPE;
  v_rec public.clock_sessions%ROWTYPE;
  v_first_iter boolean := true;
  v_gap_ok boolean;
  v_n int;
  v_i int;
  v_elem jsonb;
  v_in timestamptz;
  v_out timestamptz;
  v_out_null boolean;
  v_notes text;
  v_person_name text;
  v_hours numeric;
  v_new_hours numeric;
  v_eps double precision := 1.0;
  v_min_h numeric := 0.01;
  v_prev_out timestamptz;
  v_is_open_block boolean;
  v_ids uuid[] := ARRAY[]::uuid[];
  v_new_id uuid;
  v_work date;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Not authenticated'::text;
    RETURN;
  END IF;

  IF p_session_ids IS NULL OR array_length(p_session_ids, 1) IS NULL OR array_length(p_session_ids, 1) < 1 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least one session id'::text;
    RETURN;
  END IF;

  IF jsonb_typeof(p_segments) <> 'array' OR jsonb_array_length(p_segments) < 2 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least two segments'::text;
    RETURN;
  END IF;

  SELECT count(DISTINCT x)::int INTO v_cnt FROM unnest(p_session_ids) AS x;
  IF v_cnt <> array_length(p_session_ids, 1) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Duplicate session ids'::text;
    RETURN;
  END IF;

  SELECT count(*)::int INTO v_cnt FROM public.clock_sessions WHERE id = ANY (p_session_ids);
  IF v_cnt <> array_length(p_session_ids, 1) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'One or more sessions not found'::text;
    RETURN;
  END IF;

  v_today := (now() AT TIME ZONE v_tz)::date;
  v_week_start := v_today - EXTRACT(DOW FROM v_today)::integer;
  v_week_end := v_week_start + 6;
  v_prev_week_start := v_week_start - 7;
  v_prev_week_end := v_week_end - 7;

  v_prev := NULL;
  FOR v_rec IN
    SELECT * FROM public.clock_sessions
    WHERE id = ANY (p_session_ids)
    ORDER BY clocked_in_at ASC
    FOR UPDATE
  LOOP
    IF NOT public.can_edit_clock_sessions_for_user(v_rec.user_id) THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Access denied'::text;
      RETURN;
    END IF;
    IF v_rec.rejected_at IS NOT NULL THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Rejected sessions cannot be split'::text;
      RETURN;
    END IF;
    IF v_rec.revoked_at IS NOT NULL THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Revoked sessions cannot be split'::text;
      RETURN;
    END IF;

    IF NOT (
      (v_rec.work_date >= v_week_start AND v_rec.work_date <= v_week_end)
      OR (v_rec.work_date >= v_prev_week_start AND v_rec.work_date <= v_prev_week_end)
    ) THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Session is outside the editable this or last week (America/Chicago)'::text;
      RETURN;
    END IF;

    IF v_first_iter THEN
      v_first := v_rec;
      v_first_iter := false;
    ELSE
      IF v_prev.user_id IS DISTINCT FROM v_rec.user_id THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Cluster sessions must belong to the same user'::text;
        RETURN;
      END IF;
      IF v_prev.job_ledger_id IS NOT DISTINCT FROM v_rec.job_ledger_id
         AND v_prev.bid_id IS NOT DISTINCT FROM v_rec.bid_id THEN
        NULL;
      ELSE
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Cluster sessions must share the same job and bid'::text;
        RETURN;
      END IF;
      IF v_prev.clocked_out_at IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final session in a cluster may be open'::text;
        RETURN;
      END IF;
      v_gap_ok := v_rec.clocked_in_at <= v_prev.clocked_out_at + interval '1 second';
      IF NOT v_gap_ok THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Sessions in cluster must be contiguous'::text;
        RETURN;
      END IF;
    END IF;
    v_prev := v_rec;
    v_last := v_rec;
  END LOOP;

  v_is_open_block := v_last.clocked_out_at IS NULL;
  v_n := jsonb_array_length(p_segments);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    IF v_elem IS NULL OR jsonb_typeof(v_elem) <> 'object' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Invalid segment payload'::text;
      RETURN;
    END IF;

    IF v_elem->>'clocked_in_at' IS NULL OR v_elem->>'clocked_in_at' = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment needs clocked_in_at'::text;
      RETURN;
    END IF;

    v_in := (v_elem->>'clocked_in_at')::timestamptz;

    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;

    v_notes := trim(both from coalesce(v_elem->>'notes', ''));
    IF v_notes = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Notes are required for each segment'::text;
      RETURN;
    END IF;

    IF v_i = 0 THEN
      IF abs(EXTRACT(EPOCH FROM (v_in - v_first.clocked_in_at))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'First segment must start at the original clock-in time'::text;
        RETURN;
      END IF;
    ELSE
      IF v_prev_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the last segment may be open (no clock-out)'::text;
        RETURN;
      END IF;
      IF abs(EXTRACT(EPOCH FROM (v_in - v_prev_out))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Segments must be contiguous'::text;
        RETURN;
      END IF;
    END IF;

    IF NOT v_is_open_block THEN
      IF v_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'All segments must be closed for a closed block'::text;
        RETURN;
      END IF;
      IF v_in >= v_out THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment must have clock-out after clock-in'::text;
        RETURN;
      END IF;
      IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
        RETURN;
      END IF;
      IF v_out > now() THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
        RETURN;
      END IF;
      v_prev_out := v_out;
    ELSE
      IF v_i < v_n - 1 THEN
        IF v_out IS NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final segment may be open for an open block'::text;
          RETURN;
        END IF;
        IF v_in >= v_out THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each closed part must have clock-out after clock-in'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
          RETURN;
        END IF;
        IF v_out > now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
          RETURN;
        END IF;
        v_prev_out := v_out;
      ELSE
        IF v_out IS NOT NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Final segment of an open block must stay open'::text;
          RETURN;
        END IF;
        IF v_in >= now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must start before now'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (now() - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must be at least 0.01 hours so far'::text;
          RETURN;
        END IF;
        v_prev_out := NULL;
      END IF;
    END IF;
  END LOOP;

  IF NOT v_is_open_block THEN
    IF abs(EXTRACT(EPOCH FROM (v_prev_out - v_last.clocked_out_at))) > v_eps THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Last segment must end at the original clock-out time'::text;
      RETURN;
    END IF;
  END IF;

  FOR v_rec IN
    SELECT * FROM public.clock_sessions
    WHERE id = ANY (p_session_ids)
    ORDER BY clocked_in_at ASC
  LOOP
    IF v_rec.approved_at IS NOT NULL AND v_rec.clocked_out_at IS NOT NULL THEN
      SELECT trim(both from u.name) INTO v_person_name
      FROM public.users u
      WHERE u.id = v_rec.user_id;

      IF v_person_name IS NULL OR v_person_name = '' THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'User has no name'::text;
        RETURN;
      END IF;

      v_hours := EXTRACT(EPOCH FROM (v_rec.clocked_out_at - v_rec.clocked_in_at)) / 3600.0;
      IF v_hours > 0 THEN
        PERFORM public.people_hours_subtract_approved_hours(
          v_rec.user_id,
          v_person_name,
          v_rec.work_date,
          v_hours,
          v_uid
        );
      END IF;

      IF v_rec.job_ledger_id IS NOT NULL THEN
        PERFORM public.sync_crew_jobs_from_clock(v_person_name, v_rec.work_date);
      END IF;
      IF v_rec.bid_id IS NOT NULL THEN
        PERFORM public.sync_crew_bids_from_clock(v_person_name, v_rec.work_date);
      END IF;
    END IF;
  END LOOP;

  DELETE FROM public.clock_sessions WHERE id = ANY (p_session_ids);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    v_in := (v_elem->>'clocked_in_at')::timestamptz;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;
    v_notes := trim(both from coalesce(v_elem->>'notes', ''));

    v_work := (v_in AT TIME ZONE v_tz)::date;

    INSERT INTO public.clock_sessions (
      user_id,
      clocked_in_at,
      clocked_out_at,
      work_date,
      notes,
      job_ledger_id,
      bid_id,
      origin,
      salary_segment_index,
      clock_in_lat,
      clock_in_lng,
      clock_out_lat,
      clock_out_lng
    )
    VALUES (
      v_first.user_id,
      v_in,
      v_out,
      v_work,
      v_notes,
      v_first.job_ledger_id,
      v_first.bid_id,
      CASE
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NOT NULL THEN 'user_punch'
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NULL THEN 'salary_schedule'
        ELSE v_first.origin
      END,
      CASE
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NOT NULL THEN NULL
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NULL AND v_n >= 2 THEN (v_i + 1)::smallint
        ELSE NULL
      END,
      NULL,
      NULL,
      NULL,
      NULL
    )
    RETURNING id INTO v_new_id;

    v_ids := array_append(v_ids, v_new_id);
  END LOOP;

  UPDATE public.clock_sessions
  SET clock_in_lat = v_first.clock_in_lat,
      clock_in_lng = v_first.clock_in_lng
  WHERE id = v_ids[1];

  FOR v_i IN REVERSE (v_n - 1) .. 0 LOOP
    v_elem := p_segments -> v_i;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      UPDATE public.clock_sessions
      SET clock_out_lat = v_last.clock_out_lat,
          clock_out_lng = v_last.clock_out_lng
      WHERE id = v_ids[v_i + 1];
      EXIT;
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_ids, NULL::text;
END;
$$;


ALTER FUNCTION "public"."leader_split_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "leader_split_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."leader_split_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb") IS 'Like split_own_clock_session_cluster for self, team lead, or pay access. Indexed salary_schedule children become user_punch.';


--
-- Name: leader_split_clock_session_segments("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."leader_split_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb") RETURNS TABLE("inserted_ids" "uuid"[], "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_parent public.clock_sessions%ROWTYPE;
  v_tz text := 'America/Chicago';
  v_today date;
  v_week_start date;
  v_week_end date;
  v_prev_week_start date;
  v_prev_week_end date;
  v_n int;
  v_i int;
  v_elem jsonb;
  v_in timestamptz;
  v_out timestamptz;
  v_out_null boolean;
  v_notes text;
  v_person_name text;
  v_hours numeric;
  v_new_hours numeric;
  v_eps double precision := 1.0;
  v_min_h numeric := 0.01;
  v_prev_out timestamptz;
  v_is_open_parent boolean;
  v_ids uuid[] := ARRAY[]::uuid[];
  v_new_id uuid;
  v_work date;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Not authenticated'::text;
    RETURN;
  END IF;

  IF jsonb_typeof(p_segments) <> 'array' OR jsonb_array_length(p_segments) < 2 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least two segments'::text;
    RETURN;
  END IF;

  v_today := (now() AT TIME ZONE v_tz)::date;
  v_week_start := v_today - EXTRACT(DOW FROM v_today)::integer;
  v_week_end := v_week_start + 6;
  v_prev_week_start := v_week_start - 7;
  v_prev_week_end := v_week_end - 7;

  SELECT * INTO v_parent
  FROM public.clock_sessions
  WHERE id = p_session_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Session not found'::text;
    RETURN;
  END IF;

  IF NOT public.can_edit_clock_sessions_for_user(v_parent.user_id) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Access denied'::text;
    RETURN;
  END IF;

  IF v_parent.rejected_at IS NOT NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Rejected sessions cannot be split'::text;
    RETURN;
  END IF;

  IF v_parent.revoked_at IS NOT NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Revoked sessions cannot be split'::text;
    RETURN;
  END IF;

  IF NOT (
    (v_parent.work_date >= v_week_start AND v_parent.work_date <= v_week_end)
    OR (v_parent.work_date >= v_prev_week_start AND v_parent.work_date <= v_prev_week_end)
  ) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Session is outside the editable this or last week (America/Chicago)'::text;
    RETURN;
  END IF;

  v_is_open_parent := v_parent.clocked_out_at IS NULL;
  v_n := jsonb_array_length(p_segments);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    IF v_elem IS NULL OR jsonb_typeof(v_elem) <> 'object' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Invalid segment payload'::text;
      RETURN;
    END IF;

    IF v_elem->>'clocked_in_at' IS NULL OR v_elem->>'clocked_in_at' = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment needs clocked_in_at'::text;
      RETURN;
    END IF;

    v_in := (v_elem->>'clocked_in_at')::timestamptz;

    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;

    v_notes := trim(both from coalesce(v_elem->>'notes', ''));
    IF v_notes = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Notes are required for each segment'::text;
      RETURN;
    END IF;

    IF v_i = 0 THEN
      IF abs(EXTRACT(EPOCH FROM (v_in - v_parent.clocked_in_at))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'First segment must start at the original clock-in time'::text;
        RETURN;
      END IF;
    ELSE
      IF v_prev_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the last segment may be open (no clock-out)'::text;
        RETURN;
      END IF;
      IF abs(EXTRACT(EPOCH FROM (v_in - v_prev_out))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Segments must be contiguous'::text;
        RETURN;
      END IF;
    END IF;

    IF NOT v_is_open_parent THEN
      IF v_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'All segments must be closed for a closed session'::text;
        RETURN;
      END IF;
      IF v_in >= v_out THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment must have clock-out after clock-in'::text;
        RETURN;
      END IF;
      IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
        RETURN;
      END IF;
      IF v_out > now() THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
        RETURN;
      END IF;
      v_prev_out := v_out;
    ELSE
      IF v_i < v_n - 1 THEN
        IF v_out IS NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final segment may be open for an open session'::text;
          RETURN;
        END IF;
        IF v_in >= v_out THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each closed part must have clock-out after clock-in'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
          RETURN;
        END IF;
        IF v_out > now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
          RETURN;
        END IF;
        v_prev_out := v_out;
      ELSE
        IF v_out IS NOT NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Final segment of an open session must stay open'::text;
          RETURN;
        END IF;
        IF v_in >= now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must start before now'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (now() - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must be at least 0.01 hours so far'::text;
          RETURN;
        END IF;
        v_prev_out := NULL;
      END IF;
    END IF;
  END LOOP;

  IF NOT v_is_open_parent THEN
    IF abs(EXTRACT(EPOCH FROM (v_prev_out - v_parent.clocked_out_at))) > v_eps THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Last segment must end at the original clock-out time'::text;
      RETURN;
    END IF;
  END IF;

  IF v_parent.approved_at IS NOT NULL AND v_parent.clocked_out_at IS NOT NULL THEN
    SELECT trim(both from u.name) INTO v_person_name
    FROM public.users u
    WHERE u.id = v_parent.user_id;

    IF v_person_name IS NULL OR v_person_name = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'User has no name'::text;
      RETURN;
    END IF;

    v_hours := EXTRACT(EPOCH FROM (v_parent.clocked_out_at - v_parent.clocked_in_at)) / 3600.0;
    IF v_hours > 0 THEN
      PERFORM public.people_hours_subtract_approved_hours(
        v_parent.user_id,
        v_person_name,
        v_parent.work_date,
        v_hours,
        v_uid
      );
    END IF;

    IF v_parent.job_ledger_id IS NOT NULL THEN
      PERFORM public.sync_crew_jobs_from_clock(v_person_name, v_parent.work_date);
    END IF;
    IF v_parent.bid_id IS NOT NULL THEN
      PERFORM public.sync_crew_bids_from_clock(v_person_name, v_parent.work_date);
    END IF;
  END IF;

  DELETE FROM public.clock_sessions WHERE id = p_session_id;

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    v_in := (v_elem->>'clocked_in_at')::timestamptz;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;
    v_notes := trim(both from coalesce(v_elem->>'notes', ''));

    v_work := (v_in AT TIME ZONE v_tz)::date;

    INSERT INTO public.clock_sessions (
      user_id,
      clocked_in_at,
      clocked_out_at,
      work_date,
      notes,
      job_ledger_id,
      bid_id,
      origin,
      salary_segment_index,
      clock_in_lat,
      clock_in_lng,
      clock_out_lat,
      clock_out_lng
    )
    VALUES (
      v_parent.user_id,
      v_in,
      v_out,
      v_work,
      v_notes,
      v_parent.job_ledger_id,
      v_parent.bid_id,
      CASE
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NOT NULL THEN 'user_punch'
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NULL THEN 'salary_schedule'
        ELSE v_parent.origin
      END,
      CASE
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NOT NULL THEN NULL
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NULL AND v_n >= 2 THEN (v_i + 1)::smallint
        ELSE NULL
      END,
      NULL,
      NULL,
      NULL,
      NULL
    )
    RETURNING id INTO v_new_id;

    v_ids := array_append(v_ids, v_new_id);
  END LOOP;

  UPDATE public.clock_sessions
  SET clock_in_lat = v_parent.clock_in_lat,
      clock_in_lng = v_parent.clock_in_lng
  WHERE id = v_ids[1];

  FOR v_i IN REVERSE (v_n - 1) .. 0 LOOP
    v_elem := p_segments -> v_i;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      UPDATE public.clock_sessions
      SET clock_out_lat = v_parent.clock_out_lat,
          clock_out_lng = v_parent.clock_out_lng
      WHERE id = v_ids[v_i + 1];
      EXIT;
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_ids, NULL::text;
END;
$$;


ALTER FUNCTION "public"."leader_split_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "leader_split_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."leader_split_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb") IS 'Like split_own_clock_session_segments for self, team lead, or pay access. Indexed salary_schedule children become user_punch.';


--
-- Name: list_ar_allocations_for_mercury_transaction("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_ar_allocations_for_mercury_transaction"("p_mercury_transaction_id" "uuid") RETURNS TABLE("payment_id" "uuid", "job_id" "uuid", "amount" numeric, "paid_on" "date", "invoice_id" "uuid", "note" "text", "hcp_number" "text", "job_name" "text", "invoice_sequence_order" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'list_ar_allocations_for_mercury_transaction: not authenticated';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RAISE EXCEPTION 'list_ar_allocations_for_mercury_transaction: not authorized';
  END IF;

  IF p_mercury_transaction_id IS NULL THEN
    RAISE EXCEPTION 'list_ar_allocations_for_mercury_transaction: mercury transaction required';
  END IF;

  RETURN QUERY
  SELECT
    p.id AS payment_id,
    p.job_id,
    p.amount::numeric,
    p.paid_on,
    p.invoice_id,
    nullif(trim(coalesce(p.note, '')), '') AS note,
    j.hcp_number,
    j.job_name,
    inv.sequence_order AS invoice_sequence_order
  FROM public.jobs_ledger_payments p
  INNER JOIN public.jobs_ledger j ON j.id = p.job_id
  LEFT JOIN public.jobs_ledger_invoices inv ON inv.id = p.invoice_id
  WHERE p.mercury_transaction_id = p_mercury_transaction_id
    AND (
      j.master_user_id = auth.uid()
      OR public.is_dev()
      OR EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
      OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = j.master_user_id)
      OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = j.master_user_id AND assistant_id = auth.uid())
      OR public.assistants_share_master(auth.uid(), j.master_user_id)
    )
  ORDER BY p.paid_on DESC NULLS LAST, p.id;
END;
$$;


ALTER FUNCTION "public"."list_ar_allocations_for_mercury_transaction"("p_mercury_transaction_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "list_ar_allocations_for_mercury_transaction"("p_mercury_transaction_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_ar_allocations_for_mercury_transaction"("p_mercury_transaction_id" "uuid") IS 'AR Bank Payments: jobs_ledger_payments rows linked to a Mercury transaction, with job/invoice labels (job access same as apply_mercury_bank_payment_allocations). Dev/master/assistant/primary only.';


--
-- Name: list_assigned_jobs_for_dashboard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_assigned_jobs_for_dashboard"() RETURNS TABLE("id" "uuid", "hcp_number" "text", "job_name" "text", "job_address" "text", "google_drive_link" "text", "job_plans_link" "text", "job_pictures_link" "text", "revenue" numeric, "master_user_id" "uuid", "created_at" timestamp with time zone, "last_report_at" timestamp with time zone, "my_last_report_at" timestamp with time zone, "last_thread_note_at" timestamp with time zone, "last_clock_activity_at" timestamp with time zone, "last_schedule_activity_at" timestamp with time zone, "last_job_activity_at" timestamp with time zone, "project_id" "uuid", "in_progress_stage_name" "text", "in_progress_step_id" "uuid", "status" "text", "service_type_id" "uuid", "service_type_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    jl.id,
    jl.hcp_number,
    jl.job_name,
    jl.job_address,
    jl.google_drive_link,
    jl.job_plans_link,
    jl.job_pictures_link,
    jl.revenue,
    jl.master_user_id,
    jl.created_at,
    (SELECT MAX(r.created_at)
     FROM public.reports r
     WHERE r.job_ledger_id = jl.id) AS last_report_at,
    (SELECT MAX(r.created_at)
     FROM public.reports r
     WHERE r.job_ledger_id = jl.id AND r.created_by_user_id = auth.uid()) AS my_last_report_at,
    (SELECT max(n.created_at) FROM public.jobs_ledger_thread_notes n WHERE n.job_id = jl.id) AS last_thread_note_at,
    (SELECT max(coalesce(cs.clocked_out_at, cs.clocked_in_at))
     FROM public.clock_sessions cs
     WHERE cs.job_ledger_id = jl.id
       AND cs.approved_at IS NOT NULL
       AND cs.rejected_at IS NULL
       AND cs.revoked_at IS NULL) AS last_clock_activity_at,
    (SELECT max(greatest(jb.created_at, jb.updated_at))
     FROM public.job_schedule_blocks jb
     WHERE jb.job_id = jl.id) AS last_schedule_activity_at,
    (SELECT max(x.v) FROM (
      SELECT (SELECT max(n2.created_at) FROM public.jobs_ledger_thread_notes n2 WHERE n2.job_id = jl.id) AS v
      UNION ALL
      SELECT (SELECT max(r2.created_at) FROM public.reports r2 WHERE r2.job_ledger_id = jl.id) AS v
      UNION ALL
      SELECT (SELECT max(coalesce(cs2.clocked_out_at, cs2.clocked_in_at))
              FROM public.clock_sessions cs2
              WHERE cs2.job_ledger_id = jl.id
                AND cs2.approved_at IS NOT NULL
                AND cs2.rejected_at IS NULL
                AND cs2.revoked_at IS NULL) AS v
      UNION ALL
      SELECT (SELECT max(greatest(jb2.created_at, jb2.updated_at))
              FROM public.job_schedule_blocks jb2
              WHERE jb2.job_id = jl.id) AS v
    ) x) AS last_job_activity_at,
    jl.project_id,
    (SELECT s.name
     FROM public.project_workflows pw
     JOIN public.project_workflow_steps s ON s.workflow_id = pw.id AND s.status = 'in_progress'
     WHERE pw.project_id = jl.project_id
     LIMIT 1) AS in_progress_stage_name,
    (SELECT s.id
     FROM public.project_workflows pw
     JOIN public.project_workflow_steps s ON s.workflow_id = pw.id AND s.status = 'in_progress'
     WHERE pw.project_id = jl.project_id
     LIMIT 1) AS in_progress_step_id,
    jl.status::text,
    jl.service_type_id,
    (SELECT stn.name FROM public.service_types stn WHERE stn.id = jl.service_type_id LIMIT 1) AS service_type_name
  FROM public.jobs_ledger jl
  INNER JOIN public.jobs_ledger_team_members jtm ON jtm.job_id = jl.id AND jtm.user_id = auth.uid()
  WHERE jl.status IN ('waiting', 'working')
  ORDER BY jl.hcp_number DESC, jl.job_name;
$$;


ALTER FUNCTION "public"."list_assigned_jobs_for_dashboard"() OWNER TO "postgres";

--
-- Name: FUNCTION "list_assigned_jobs_for_dashboard"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_assigned_jobs_for_dashboard"() IS 'Team waiting+working jobs for dashboard. last_report_at = any author; my_last_report_at = current user. job_pictures_link, service_type_id, service_type_name. Returns status so callers can distinguish waiting vs working.';


--
-- Name: list_bid_estimators_all_time_hours("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_bid_estimators_all_time_hours"("p_bid_ids" "uuid"[]) RETURNS TABLE("bid_id" "uuid", "hours" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    cs.bid_id,
    SUM(
      EXTRACT(EPOCH FROM (COALESCE(cs.clocked_out_at, now()) - cs.clocked_in_at)) / 3600.0
    )::numeric AS hours
  FROM public.clock_sessions cs
  WHERE cs.bid_id = ANY(p_bid_ids)
    AND cs.rejected_at IS NULL
    AND cs.revoked_at IS NULL
    AND COALESCE(cs.clocked_out_at, now()) > cs.clocked_in_at
  GROUP BY cs.bid_id;
$$;


ALTER FUNCTION "public"."list_bid_estimators_all_time_hours"("p_bid_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "list_bid_estimators_all_time_hours"("p_bid_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_bid_estimators_all_time_hours"("p_bid_ids" "uuid"[]) IS 'Bids → Estimators tab: lifetime (all-time) total clock hours per bid. Used as the denominator for per-day per-user cell percentages. Excludes rejected/revoked sessions; clips open sessions at now().';


--
-- Name: list_bid_estimators_window_hours("uuid"[], "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_bid_estimators_window_hours"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date") RETURNS TABLE("user_id" "uuid", "bid_id" "uuid", "work_date" "date", "hours" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    cs.user_id,
    cs.bid_id,
    cs.work_date,
    SUM(
      EXTRACT(EPOCH FROM (COALESCE(cs.clocked_out_at, now()) - cs.clocked_in_at)) / 3600.0
    )::numeric AS hours
  FROM public.clock_sessions cs
  WHERE cs.bid_id IS NOT NULL
    AND cs.rejected_at IS NULL
    AND cs.revoked_at IS NULL
    AND cs.work_date >= p_start_date
    AND cs.work_date <= p_end_date
    AND (p_user_ids IS NULL OR cs.user_id = ANY(p_user_ids))
    AND COALESCE(cs.clocked_out_at, now()) > cs.clocked_in_at
  GROUP BY cs.user_id, cs.bid_id, cs.work_date;
$$;


ALTER FUNCTION "public"."list_bid_estimators_window_hours"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "list_bid_estimators_window_hours"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_bid_estimators_window_hours"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date") IS 'Bids → Estimators tab: per-day hours per (user, bid) inside the visible window. Excludes rejected/revoked sessions; clips open sessions at now().';


--
-- Name: list_feedback_peer_candidates(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_feedback_peer_candidates"() RETURNS TABLE("person_id" "uuid", "peer_user_id" "uuid", "peer_name" "text", "shared_tag_count" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  uid UUID := auth.uid();
BEGIN
  IF uid IS NULL THEN RETURN; END IF;

  RETURN QUERY
  WITH reviewer_labels AS (
    SELECT DISTINCT ul.label_id
    FROM public.user_labels ul
    WHERE ul.user_id = uid
  ),
  user_peers AS (
    SELECT
      NULL::uuid AS person_id,
      u.id AS peer_user_id,
      COALESCE(NULLIF(trim(u.name), ''), u.email::text) AS peer_name,
      (
        SELECT COUNT(*)::int
        FROM public.user_labels ul2
        INNER JOIN reviewer_labels rl ON rl.label_id = ul2.label_id
        WHERE ul2.user_id = u.id
      ) AS shared_tag_count
    FROM public.users u
    WHERE u.archived_at IS NULL
      AND u.id <> uid
      AND EXISTS (
        SELECT 1
        FROM public.user_labels ul
        INNER JOIN reviewer_labels rl ON rl.label_id = ul.label_id
        WHERE ul.user_id = u.id
      )
  ),
  people_peers AS (
    SELECT
      p.id AS person_id,
      NULL::uuid AS peer_user_id,
      p.name::text AS peer_name,
      (
        SELECT COUNT(*)::int
        FROM public.people_labels pl2
        INNER JOIN reviewer_labels rl ON rl.label_id = pl2.label_id
        WHERE pl2.person_id = p.id
      ) AS shared_tag_count
    FROM public.people p
    WHERE p.archived_at IS NULL
      AND NOT EXISTS (
        SELECT 1
        FROM public.users u
        WHERE u.id = uid
          AND p.email IS NOT NULL
          AND trim(p.email) <> ''
          AND u.email IS NOT NULL
          AND trim(u.email) <> ''
          AND lower(trim(p.email)) = lower(trim(u.email))
      )
      AND EXISTS (
        SELECT 1
        FROM public.people_labels pl
        INNER JOIN reviewer_labels rl ON rl.label_id = pl.label_id
        WHERE pl.person_id = p.id
      )
  )
  SELECT combined.person_id, combined.peer_user_id, combined.peer_name, combined.shared_tag_count
  FROM (
    SELECT * FROM user_peers
    UNION ALL
    SELECT * FROM people_peers
  ) AS combined
  ORDER BY combined.shared_tag_count DESC, combined.peer_name ASC
  LIMIT 5000;
END;
$$;


ALTER FUNCTION "public"."list_feedback_peer_candidates"() OWNER TO "postgres";

--
-- Name: FUNCTION "list_feedback_peer_candidates"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_feedback_peer_candidates"() IS 'Team Feedback peer picker: users and people who share at least one label_id with the reviewer (reviewer labels from user_labels; peer match via user_labels or people_labels). Excludes self as user peer (id <> auth.uid()) and as people peer when people.email matches reviewer email. shared_tag_count is the intersection size. Empty when reviewer has no user_labels. Same human may appear twice (p: and u:) if both rows exist. SECURITY DEFINER; cap 5000.';


--
-- Name: list_job_counts_by_master_for_dev_settings(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_job_counts_by_master_for_dev_settings"() RETURNS TABLE("master_user_id" "uuid", "job_count" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'list_job_counts_by_master_for_dev_settings: not authenticated';
  END IF;
  IF NOT public.is_dev() THEN
    RAISE EXCEPTION 'list_job_counts_by_master_for_dev_settings: dev only';
  END IF;

  RETURN QUERY
  SELECT jl.master_user_id, COUNT(*)::bigint AS job_count
  FROM public.jobs_ledger jl
  WHERE jl.master_user_id IS NOT NULL
  GROUP BY jl.master_user_id;
END;
$$;


ALTER FUNCTION "public"."list_job_counts_by_master_for_dev_settings"() OWNER TO "postgres";

--
-- Name: FUNCTION "list_job_counts_by_master_for_dev_settings"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_job_counts_by_master_for_dev_settings"() IS 'Returns job counts grouped by jobs_ledger.master_user_id. Dev-only (is_dev). Used by Settings People & accounts.';


--
-- Name: list_job_schedule_blocks_for_schedule_email("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_job_schedule_blocks_for_schedule_email"("p_recipient" "uuid", "p_work_date" "date") RETURNS TABLE("id" "uuid", "job_id" "uuid", "assignee_user_id" "uuid", "work_date" "date", "time_start" time without time zone, "time_end" time without time zone, "note" "text", "assignee_name" "text", "job_hcp_number" "text", "job_name" "text", "job_address" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    jsb.id,
    jsb.job_id,
    jsb.assignee_user_id,
    jsb.work_date,
    jsb.time_start,
    jsb.time_end,
    jsb.note,
    trim(COALESCE(u.name, '')) AS assignee_name,
    jl.hcp_number AS job_hcp_number,
    jl.job_name AS job_name,
    jl.job_address AS job_address
  FROM public.job_schedule_blocks jsb
  INNER JOIN public.jobs_ledger jl ON jl.id = jsb.job_id
  LEFT JOIN public.users u ON u.id = jsb.assignee_user_id
  WHERE jsb.work_date = p_work_date
    AND (
      jsb.assignee_user_id = p_recipient
      OR EXISTS (SELECT 1 FROM public.users WHERE id = p_recipient AND role = 'dev')
      OR jl.master_user_id = p_recipient
      OR EXISTS (SELECT 1 FROM public.users WHERE id = p_recipient AND role = 'primary')
      OR EXISTS (
        SELECT 1 FROM public.master_superintendents ms
        WHERE ms.master_id = jl.master_user_id AND ms.superintendent_id = p_recipient
      )
      OR (jl.project_id IS NOT NULL AND public.can_access_project_row_for_user(jl.project_id, p_recipient))
      OR EXISTS (
        SELECT 1 FROM public.master_assistants
        WHERE master_id = p_recipient AND assistant_id = jl.master_user_id
      )
      OR EXISTS (
        SELECT 1 FROM public.master_assistants
        WHERE master_id = jl.master_user_id AND assistant_id = p_recipient
      )
      OR public.assistants_share_master(p_recipient, jl.master_user_id)
      OR EXISTS (
        SELECT 1 FROM public.jobs_ledger_team_members jtm
        WHERE jtm.job_id = jl.id AND jtm.user_id = p_recipient
      )
    )
  ORDER BY jsb.time_start ASC, jsb.assignee_user_id ASC;
$$;


ALTER FUNCTION "public"."list_job_schedule_blocks_for_schedule_email"("p_recipient" "uuid", "p_work_date" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "list_job_schedule_blocks_for_schedule_email"("p_recipient" "uuid", "p_work_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_job_schedule_blocks_for_schedule_email"("p_recipient" "uuid", "p_work_date" "date") IS 'Dispatch schedule blocks for one calendar day visible to p_recipient (job_schedule_blocks SELECT policy). Service role / Edge only.';


--
-- Name: list_jobs_for_tally(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_jobs_for_tally"() RETURNS TABLE("id" "uuid", "hcp_number" "text", "job_name" "text", "job_address" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    jl.id,
    jl.hcp_number,
    jl.job_name,
    jl.job_address
  FROM public.jobs_ledger jl
  INNER JOIN public.jobs_ledger_team_members jtm ON jtm.job_id = jl.id AND jtm.user_id = auth.uid()
  WHERE EXISTS (
    SELECT 1 FROM public.users
    WHERE id = auth.uid() AND role IN ('helpers', 'subcontractor')
  )
  ORDER BY jl.hcp_number DESC, jl.job_name;
$$;


