--
-- Name: list_manual_bank_accounts(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_manual_bank_accounts"() RETURNS TABLE("mercury_account_id" "uuid", "name" "text", "tx_count" bigint, "net_total" numeric, "oldest_posted" timestamp with time zone, "newest_posted" timestamp with time zone)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select
    t.mercury_account_id,
    n.nickname as name,
    count(*) as tx_count,
    coalesce(sum(t.amount), 0) as net_total,
    min(t.posted_at) as oldest_posted,
    max(t.posted_at) as newest_posted
  from public.mercury_transactions t
  left join public.mercury_account_nicknames n on n.mercury_account_id = t.mercury_account_id
  where t.source = 'manual'
  group by t.mercury_account_id, n.nickname
  order by max(t.posted_at) desc nulls last;
$$;


