COMMENT ON FUNCTION "public"."list_mercury_drag_sort_label_assignment_counts"() IS 'Returns mercury_transaction_drag_sort_assignments counts per label_id for Banking Accounting rule modal ordering (SECURITY INVOKER; banking staff via assignments SELECT RLS).';


--
-- Name: list_mercury_transactions_for_bank_payments("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_mercury_transactions_for_bank_payments"("p_filter" "jsonb" DEFAULT NULL::"jsonb") RETURNS TABLE("mercury_transaction_id" "uuid", "amount" numeric, "posted_at" timestamp with time zone, "counterparty_name" "text", "note" "text", "external_memo" "text", "kind" "text", "mercury_account_id" "uuid", "raw" "jsonb", "mercury_id" "uuid", "consumed" numeric, "remaining_available" numeric, "returned" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_kinds text[] := ARRAY[]::text[];
  v_account_ids text[] := ARRAY[]::text[];
  v_debit_ids text[] := ARRAY[]::text[];
  v_start_ymd text;
  v_exclude_cp text[] := ARRAY[]::text[];
  v_exclude_note text[] := ARRAY[]::text[];
  v_include_hidden boolean := false;
  o jsonb;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'list_mercury_transactions_for_bank_payments: not authenticated';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RAISE EXCEPTION 'list_mercury_transactions_for_bank_payments: not authorized';
  END IF;

  IF p_filter IS NOT NULL AND jsonb_typeof(p_filter) = 'object' THEN
    o := p_filter;
    IF o ? 'kinds' AND jsonb_typeof(o->'kinds') = 'array' THEN
      SELECT coalesce(array_agg(value::text), ARRAY[]::text[])
      INTO v_kinds
      FROM jsonb_array_elements_text(o->'kinds');
    END IF;
    IF o ? 'accountIds' AND jsonb_typeof(o->'accountIds') = 'array' THEN
      SELECT coalesce(array_agg(value::text), ARRAY[]::text[])
      INTO v_account_ids
      FROM jsonb_array_elements_text(o->'accountIds');
    END IF;
    IF o ? 'debitCardIds' AND jsonb_typeof(o->'debitCardIds') = 'array' THEN
      SELECT coalesce(array_agg(lower(trim(value::text))), ARRAY[]::text[])
      INTO v_debit_ids
      FROM jsonb_array_elements_text(o->'debitCardIds');
    END IF;
    IF o ? 'startDateYmd' AND jsonb_typeof(o->'startDateYmd') = 'string' THEN
      v_start_ymd := trim(o->>'startDateYmd');
    END IF;
    IF o ? 'excludeCounterpartyContains' AND jsonb_typeof(o->'excludeCounterpartyContains') = 'array' THEN
      WITH elements AS (
        SELECT left(btrim(value), 120) AS p
        FROM jsonb_array_elements_text(o->'excludeCounterpartyContains')
        WHERE length(btrim(value)) > 0
        LIMIT 50
      )
      SELECT coalesce(array_agg(p ORDER BY p), ARRAY[]::text[])
      INTO v_exclude_cp
      FROM elements;
    END IF;
    IF o ? 'excludeNoteContains' AND jsonb_typeof(o->'excludeNoteContains') = 'array' THEN
      WITH elements AS (
        SELECT left(btrim(value), 120) AS p
        FROM jsonb_array_elements_text(o->'excludeNoteContains')
        WHERE length(btrim(value)) > 0
        LIMIT 50
      )
      SELECT coalesce(array_agg(p ORDER BY p), ARRAY[]::text[])
      INTO v_exclude_note
      FROM elements;
    END IF;
    IF o ? 'includeHiddenArDeposits' AND jsonb_typeof(o->'includeHiddenArDeposits') = 'boolean' THEN
      v_include_hidden := (o->>'includeHiddenArDeposits')::boolean;
    ELSIF o ? 'includeFullyApplied' AND jsonb_typeof(o->'includeFullyApplied') = 'boolean' THEN
      v_include_hidden := (o->>'includeFullyApplied')::boolean;
    END IF;
  END IF;

  IF v_start_ymd IS NULL OR v_start_ymd !~ '^\d{4}-\d{2}-\d{2}$' THEN
    v_start_ymd := to_char((CURRENT_TIMESTAMP AT TIME ZONE 'America/Chicago')::date - 90, 'YYYY-MM-DD');
  END IF;

  RETURN QUERY
  SELECT
    t.id AS mercury_transaction_id,
    t.amount::numeric,
    t.posted_at,
    t.counterparty_name,
    t.note,
    t.external_memo,
    t.kind,
    t.mercury_account_id,
    t.raw,
    t.mercury_id,
    coalesce((
      SELECT sum(p.amount)
      FROM public.jobs_ledger_payments p
      WHERE p.mercury_transaction_id = t.id
    ), 0)::numeric AS consumed,
    (abs(t.amount) - coalesce((
      SELECT sum(p.amount)
      FROM public.jobs_ledger_payments p
      WHERE p.mercury_transaction_id = t.id
    ), 0))::numeric AS remaining_available,
    coalesce(r.returned, false) AS returned
  FROM public.mercury_transactions t
  LEFT JOIN public.mercury_transaction_ar_returned r ON r.mercury_transaction_id = t.id
  WHERE t.posted_at IS NOT NULL
    AND to_char((t.posted_at AT TIME ZONE 'America/Chicago')::date, 'YYYY-MM-DD') >= v_start_ymd
    AND (cardinality(v_kinds) = 0 OR t.kind = ANY (v_kinds))
    AND (cardinality(v_account_ids) = 0 OR t.mercury_account_id::text = ANY (v_account_ids))
    AND (
      cardinality(v_debit_ids) = 0
      OR public._mercury_raw_debit_card_id_lower(t.raw) = ANY (v_debit_ids)
    )
    AND abs(t.amount) > 0
    AND (
      v_include_hidden
      OR (
        abs(t.amount) - coalesce((
          SELECT sum(p.amount)
          FROM public.jobs_ledger_payments p
          WHERE p.mercury_transaction_id = t.id
        ), 0)
      ) > 0.0005
    )
    AND (
      v_include_hidden
      OR NOT EXISTS (
        SELECT 1
        FROM public.mercury_transaction_ar_returned r2
        WHERE r2.mercury_transaction_id = t.id
          AND r2.returned
      )
    )
    AND NOT (
      cardinality(v_exclude_cp) > 0
      AND EXISTS (
        SELECT 1
        FROM unnest(v_exclude_cp) AS x(pat)
        WHERE position(lower(x.pat) IN lower(coalesce(t.counterparty_name, ''))) > 0
      )
    )
    AND NOT (
      cardinality(v_exclude_note) > 0
      AND EXISTS (
        SELECT 1
        FROM unnest(v_exclude_note) AS x(pat)
        WHERE position(lower(x.pat) IN lower(coalesce(t.note, ''))) > 0
      )
    )
  ORDER BY t.posted_at DESC NULLS LAST, t.id DESC;
END;
$_$;


ALTER FUNCTION "public"."list_mercury_transactions_for_bank_payments"("p_filter" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "list_mercury_transactions_for_bank_payments"("p_filter" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_mercury_transactions_for_bank_payments"("p_filter" "jsonb") IS 'Lists Mercury transactions for Jobs Bank Payments modal (filter mirrors BankingSortingConfigV1; includeHiddenArDeposits or legacy includeFullyApplied shows zero-remainder and returned-flag rows; returned column from mercury_transaction_ar_returned). Dev/master/assistant/primary only.';


--
-- Name: mercury_transactions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."mercury_transactions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "mercury_id" "uuid",
    "mercury_account_id" "uuid" NOT NULL,
    "amount" numeric(18,4) NOT NULL,
    "currency" "text" DEFAULT 'USD'::"text" NOT NULL,
    "created_at" timestamp with time zone NOT NULL,
    "posted_at" timestamp with time zone,
    "status" "text" NOT NULL,
    "kind" "text" NOT NULL,
    "counterparty_id" "uuid",
    "counterparty_name" "text",
    "note" "text",
    "external_memo" "text",
    "dashboard_link" "text",
    "mercury_category" "jsonb",
    "raw" "jsonb",
    "synced_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "source" "text" DEFAULT 'mercury'::"text" NOT NULL,
    "manual_upload_id" "uuid",
    "created_by" "uuid",
    "duplicate_of_transaction_id" "uuid",
    CONSTRAINT "mercury_transactions_source_chk" CHECK (("source" = ANY (ARRAY['mercury'::"text", 'manual'::"text"]))),
    CONSTRAINT "mercury_transactions_source_provenance_chk" CHECK (((("source" = 'mercury'::"text") AND ("mercury_id" IS NOT NULL)) OR (("source" = 'manual'::"text") AND ("mercury_id" IS NULL))))
);


ALTER TABLE "public"."mercury_transactions" OWNER TO "postgres";

--
-- Name: TABLE "mercury_transactions"; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE "public"."mercury_transactions" IS 'Mercury API transactions; populated by sync-mercury-transactions Edge Function.';


--
-- Name: list_mercury_transactions_keyset(timestamp with time zone, "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_mercury_transactions_keyset"("p_after_posted_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_after_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 500) RETURNS SETOF "public"."mercury_transactions"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select t.*
  from public.mercury_transactions t
  where t.duplicate_of_transaction_id is null
    and (
      p_after_id is null
      or (
        p_after_posted_at is not null and (
          t.posted_at < p_after_posted_at
          or (t.posted_at = p_after_posted_at and t.id < p_after_id)
          or t.posted_at is null
        )
      )
      or (
        p_after_posted_at is null and t.posted_at is null and t.id < p_after_id
      )
    )
  order by t.posted_at desc nulls last, t.id desc
  limit p_limit;
$$;


ALTER FUNCTION "public"."list_mercury_transactions_keyset"("p_after_posted_at" timestamp with time zone, "p_after_id" "uuid", "p_limit" integer) OWNER TO "postgres";

--
-- Name: list_mercury_transactions_keyset_before(timestamp with time zone, "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_mercury_transactions_keyset_before"("p_before_posted_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_before_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20) RETURNS SETOF "public"."mercury_transactions"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select t.*
  from public.mercury_transactions t
  where
    p_before_id is null
    or (
      p_before_posted_at is not null and (
        t.posted_at > p_before_posted_at
        or (t.posted_at = p_before_posted_at and t.id > p_before_id)
      )
    )
    or (
      p_before_posted_at is null and (t.posted_at is not null or t.id > p_before_id)
    )
  order by t.posted_at asc nulls last, t.id asc
  limit p_limit;
$$;


ALTER FUNCTION "public"."list_mercury_transactions_keyset_before"("p_before_posted_at" timestamp with time zone, "p_before_id" "uuid", "p_limit" integer) OWNER TO "postgres";

--
-- Name: list_my_accessible_job_activity_events("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_my_accessible_job_activity_events"("p_job_id" "uuid", "p_limit" integer DEFAULT 10) RETURNS TABLE("activity_at" timestamp with time zone, "kind" "text", "summary" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT e.activity_at,
         e.kind,
         e.summary
  FROM (
    SELECT
      n.created_at AS activity_at,
      'thread_note'::text AS kind,
      left(
        coalesce(
          nullif(
            btrim(
              regexp_replace(
                regexp_replace(coalesce(n.body, ''), chr(13), ' ', 'g'),
                chr(10),
                ' ',
                'g'
              )
            ),
            ''
          ),
          'Thread note'
        ),
        500
      ) AS summary
    FROM public.jobs_ledger_thread_notes n
    WHERE n.job_id = p_job_id
    UNION ALL
    SELECT
      r.created_at AS activity_at,
      'field_report'::text AS kind,
      left(coalesce(rt.name, 'Field report'), 500) AS summary
    FROM public.reports r
    JOIN public.report_templates rt ON r.template_id = rt.id
    WHERE r.job_ledger_id = p_job_id
    UNION ALL
    SELECT
      coalesce(cs.clocked_out_at, cs.clocked_in_at) AS activity_at,
      'clock'::text AS kind,
      left(
        'Work session'
        || coalesce(' · ' || u.name, '')
        || CASE
          WHEN cs.clocked_out_at IS NOT NULL THEN
            ' · '
            || (greatest(
              1,
              (extract(epoch FROM (cs.clocked_out_at - cs.clocked_in_at)) / 60.0)
            ))::int::text
            || ' min'
          ELSE
            ' · in progress'
        END,
        500
      ) AS summary
    FROM public.clock_sessions cs
    LEFT JOIN public.users u ON u.id = cs.user_id
    WHERE cs.job_ledger_id = p_job_id
      AND cs.approved_at IS NOT NULL
      AND cs.rejected_at IS NULL
      AND cs.revoked_at IS NULL
    UNION ALL
    SELECT
      greatest(jb.created_at, jb.updated_at) AS activity_at,
      'schedule'::text AS kind,
      left(
        coalesce(
          nullif(btrim(jb.note), ''),
          to_char(jb.work_date, 'Mon DD, YYYY')
          || ' — '
          || to_char(jb.time_start, 'HH24:MI')
          || '–'
          || to_char(jb.time_end, 'HH24:MI')
        ),
        500
      ) AS summary
    FROM public.job_schedule_blocks jb
    WHERE jb.job_id = p_job_id
  ) e
  WHERE EXISTS (
    SELECT 1
    FROM public.jobs_ledger_team_members jtm
    WHERE jtm.job_id = p_job_id
      AND jtm.user_id = auth.uid()
  )
  ORDER BY e.activity_at DESC
  LIMIT least(greatest(coalesce(p_limit, 10), 1), 50);
$$;


ALTER FUNCTION "public"."list_my_accessible_job_activity_events"("p_job_id" "uuid", "p_limit" integer) OWNER TO "postgres";

--
-- Name: FUNCTION "list_my_accessible_job_activity_events"("p_job_id" "uuid", "p_limit" integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_my_accessible_job_activity_events"("p_job_id" "uuid", "p_limit" integer) IS 'Reverse-chronological job activity the caller can see (RLS on each source), union of thread notes, field reports, qualifying approved clock sessions, and schedule block touches. Requires jobs_ledger_team_members row for p_job_id.';


--
-- Name: list_my_contract_dashboard_prompts(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_my_contract_dashboard_prompts"() RETURNS TABLE("id" "uuid", "document_name" "text", "status" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT pcd.id, pcd.document_name, pcd.status
  FROM public.person_contract_documents pcd
  CROSS JOIN public.users u
  WHERE u.id = auth.uid()
    AND pcd.dashboard_prompt_after_clock_in = true
    AND pcd.status <> 'signed'
    AND (
      (pcd.signing_body_html IS NOT NULL AND btrim(pcd.signing_body_html) <> '')
      OR (pcd.canonical_document_url IS NOT NULL AND btrim(pcd.canonical_document_url) <> '')
      OR (pcd.url IS NOT NULL AND btrim(pcd.url) <> '')
    )
    AND (
      EXISTS (
        SELECT 1
        FROM public.people p
        WHERE p.archived_at IS NULL
          AND trim(p.name) = trim(pcd.person_name)
          AND p.email IS NOT NULL
          AND btrim(p.email) <> ''
          AND u.email IS NOT NULL
          AND btrim(u.email) <> ''
          AND lower(btrim(p.email)) = lower(btrim(u.email))
      )
      OR trim(u.name) = trim(pcd.person_name)
    );
$$;


ALTER FUNCTION "public"."list_my_contract_dashboard_prompts"() OWNER TO "postgres";

--
-- Name: FUNCTION "list_my_contract_dashboard_prompts"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_my_contract_dashboard_prompts"() IS 'Unsigned person_contract_documents flagged for dashboard reminder, for the current auth user (roster email/name match). SECURITY DEFINER.';


--
-- Name: list_my_linked_mercury_debit_cards_for_tally(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_my_linked_mercury_debit_cards_for_tally"() RETURNS TABLE("mercury_debit_card_id" "uuid", "nickname" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'list_my_linked_mercury_debit_cards_for_tally: not authenticated';
  END IF;

  RETURN QUERY
  SELECT
    l.mercury_debit_card_id,
    nn.nickname
  FROM public.mercury_debit_card_user_links l
  LEFT JOIN public.mercury_debit_card_nicknames nn
    ON nn.mercury_debit_card_id = l.mercury_debit_card_id
  WHERE l.user_id = auth.uid()
  ORDER BY COALESCE(nn.nickname, ''), l.mercury_debit_card_id;
END;
$$;


