--
-- Name: list_my_linked_mercury_transactions_for_tally(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_my_linked_mercury_transactions_for_tally"() RETURNS TABLE("mercury_transaction_id" "uuid", "mercury_debit_card_id" "uuid", "posted_at" timestamp with time zone, "amount" numeric, "counterparty_name" "text", "note" "text", "tally_user_note" "text", "person_label" "text", "jobs_summary" "text", "invoices_summary" "text", "mercury_account_id" "uuid", "mercury_account_nickname" "text", "currency" "text", "mercury_id" "uuid", "raw" "jsonb", "job_splits" "jsonb")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'list_my_linked_mercury_transactions_for_tally: not authenticated';
  END IF;

  RETURN QUERY
  SELECT
    t.id,
    l.mercury_debit_card_id,
    t.posted_at,
    t.amount,
    t.counterparty_name,
    t.note,
    n.body AS tally_user_note,
    COALESCE(ppl.name, u_attr.name, u_self.name)::text AS person_label,
    jobs.jobs_summary,
    inv.invoices_summary,
    t.mercury_account_id,
    ann.nickname AS mercury_account_nickname,
    t.currency,
    t.mercury_id,
    t.raw,
    COALESCE(splits.job_splits, '[]'::jsonb) AS job_splits
  FROM public.mercury_transactions t
  INNER JOIN public.mercury_debit_card_user_links l
    ON l.user_id = auth.uid()
    AND l.mercury_debit_card_id = public.mercury_debit_card_id_from_raw(t.raw)
  INNER JOIN public.users u_self ON u_self.id = auth.uid()
  LEFT JOIN public.mercury_tally_transaction_notes n
    ON n.mercury_transaction_id = t.id
    AND n.user_id = auth.uid()
  LEFT JOIN public.mercury_account_nicknames ann
    ON ann.mercury_account_id = t.mercury_account_id
  LEFT JOIN public.mercury_transaction_attributions a
    ON a.mercury_transaction_id = t.id
  LEFT JOIN public.people ppl ON ppl.id = a.person_id
  LEFT JOIN public.users u_attr ON u_attr.id = a.user_id
  LEFT JOIN LATERAL (
    SELECT
      string_agg(
        concat_ws(' · ', j.hcp_number, j.job_name),
        '; ' ORDER BY j.hcp_number NULLS LAST, j.job_name NULLS LAST
      ) AS jobs_summary
    FROM public.mercury_transaction_job_allocations m
    INNER JOIN public.jobs_ledger j ON j.id = m.job_id
    WHERE m.mercury_transaction_id = t.id
  ) jobs ON true
  LEFT JOIN LATERAL (
    SELECT
      string_agg(
        concat_ws(' · ', sh.name, si.invoice_number),
        '; ' ORDER BY si.invoice_date DESC NULLS LAST, si.invoice_number ASC
      ) AS invoices_summary
    FROM public.mercury_transaction_supply_house_invoice_links il
    INNER JOIN public.supply_house_invoices si ON si.id = il.invoice_id
    INNER JOIN public.supply_houses sh ON sh.id = si.supply_house_id
    WHERE il.mercury_transaction_id = t.id
  ) inv ON true
  LEFT JOIN LATERAL (
    SELECT
      COALESCE(
        jsonb_agg(
          jsonb_build_object(
            'job_id', m.job_id,
            'amount', m.amount,
            'note', m.note,
            'hcp_number', j.hcp_number,
            'job_name', j.job_name
          )
          ORDER BY j.hcp_number NULLS LAST, j.job_name NULLS LAST
        ),
        '[]'::jsonb
      ) AS job_splits
    FROM public.mercury_transaction_job_allocations m
    INNER JOIN public.jobs_ledger j ON j.id = m.job_id
    WHERE m.mercury_transaction_id = t.id
  ) splits ON true
  ORDER BY t.posted_at DESC NULLS LAST, t.id ASC;
END;
$$;


ALTER FUNCTION "public"."list_my_linked_mercury_transactions_for_tally"() OWNER TO "postgres";

--
-- Name: FUNCTION "list_my_linked_mercury_transactions_for_tally"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_my_linked_mercury_transactions_for_tally"() IS 'Linked-card transactions for Tally: debit card id, account nickname, raw, job_splits, Mercury memo (note), user Tally note, jobs_summary, and invoices_summary (linked supply-house invoices).';


--
-- Name: list_my_reports(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_my_reports"() RETURNS TABLE("id" "uuid", "template_id" "uuid", "template_name" "text", "created_by_user_id" "uuid", "created_by_name" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "field_values" "jsonb", "job_ledger_id" "uuid", "project_id" "uuid", "bid_id" "uuid", "job_display_name" "text", "job_hcp_number" "text", "reported_at_lat" numeric, "reported_at_lng" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    r.id,
    r.template_id,
    rt.name AS template_name,
    r.created_by_user_id,
    u.name AS created_by_name,
    r.created_at,
    r.updated_at,
    r.field_values,
    r.job_ledger_id,
    r.project_id,
    r.bid_id,
    COALESCE(jl.job_name, p.name, b.project_name, b.gc_contact_name, 'Bid') AS job_display_name,
    COALESCE(jl.hcp_number, p.housecallpro_number, b.bid_number, '')::TEXT AS job_hcp_number,
    r.reported_at_lat AS reported_at_lat,
    r.reported_at_lng AS reported_at_lng
  FROM public.reports r
  JOIN public.report_templates rt ON r.template_id = rt.id
  JOIN public.users u ON r.created_by_user_id = u.id
  LEFT JOIN public.jobs_ledger jl ON r.job_ledger_id = jl.id
  LEFT JOIN public.projects p ON r.project_id = p.id
  LEFT JOIN public.bids b ON r.bid_id = b.id
  WHERE r.created_by_user_id = auth.uid()
    AND r.created_at >= (NOW() - (public.report_sub_visibility_months() || ' months')::interval)
  ORDER BY r.created_at DESC;
$$;


ALTER FUNCTION "public"."list_my_reports"() OWNER TO "postgres";

--
-- Name: list_people_for_banking_attribution(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_people_for_banking_attribution"() RETURNS TABLE("id" "uuid", "name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT p.id, p.name
  FROM public.people p
  WHERE p.archived_at IS NULL
    AND EXISTS (
      SELECT 1 FROM public.users u
      WHERE u.id = auth.uid()
        AND u.role IN ('dev', 'master_technician', 'assistant')
    )
  ORDER BY p.name;
$$;


