COMMENT ON FUNCTION "public"."list_superintendent_jobs_for_dashboard"() IS 'Superintendent project-linked jobs for dashboard. Includes job_pictures_link and my_last_report_at.';


--
-- Name: list_supply_house_invoices_for_tally_link("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_supply_house_invoices_for_tally_link"("p_mercury_transaction_id" "uuid", "search_text" "text" DEFAULT ''::"text") RETURNS TABLE("invoice_id" "uuid", "invoice_number" "text", "invoice_date" "date", "due_date" "date", "amount" numeric, "is_paid" boolean, "purchase_order_number" "text", "link" "text", "supply_house_id" "uuid", "supply_house_name" "text", "counterparty_match" boolean, "already_linked" boolean, "job_allocation_summary" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_counterparty text;
  v_authorized boolean := false;
  v_search text := NULLIF(trim(both FROM COALESCE(search_text, '')), '');
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'list_supply_house_invoices_for_tally_link: not authenticated';
  END IF;

  SELECT t.counterparty_name INTO v_counterparty
  FROM public.mercury_transactions t
  WHERE t.id = p_mercury_transaction_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'list_supply_house_invoices_for_tally_link: transaction not found';
  END IF;

  -- Authorize: staff role, or linked-card holder of this transaction.
  v_authorized := EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid() AND u.role IN ('dev', 'master_technician', 'assistant')
  ) OR EXISTS (
    SELECT 1
    FROM public.mercury_transactions t
    INNER JOIN public.mercury_debit_card_user_links l
      ON l.user_id = auth.uid()
      AND l.mercury_debit_card_id = public.mercury_debit_card_id_from_raw(t.raw)
    WHERE t.id = p_mercury_transaction_id
  );

  IF NOT v_authorized THEN
    RAISE EXCEPTION 'list_supply_house_invoices_for_tally_link: not authorized';
  END IF;

  RETURN QUERY
  SELECT
    si.id AS invoice_id,
    si.invoice_number,
    si.invoice_date,
    si.due_date,
    si.amount,
    si.is_paid,
    si.purchase_order_number,
    si.link,
    sh.id AS supply_house_id,
    sh.name::text AS supply_house_name,
    (
      v_counterparty IS NOT NULL
      AND v_counterparty <> ''
      AND (
        sh.name ILIKE '%' || v_counterparty || '%'
        OR v_counterparty ILIKE '%' || sh.name || '%'
      )
    ) AS counterparty_match,
    EXISTS (
      SELECT 1 FROM public.mercury_transaction_supply_house_invoice_links il
      WHERE il.mercury_transaction_id = p_mercury_transaction_id
        AND il.invoice_id = si.id
    ) AS already_linked,
    alloc.job_allocation_summary
  FROM public.supply_house_invoices si
  INNER JOIN public.supply_houses sh ON sh.id = si.supply_house_id
  LEFT JOIN LATERAL (
    SELECT string_agg(
      concat_ws(' ', concat_ws(' · ', j.hcp_number, j.job_name), '(' || round(a.pct)::text || '%)'),
      '; ' ORDER BY a.pct DESC NULLS LAST
    ) AS job_allocation_summary
    FROM public.supply_house_invoice_job_allocations a
    INNER JOIN public.jobs_ledger j ON j.id = a.job_id
    WHERE a.invoice_id = si.id
  ) alloc ON true
  WHERE (
    v_search IS NULL
    OR si.invoice_number ILIKE '%' || v_search || '%'
    OR sh.name ILIKE '%' || v_search || '%'
    OR COALESCE(si.purchase_order_number, '') ILIKE '%' || v_search || '%'
  )
  ORDER BY
    EXISTS (
      SELECT 1 FROM public.mercury_transaction_supply_house_invoice_links il
      WHERE il.mercury_transaction_id = p_mercury_transaction_id AND il.invoice_id = si.id
    ) DESC,
    (
      v_counterparty IS NOT NULL
      AND v_counterparty <> ''
      AND (sh.name ILIKE '%' || v_counterparty || '%' OR v_counterparty ILIKE '%' || sh.name || '%')
    ) DESC,
    si.is_paid ASC,
    si.invoice_date DESC NULLS LAST,
    si.invoice_number ASC
  LIMIT 100;
END;
$$;


ALTER FUNCTION "public"."list_supply_house_invoices_for_tally_link"("p_mercury_transaction_id" "uuid", "search_text" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "list_supply_house_invoices_for_tally_link"("p_mercury_transaction_id" "uuid", "search_text" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_supply_house_invoices_for_tally_link"("p_mercury_transaction_id" "uuid", "search_text" "text") IS 'Search supply-house invoices to link to a Mercury transaction (staff or the linked-card holder). Counterparty-matched and unpaid invoices first; already_linked flags current links.';


--
-- Name: list_tally_parts_with_po(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_tally_parts_with_po"() RETURNS TABLE("id" "uuid", "job_id" "uuid", "fixture_name" "text", "part_id" "uuid", "quantity" numeric, "created_by_user_id" "uuid", "created_at" timestamp with time zone, "price_at_time" numeric, "fixture_cost" numeric, "purchase_order_id" "uuid", "purchase_order_name" "text", "purchase_order_status" "text", "hcp_number" "text", "job_name" "text", "job_address" "text", "part_name" "text", "part_manufacturer" "text", "created_by_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    jtp.id,
    jtp.job_id,
    jtp.fixture_name,
    jtp.part_id,
    jtp.quantity,
    jtp.created_by_user_id,
    jtp.created_at,
    poi.price_at_time,
    jtp.fixture_cost,
    jtp.purchase_order_id,
    po.name AS purchase_order_name,
    po.status::TEXT AS purchase_order_status,
    jl.hcp_number,
    jl.job_name,
    jl.job_address,
    mp.name AS part_name,
    mp.manufacturer AS part_manufacturer,
    u.name AS created_by_name
  FROM public.jobs_tally_parts jtp
  INNER JOIN public.jobs_ledger jl ON jl.id = jtp.job_id
  LEFT JOIN public.material_parts mp ON mp.id = jtp.part_id
  LEFT JOIN public.users u ON u.id = jtp.created_by_user_id
  LEFT JOIN public.purchase_orders po ON po.id = jtp.purchase_order_id
  LEFT JOIN public.purchase_order_items poi
    ON poi.purchase_order_id = jtp.purchase_order_id
    AND poi.part_id = jtp.part_id
  WHERE EXISTS (
    SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant')
    AND (
      jl.master_user_id = auth.uid()
      OR public.is_dev()
      OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = jl.master_user_id)
      OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = jl.master_user_id AND assistant_id = auth.uid())
      OR public.assistants_share_master(auth.uid(), jl.master_user_id)
    )
  )
  OR (
    EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
    AND EXISTS (SELECT 1 FROM public.master_primaries WHERE master_id = jl.master_user_id AND primary_id = auth.uid())
  )
  OR (
    public.auth_uid_is_helpers_or_subcontractor()
    AND EXISTS (SELECT 1 FROM public.jobs_ledger_team_members jtm WHERE jtm.job_id = jtp.job_id AND jtm.user_id = auth.uid())
  )
  ORDER BY jtp.created_at DESC;
$$;


ALTER FUNCTION "public"."list_tally_parts_with_po"() OWNER TO "postgres";

--
-- Name: list_unlabeled_mercury_transactions(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_unlabeled_mercury_transactions"("p_limit" integer DEFAULT NULL::integer) RETURNS SETOF "public"."mercury_transactions"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select t.*
  from public.mercury_transactions t
  left join public.mercury_transaction_drag_sort_assignments a
    on a.mercury_transaction_id = t.id
  where a.mercury_transaction_id is null
    and t.duplicate_of_transaction_id is null
  order by t.posted_at desc nulls last, t.id desc
  limit p_limit;
$$;


