--
-- Name: list_user_mercury_review_window("uuid", "date", "date", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_user_mercury_review_window"("p_user_id" "uuid", "p_start_ymd" "date", "p_end_ymd" "date", "p_include_person_attributed" boolean DEFAULT true) RETURNS TABLE("mercury_transaction_id" "uuid", "posted_at" timestamp with time zone, "created_at" timestamp with time zone, "amount" numeric, "counterparty_name" "text", "attribution_source" "text", "attribution_person_id" "uuid", "label_id" "uuid", "label_name" "text", "allocation_id" "uuid", "job_id" "uuid", "allocation_amount" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant')
  ) THEN
    RAISE EXCEPTION 'list_user_mercury_review_window: not authorized';
  END IF;

  RETURN QUERY
  WITH win AS (
    SELECT
      ((p_start_ymd::timestamp)            AT TIME ZONE 'America/Chicago') AS lo,
      (((p_end_ymd + INTEGER '1')::timestamp) AT TIME ZONE 'America/Chicago') AS hi
  ),
  tx AS (
    SELECT
      t.id,
      t.posted_at,
      t.created_at,
      t.amount,
      t.counterparty_name,
      a.user_id,
      a.person_id,
      CASE
        WHEN a.user_id = p_user_id THEN 'user'
        WHEN a.person_id IS NOT NULL AND p_include_person_attributed THEN 'person'
      END AS attribution_source
    FROM public.mercury_transactions t
    JOIN public.mercury_transaction_attributions a
      ON a.mercury_transaction_id = t.id
    CROSS JOIN win
    WHERE COALESCE(t.posted_at, t.created_at) >= win.lo
      AND COALESCE(t.posted_at, t.created_at) <  win.hi
      AND (
        a.user_id = p_user_id
        OR (p_include_person_attributed AND a.person_id IS NOT NULL)
      )
  )
  SELECT
    tx.id,
    tx.posted_at,
    tx.created_at,
    tx.amount,
    tx.counterparty_name,
    tx.attribution_source,
    tx.person_id,
    l.id   AS label_id,
    l.name AS label_name,
    al.id  AS allocation_id,
    al.job_id,
    al.amount AS allocation_amount
  FROM tx
  LEFT JOIN public.mercury_transaction_drag_sort_assignments asg
    ON asg.mercury_transaction_id = tx.id
  LEFT JOIN public.mercury_drag_sort_labels l
    ON l.id = asg.label_id
  LEFT JOIN public.mercury_transaction_job_allocations al
    ON al.mercury_transaction_id = tx.id
  WHERE tx.attribution_source IS NOT NULL
  ORDER BY
    COALESCE(tx.posted_at, tx.created_at) DESC NULLS LAST,
    tx.id,
    al.id NULLS FIRST;
END;
$$;


ALTER FUNCTION "public"."list_user_mercury_review_window"("p_user_id" "uuid", "p_start_ymd" "date", "p_end_ymd" "date", "p_include_person_attributed" boolean) OWNER TO "postgres";

--
-- Name: FUNCTION "list_user_mercury_review_window"("p_user_id" "uuid", "p_start_ymd" "date", "p_end_ymd" "date", "p_include_person_attributed" boolean); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_user_mercury_review_window"("p_user_id" "uuid", "p_start_ymd" "date", "p_end_ymd" "date", "p_include_person_attributed" boolean) IS 'User Review Modal: returns Mercury tx rows (joined to job allocations + drag-sort label) attributed to a user (and optionally any person-attributed tx) within a company-calendar-day window. Banking staff only.';


