--
-- Name: log_bid_pricing_package_send("uuid", "uuid", "uuid", "text", integer, integer, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."log_bid_pricing_package_send"("p_bid_id" "uuid", "p_price_book_version_id" "uuid", "p_recipient_user_id" "uuid", "p_recipient_email" "text", "p_revenue_total_cents" integer, "p_row_count" integer, "p_plans_link" "text") RETURNS "uuid"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  new_id uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  INSERT INTO public.bid_pricing_package_sends (
    bid_id,
    price_book_version_id,
    sent_by_user_id,
    recipient_user_id,
    recipient_email,
    sent_via,
    resend_id,
    plans_link,
    revenue_total_cents,
    row_count
  )
  VALUES (
    p_bid_id,
    p_price_book_version_id,
    auth.uid(),
    p_recipient_user_id,
    p_recipient_email,
    'mailto_logged',
    NULL,
    p_plans_link,
    p_revenue_total_cents,
    p_row_count
  )
  RETURNING id INTO new_id;

  RETURN new_id;
END;
$$;


