-- Name: FUNCTION "mark_invoice_paid"("p_invoice_id" "uuid", "p_amount" numeric, "p_paid_on" "date", "p_note" "text", "p_payment_type" "text", "p_reference_number" "text"); Type: COMMENT; Schema: public; Owner: postgres
