--
-- Name: mark_invoice_paid_from_stripe("uuid", "text", "text", "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mark_invoice_paid_from_stripe"("p_invoice_id" "uuid", "p_payment_type" "text" DEFAULT NULL::"text", "p_reference_number" "text" DEFAULT NULL::"text", "p_paid_on" "date" DEFAULT NULL::"date", "p_internal_note" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_next_order INTEGER;
  v_applied NUMERIC;
  v_remaining NUMERIC;
  v_paid_on DATE;
  v_pt TEXT;
  v_ref TEXT;
  v_note TEXT;
  v_row_note TEXT;
BEGIN
  SELECT id, job_id, amount, status INTO v_invoice
  FROM public.jobs_ledger_invoices
  WHERE id = p_invoice_id;

  IF v_invoice.id IS NULL THEN
    RETURN jsonb_build_object('error', 'Invoice not found');
  END IF;

  IF v_invoice.status = 'paid' THEN
    RETURN jsonb_build_object('ok', true);
  END IF;

  IF v_invoice.status <> 'billed' THEN
    RETURN jsonb_build_object('error', 'Invoice must be in Billed status to mark as paid');
  END IF;

  SELECT COALESCE(SUM(amount), 0) INTO v_applied
  FROM public.jobs_ledger_payments
  WHERE invoice_id = p_invoice_id;

  v_remaining := COALESCE(v_invoice.amount, 0) - v_applied;

  IF v_remaining <= 0 THEN
    UPDATE public.jobs_ledger_invoices SET status = 'paid' WHERE id = p_invoice_id;
    RETURN jsonb_build_object('ok', true);
  END IF;

  v_paid_on := COALESCE(p_paid_on, (CURRENT_TIMESTAMP AT TIME ZONE 'UTC')::date);
  v_pt := NULLIF(trim(COALESCE(p_payment_type, '')), '');
  v_ref := NULLIF(trim(COALESCE(p_reference_number, '')), '');
  v_note := NULLIF(trim(COALESCE(p_internal_note, '')), '');

  IF v_pt IS NULL AND v_ref IS NULL AND v_note IS NULL THEN
    v_row_note := 'Stripe';
  ELSE
    v_row_note := v_note;
  END IF;

  SELECT COALESCE(MAX(sequence_order), -1) + 1 INTO v_next_order
  FROM public.jobs_ledger_payments
  WHERE job_id = v_invoice.job_id;

  INSERT INTO public.jobs_ledger_payments (
    job_id,
    amount,
    sequence_order,
    paid_on,
    note,
    invoice_id,
    payment_type,
    reference_number
  )
  VALUES (
    v_invoice.job_id,
    v_remaining,
    v_next_order,
    v_paid_on,
    v_row_note,
    p_invoice_id,
    v_pt,
    v_ref
  );

  UPDATE public.jobs_ledger
  SET payments_made = COALESCE(payments_made, 0) + v_remaining,
      status = CASE
        WHEN COALESCE(revenue, 0) <= COALESCE(payments_made, 0) + v_remaining THEN 'paid'
        ELSE status
      END,
      updated_at = NOW()
  WHERE id = v_invoice.job_id;

  UPDATE public.jobs_ledger_invoices
  SET status = 'paid'
  WHERE id = p_invoice_id;

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION "public"."mark_invoice_paid_from_stripe"("p_invoice_id" "uuid", "p_payment_type" "text", "p_reference_number" "text", "p_paid_on" "date", "p_internal_note" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "mark_invoice_paid_from_stripe"("p_invoice_id" "uuid", "p_payment_type" "text", "p_reference_number" "text", "p_paid_on" "date", "p_internal_note" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."mark_invoice_paid_from_stripe"("p_invoice_id" "uuid", "p_payment_type" "text", "p_reference_number" "text", "p_paid_on" "date", "p_internal_note" "text") IS 'Marks invoice paid (Stripe webhook). Optional OOB metadata when user recorded payment off-Stripe; else note defaults to Stripe.';


