-- Name: FUNCTION "master_adopted_current_user"("master_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."master_adopted_current_user"("master_user_id" "uuid") IS 'Checks if the given master has adopted the current user (as assistant or primary). Uses SECURITY DEFINER to bypass RLS and avoid recursion.';


--
-- Name: master_shared_current_user("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."master_shared_current_user"("sharing_master_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.master_shares ms
    WHERE ms.sharing_master_id = master_shared_current_user.sharing_master_id
      AND ms.viewing_master_id = auth.uid()
  );
$$;


ALTER FUNCTION "public"."master_shared_current_user"("sharing_master_id" "uuid") OWNER TO "postgres";

