-- Name: mercury_debit_card_id_from_raw("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mercury_debit_card_id_from_raw"("p_raw" "jsonb") RETURNS "uuid"
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    AS $_$
  SELECT CASE
    WHEN p_raw IS NULL THEN NULL
    WHEN v IS NULL OR v = '' OR v !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[1-8][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$' THEN NULL
    ELSE v::uuid
  END
  FROM (
    SELECT lower(trim(both FROM COALESCE(
      NULLIF(trim(both FROM p_raw #>> '{details,debitCardInfo,id}'), ''),
      NULLIF(trim(both FROM p_raw #>> '{debitCardInfo,id}'), '')
    ))) AS v
  ) x
$_$;


ALTER FUNCTION "public"."mercury_debit_card_id_from_raw"("p_raw" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "mercury_debit_card_id_from_raw"("p_raw" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."mercury_debit_card_id_from_raw"("p_raw" "jsonb") IS 'Resolves Mercury debit card id from raw JSON (details.debitCardInfo.id or debitCardInfo.id); mirrors app mercuryDebitCardIdFromRaw.';


--
-- Name: mercury_drag_sort_labels_guard_system_fields(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mercury_drag_sort_labels_guard_system_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if old.is_system_default
     and (
       new.default_key is distinct from old.default_key
       or new.is_system_default is distinct from old.is_system_default
     )
  then
    raise exception 'Built-in category identity (default_key) cannot be changed'
      using errcode = 'check_violation';
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."mercury_drag_sort_labels_guard_system_fields"() OWNER TO "postgres";

--
-- Name: mercury_transactions_apply_debit_card_auto_attribution(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mercury_transactions_apply_debit_card_auto_attribution"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_card uuid;
  v_user_id uuid;
BEGIN
  v_card := public.mercury_debit_card_id_from_raw(NEW.raw);
  IF v_card IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT l.auto_assign_user_id INTO v_user_id
  FROM public.mercury_debit_card_user_links l
  WHERE l.mercury_debit_card_id = v_card;

  IF v_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.mercury_transaction_attributions a
    WHERE a.mercury_transaction_id = NEW.id
      AND (a.user_id IS NOT NULL OR a.person_id IS NOT NULL)
  ) THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.mercury_transaction_attributions (mercury_transaction_id, person_id, user_id)
  VALUES (NEW.id, NULL, v_user_id)
  ON CONFLICT (mercury_transaction_id) DO UPDATE
  SET user_id = EXCLUDED.user_id
  WHERE public.mercury_transaction_attributions.user_id IS NULL
    AND public.mercury_transaction_attributions.person_id IS NULL;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."mercury_transactions_apply_debit_card_auto_attribution"() OWNER TO "postgres";

--
-- Name: FUNCTION "mercury_transactions_apply_debit_card_auto_attribution"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."mercury_transactions_apply_debit_card_auto_attribution"() IS 'Fills mercury_transaction_attributions (user_id) from mercury_debit_card_user_links when unattributed.';


--
-- Name: merge_customers("uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."merge_customers"("p_survivor" "uuid", "p_victim" "uuid", "p_field_choices" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_survivor public.customers%ROWTYPE;
  v_victim public.customers%ROWTYPE;
  v_src_name text;
  v_src_address text;
  v_src_contact jsonb;
  v_src_type text;
  v_src_date_met date;
  v_src_master uuid;
  v_src_google_drive_link text;
  v_src_job_pictures_link text;
  v_survivor_stripe boolean;
  v_victim_stripe boolean;
  v_choice text;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;
  IF p_survivor IS NULL OR p_victim IS NULL OR p_survivor = p_victim THEN
    RAISE EXCEPTION 'Invalid customer pair';
  END IF;

  SELECT * INTO v_survivor FROM public.customers WHERE id = p_survivor FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Survivor customer not found';
  END IF;
  SELECT * INTO v_victim FROM public.customers WHERE id = p_victim FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Victim customer not found';
  END IF;

  PERFORM public.assert_caller_can_merge_customer_pair(v_survivor.master_user_id, v_victim.master_user_id);

  v_survivor_stripe := v_survivor.stripe_customer_id IS NOT NULL AND trim(v_survivor.stripe_customer_id) <> '';
  v_victim_stripe := v_victim.stripe_customer_id IS NOT NULL AND trim(v_victim.stripe_customer_id) <> '';
  IF v_survivor_stripe AND v_victim_stripe
     AND trim(v_survivor.stripe_customer_id) IS DISTINCT FROM trim(v_victim.stripe_customer_id) THEN
    RAISE EXCEPTION 'Both customers have different Stripe customer ids; resolve in Stripe before merging';
  END IF;

  v_choice := lower(coalesce(p_field_choices->>'name', 'survivor'));
  IF v_choice = 'victim' THEN v_src_name := v_victim.name; ELSE v_src_name := v_survivor.name; END IF;

  v_choice := lower(coalesce(p_field_choices->>'address', 'survivor'));
  IF v_choice = 'victim' THEN v_src_address := v_victim.address; ELSE v_src_address := v_survivor.address; END IF;

  v_choice := lower(coalesce(p_field_choices->>'contact_info', 'survivor'));
  IF v_choice = 'victim' THEN
    v_src_contact := to_jsonb(v_victim.contact_info);
  ELSE
    v_src_contact := to_jsonb(v_survivor.contact_info);
  END IF;

  v_choice := lower(coalesce(p_field_choices->>'customer_type', 'survivor'));
  IF v_choice = 'victim' THEN v_src_type := v_victim.customer_type; ELSE v_src_type := v_survivor.customer_type; END IF;

  v_choice := lower(coalesce(p_field_choices->>'date_met', 'survivor'));
  IF v_choice = 'victim' THEN v_src_date_met := v_victim.date_met; ELSE v_src_date_met := v_survivor.date_met; END IF;

  v_choice := lower(coalesce(p_field_choices->>'master_user_id', 'survivor'));
  IF v_choice = 'victim' THEN v_src_master := v_victim.master_user_id; ELSE v_src_master := v_survivor.master_user_id; END IF;

  v_choice := lower(coalesce(p_field_choices->>'google_drive_link', 'survivor'));
  IF v_choice = 'victim' THEN v_src_google_drive_link := v_victim.google_drive_link; ELSE v_src_google_drive_link := v_survivor.google_drive_link; END IF;

  v_choice := lower(coalesce(p_field_choices->>'job_pictures_link', 'survivor'));
  IF v_choice = 'victim' THEN v_src_job_pictures_link := v_victim.job_pictures_link; ELSE v_src_job_pictures_link := v_survivor.job_pictures_link; END IF;

  UPDATE public.bids SET customer_id = p_survivor WHERE customer_id = p_victim;
  UPDATE public.jobs_ledger SET customer_id = p_survivor WHERE customer_id = p_victim;
  UPDATE public.estimates SET customer_id = p_survivor WHERE customer_id = p_victim;
  UPDATE public.projects SET customer_id = p_survivor WHERE customer_id = p_victim;
  UPDATE public.customer_contacts SET customer_id = p_survivor WHERE customer_id = p_victim;
  UPDATE public.customer_contact_persons SET customer_id = p_survivor WHERE customer_id = p_victim;

  UPDATE public.customers
  SET
    name = v_src_name,
    address = v_src_address,
    contact_info = v_src_contact,
    customer_type = v_src_type,
    date_met = v_src_date_met,
    master_user_id = v_src_master,
    google_drive_link = v_src_google_drive_link,
    job_pictures_link = v_src_job_pictures_link,
    stripe_customer_id = CASE
      WHEN v_survivor_stripe THEN v_survivor.stripe_customer_id
      WHEN v_victim_stripe AND NOT v_survivor_stripe THEN v_victim.stripe_customer_id
      ELSE v_survivor.stripe_customer_id
    END,
    updated_at = now()
  WHERE id = p_survivor;

  DELETE FROM public.customers WHERE id = p_victim;

  RETURN jsonb_build_object(
    'survivor_id', p_survivor,
    'removed_id', p_victim
  );
END;
$$;


ALTER FUNCTION "public"."merge_customers"("p_survivor" "uuid", "p_victim" "uuid", "p_field_choices" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "merge_customers"("p_survivor" "uuid", "p_victim" "uuid", "p_field_choices" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."merge_customers"("p_survivor" "uuid", "p_victim" "uuid", "p_field_choices" "jsonb") IS 'Atomically merge victim into survivor; p_field_choices keys name, address, contact_info, customer_type, date_met, master_user_id, google_drive_link, job_pictures_link with values survivor|victim.';


--
-- Name: migrate_job_ledger_costs_and_delete("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."migrate_job_ledger_costs_and_delete"("p_from" "uuid", "p_to" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  r RECORD;
  v_to_amt numeric(18, 4);
  v_to_pct numeric(5, 2);
  v_sum_pct numeric(5, 2);
  v_new jsonb;
  v_blocked_reason text;
  v_from_master uuid;
  v_to_master uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'code', 'not_authenticated', 'error', 'Not authenticated');
  END IF;

  IF p_from IS NULL OR p_to IS NULL OR p_from = p_to THEN
    RETURN jsonb_build_object('ok', false, 'code', 'invalid_args', 'error', 'Invalid source or target job');
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.jobs_ledger WHERE id = p_from)
     OR NOT EXISTS (SELECT 1 FROM public.jobs_ledger WHERE id = p_to) THEN
    RETURN jsonb_build_object('ok', false, 'code', 'not_found', 'error', 'Job not found');
  END IF;

  -- Same visibility as "Devs, masters, assistants can delete jobs ledger" (20260228140000_assistants_delete_jobs_ledger.sql)
  IF NOT (
    EXISTS (
      SELECT 1 FROM public.users
      WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant')
    )
    AND EXISTS (
      SELECT 1 FROM public.jobs_ledger jl
      WHERE jl.id = p_from
      AND (
        jl.master_user_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = jl.master_user_id)
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = jl.master_user_id AND assistant_id = auth.uid())
        OR public.assistants_share_master(auth.uid(), jl.master_user_id)
      )
    )
    AND EXISTS (
      SELECT 1 FROM public.jobs_ledger jl
      WHERE jl.id = p_to
      AND (
        jl.master_user_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = jl.master_user_id)
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = jl.master_user_id AND assistant_id = auth.uid())
        OR public.assistants_share_master(auth.uid(), jl.master_user_id)
      )
    )
  ) THEN
    RETURN jsonb_build_object('ok', false, 'code', 'not_authorized', 'error', 'Not authorized to migrate these jobs');
  END IF;

  SELECT jl.master_user_id INTO v_from_master FROM public.jobs_ledger jl WHERE jl.id = p_from;
  SELECT jl.master_user_id INTO v_to_master FROM public.jobs_ledger jl WHERE jl.id = p_to;

  -- Billing guard on source: do not bypass invoices, payments, collect-payment flows, or advanced job billing status.
  SELECT CASE
    WHEN (jl.status IS DISTINCT FROM 'working' AND jl.status IS DISTINCT FROM 'ready_to_bill') THEN
      'Job billing status must be Working or Ready to bill before migrate-delete.'
    WHEN COALESCE(jl.payments_made, 0) <> 0 THEN 'Clear or resolve recorded payments on this job before migrate-delete.'
    WHEN EXISTS (SELECT 1 FROM public.jobs_ledger_invoices i WHERE i.job_id = p_from) THEN 'Remove or resolve invoices on this job before migrate-delete.'
    WHEN EXISTS (SELECT 1 FROM public.jobs_ledger_payments p WHERE p.job_id = p_from) THEN 'Remove or resolve payments on this job before migrate-delete.'
    WHEN EXISTS (SELECT 1 FROM public.job_collect_payment_flows c WHERE c.job_id = p_from) THEN 'Finish or cancel the in-app collect payment flow for this job before migrate-delete.'
    ELSE NULL
  END INTO v_blocked_reason
  FROM public.jobs_ledger jl
  WHERE jl.id = p_from;

  IF v_blocked_reason IS NOT NULL THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'billing_blocked',
      'error', v_blocked_reason
    );
  END IF;

  BEGIN
    PERFORM 1 FROM public.jobs_ledger WHERE id = p_from FOR UPDATE;
    PERFORM 1 FROM public.jobs_ledger WHERE id = p_to FOR UPDATE;

    -- Mercury splits: UNIQUE (mercury_transaction_id, job_id) — merge amounts into target when both exist.
    FOR r IN
      SELECT id, mercury_transaction_id, amount
      FROM public.mercury_transaction_job_allocations
      WHERE job_id = p_from
    LOOP
      SELECT m.amount INTO v_to_amt
      FROM public.mercury_transaction_job_allocations m
      WHERE m.mercury_transaction_id = r.mercury_transaction_id AND m.job_id = p_to;

      IF v_to_amt IS NULL THEN
        UPDATE public.mercury_transaction_job_allocations
        SET job_id = p_to
        WHERE id = r.id;
      ELSE
        UPDATE public.mercury_transaction_job_allocations
        SET amount = v_to_amt + r.amount
        WHERE mercury_transaction_id = r.mercury_transaction_id AND job_id = p_to;
        DELETE FROM public.mercury_transaction_job_allocations WHERE id = r.id;
      END IF;
    END LOOP;

    -- Supply invoice allocations: PRIMARY KEY (invoice_id, job_id) — merge pct; cap at 100 per invoice line.
    FOR r IN
      SELECT invoice_id, pct
      FROM public.supply_house_invoice_job_allocations
      WHERE job_id = p_from
    LOOP
      SELECT a.pct INTO v_to_pct
      FROM public.supply_house_invoice_job_allocations a
      WHERE a.invoice_id = r.invoice_id AND a.job_id = p_to;

      IF v_to_pct IS NULL THEN
        UPDATE public.supply_house_invoice_job_allocations
        SET job_id = p_to
        WHERE invoice_id = r.invoice_id AND job_id = p_from;
      ELSE
        v_sum_pct := v_to_pct + r.pct;
        IF v_sum_pct > 100 THEN
          RETURN jsonb_build_object(
            'ok', false,
            'code', 'supply_alloc_overflow',
            'error',
            format('Merging supply invoice allocations would exceed 100%% for invoice %s.', r.invoice_id)
          );
        END IF;
        UPDATE public.supply_house_invoice_job_allocations
        SET pct = v_sum_pct
        WHERE invoice_id = r.invoice_id AND job_id = p_to;
        DELETE FROM public.supply_house_invoice_job_allocations
        WHERE invoice_id = r.invoice_id AND job_id = p_from;
      END IF;
    END LOOP;

    -- Crew grid: replace source job id with target; collapse duplicate job ids; renormalize percentages to 100.
    FOR r IN
      SELECT work_date, person_name, job_assignments
      FROM public.people_crew_jobs
      WHERE EXISTS (
        SELECT 1
        FROM jsonb_array_elements(job_assignments) AS e
        WHERE (e->>'job_id')::uuid = p_from
      )
    LOOP
      SELECT COALESCE(
        (
          WITH elems AS (
            SELECT
              CASE
                WHEN (e->>'job_id')::uuid = p_from THEN p_to
                ELSE (e->>'job_id')::uuid
              END AS jid,
              COALESCE((e->>'pct')::numeric, 0) AS pct
            FROM jsonb_array_elements(r.job_assignments) AS e
          ),
          collapsed AS (
            SELECT jid, SUM(pct) AS sp FROM elems GROUP BY jid
          ),
          tot AS (
            SELECT COALESCE(SUM(sp), 0)::numeric AS t FROM collapsed
          ),
          scaled AS (
            SELECT
              c.jid,
              CASE
                WHEN tot.t > 0 THEN ROUND((c.sp * (100.0 / tot.t))::numeric, 6)
                ELSE 0::numeric
              END AS pct
            FROM collapsed c
            CROSS JOIN tot
          )
          SELECT jsonb_agg(
            jsonb_build_object('job_id', scaled.jid::text, 'pct', scaled.pct)
            ORDER BY scaled.jid
          )
          FROM scaled
        ),
        '[]'::jsonb
      )
      INTO v_new;

      UPDATE public.people_crew_jobs
      SET job_assignments = v_new
      WHERE work_date = r.work_date AND person_name = r.person_name;
    END LOOP;

    UPDATE public.jobs_tally_parts SET job_id = p_to WHERE job_id = p_from;
    UPDATE public.jobs_ledger_materials SET job_id = p_to WHERE job_id = p_from;
    UPDATE public.clock_sessions SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.job_schedule_blocks SET job_id = p_to WHERE job_id = p_from;
    UPDATE public.jobs_ledger_fixtures SET job_id = p_to WHERE job_id = p_from;
    UPDATE public.reports SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.inspections SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.jobs_ledger_thread_notes SET job_id = p_to WHERE job_id = p_from;
    UPDATE public.job_status_events SET job_id = p_to WHERE job_id = p_from;
    UPDATE public.estimates SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.estimator_requests SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.dispatch_requests SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.stripe_oob_payment_reverts SET job_id = p_to WHERE job_id = p_from;

    UPDATE public.salary_work_schedule_templates
    SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.salary_work_schedule_templates
    SET segment_b_job_ledger_id = p_to WHERE segment_b_job_ledger_id = p_from;

    UPDATE public.salary_work_schedule_day_overrides
    SET job_ledger_id = p_to WHERE job_ledger_id = p_from;
    UPDATE public.salary_work_schedule_day_overrides
    SET segment_b_job_ledger_id = p_to WHERE segment_b_job_ledger_id = p_from;

    INSERT INTO public.jobs_ledger_team_members (job_id, user_id)
    SELECT p_to, jtm.user_id
    FROM public.jobs_ledger_team_members jtm
    WHERE jtm.job_id = p_from
    ON CONFLICT (job_id, user_id) DO NOTHING;

    DELETE FROM public.jobs_ledger_team_members WHERE job_id = p_from;

    -- Add source job revenue to target job total before removing source row.
    UPDATE public.jobs_ledger AS jl_to
    SET revenue = COALESCE(jl_to.revenue, 0) + COALESCE(jl_from.revenue, 0)
    FROM public.jobs_ledger AS jl_from
    WHERE jl_to.id = p_to AND jl_from.id = p_from;

    DELETE FROM public.common_jobs WHERE job_id = p_from;

    DELETE FROM public.jobs_ledger WHERE id = p_from;

    RETURN jsonb_build_object('ok', true, 'from_master_user_id', v_from_master, 'to_master_user_id', v_to_master);
  EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'code', 'migrate_failed', 'error', SQLERRM);
  END;
END;
$$;


ALTER FUNCTION "public"."migrate_job_ledger_costs_and_delete"("p_from" "uuid", "p_to" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "migrate_job_ledger_costs_and_delete"("p_from" "uuid", "p_to" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."migrate_job_ledger_costs_and_delete"("p_from" "uuid", "p_to" "uuid") IS 'Repoints labor/parts/materials-related rows from source jobs_ledger to target, merges Mercury and supply allocations and crew JSON, adds source revenue to target revenue, then deletes the source job. Source job must be working or ready_to_bill. Blocked when source has billing artifacts.';


--
-- Name: move_job_schedule_block_group("uuid", "uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."move_job_schedule_block_group"("p_job_id" "uuid", "p_shared_block_group_id" "uuid", "p_new_work_date" "date") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  PERFORM id
  FROM public.job_schedule_blocks
  WHERE job_id = p_job_id
    AND shared_block_group_id = p_shared_block_group_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'No schedule blocks found for that linked group.';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.job_schedule_blocks L
    WHERE L.job_id = p_job_id
      AND L.shared_block_group_id = p_shared_block_group_id
      AND L.work_date IS DISTINCT FROM p_new_work_date
  ) THEN
    RETURN;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.job_schedule_blocks L
    INNER JOIN public.job_schedule_blocks O
      ON O.assignee_user_id = L.assignee_user_id
     AND O.work_date = p_new_work_date
     AND O.id NOT IN (
       SELECT id
       FROM public.job_schedule_blocks
       WHERE job_id = p_job_id
         AND shared_block_group_id = p_shared_block_group_id
     )
     AND L.time_start < O.time_end
     AND O.time_start < L.time_end
    WHERE L.job_id = p_job_id
      AND L.shared_block_group_id = p_shared_block_group_id
  ) THEN
    RAISE EXCEPTION 'That time overlaps another block for this person on this day.';
  END IF;

  UPDATE public.job_schedule_blocks
  SET work_date = p_new_work_date
  WHERE job_id = p_job_id
    AND shared_block_group_id = p_shared_block_group_id;
END;
$$;


ALTER FUNCTION "public"."move_job_schedule_block_group"("p_job_id" "uuid", "p_shared_block_group_id" "uuid", "p_new_work_date" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "move_job_schedule_block_group"("p_job_id" "uuid", "p_shared_block_group_id" "uuid", "p_new_work_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."move_job_schedule_block_group"("p_job_id" "uuid", "p_shared_block_group_id" "uuid", "p_new_work_date" "date") IS 'Moves every leg of a linked job schedule block group to p_new_work_date; rejects if any assignee would overlap another block on that day.';


--
-- Name: next_numeric_hcp_suggestion_for_master("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."next_numeric_hcp_suggestion_for_master"("p_master_user_id" "uuid") RETURNS "text"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $_$
  SELECT (COALESCE(MAX(CAST(trim(jl.hcp_number) AS bigint)), 0) + 1)::text
  FROM public.jobs_ledger jl
  WHERE jl.master_user_id = p_master_user_id
    AND trim(COALESCE(jl.hcp_number, '')) ~ '^[0-9]+$';
$_$;


