--
-- Name: pay_staff_bulk_insert_user_time_off("uuid"[], "date", "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pay_staff_bulk_insert_user_time_off"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date", "p_note" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_today date;
  v_should_sync boolean;
  v_inserted jsonb := '[]'::jsonb;
  v_failed jsonb := '[]'::jsonb;
  v_sync_failed jsonb := '[]'::jsonb;
  v_note text;
  v_row jsonb;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'not authenticated' USING ERRCODE = '42501';
  END IF;

  IF NOT (
    public.is_dev()
    OR public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant()
  ) THEN
    RAISE EXCEPTION 'not authorized' USING ERRCODE = '42501';
  END IF;

  IF p_start_date IS NULL OR p_end_date IS NULL OR p_end_date < p_start_date THEN
    RETURN jsonb_build_object(
      'error', 'invalid date range',
      'inserted', '[]'::jsonb,
      'failed', '[]'::jsonb,
      'sync_failed', '[]'::jsonb
    );
  END IF;

  IF p_user_ids IS NULL OR coalesce(array_length(p_user_ids, 1), 0) = 0 THEN
    RETURN jsonb_build_object(
      'error', 'no user ids',
      'inserted', '[]'::jsonb,
      'failed', '[]'::jsonb,
      'sync_failed', '[]'::jsonb
    );
  END IF;

  IF array_length(p_user_ids, 1) > 200 THEN
    RETURN jsonb_build_object(
      'error', 'too many user ids (max 200)',
      'inserted', '[]'::jsonb,
      'failed', '[]'::jsonb,
      'sync_failed', '[]'::jsonb
    );
  END IF;

  v_today := (timezone('America/Denver', now()))::date;
  v_should_sync := v_today BETWEEN p_start_date AND p_end_date;
  v_note := NULLIF(trim(COALESCE(p_note, '')), '');

  FOR v_uid IN SELECT DISTINCT unnest(p_user_ids)
  LOOP
    IF NOT public.salary_schedule_staff_or_self_target(v_uid) THEN
      v_failed := v_failed || jsonb_build_array(
        jsonb_build_object('user_id', v_uid::text, 'message', 'not authorized for this user')
      );
      CONTINUE;
    END IF;

    v_row := public._pay_staff_bulk_insert_user_time_off_row(
      v_uid,
      p_start_date,
      p_end_date,
      v_note,
      v_today,
      v_should_sync
    );

    IF coalesce(v_row->>'ok', '') = 'true' THEN
      v_inserted := v_inserted || jsonb_build_array(to_jsonb(v_uid::text));
      IF v_row ? 'sync_warning' AND v_row->>'sync_warning' IS NOT NULL AND length(v_row->>'sync_warning') > 0 THEN
        v_sync_failed := v_sync_failed || jsonb_build_array(
          jsonb_build_object('user_id', v_uid::text, 'message', v_row->>'sync_warning')
        );
      END IF;
    ELSE
      v_failed := v_failed || jsonb_build_array(
        jsonb_build_object(
          'user_id',
          v_uid::text,
          'message',
          coalesce(v_row->>'message', 'insert failed')
        )
      );
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'inserted', v_inserted,
    'failed', v_failed,
    'sync_failed', v_sync_failed
  );
END;
$$;


ALTER FUNCTION "public"."pay_staff_bulk_insert_user_time_off"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date", "p_note" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "pay_staff_bulk_insert_user_time_off"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date", "p_note" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."pay_staff_bulk_insert_user_time_off"("p_user_ids" "uuid"[], "p_start_date" "date", "p_end_date" "date", "p_note" "text") IS 'Pay staff: best-effort bulk unpaid time off inserts; per-user helper; syncs salary sessions for Denver today when range covers today.';


--
-- Name: pay_staff_clear_salary_schedule_by_person_name("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pay_staff_clear_salary_schedule_by_person_name"("p_person_name" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_today date;
  v_caller_is_superintendent boolean;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'not_authenticated',
      'message', 'Not signed in.'
    );
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.users u WHERE u.id = auth.uid() AND u.role = 'superintendent'
  ) INTO v_caller_is_superintendent;

  IF NOT (
    public.is_dev()
    OR public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant()
    OR v_caller_is_superintendent
  ) THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'not_authorized',
      'message', 'Not authorized.'
    );
  END IF;

  IF p_person_name IS NULL OR btrim(p_person_name) = '' THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'invalid_name',
      'message', 'Person name is required.'
    );
  END IF;

  SELECT u.id INTO v_uid
  FROM public.users u
  WHERE btrim(u.name) = btrim(p_person_name)
  ORDER BY u.id
  LIMIT 1;

  IF v_uid IS NULL THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'no_login_user',
      'message',
      'No user account matches this pay name. Align users.name with people_pay_config.person_name, or remove the salaried workday in Settings.'
    );
  END IF;

  IF NOT (
    public.salary_schedule_staff_or_self_target(v_uid)
    OR (
      v_caller_is_superintendent
      AND public.is_team_lead_for_member(auth.uid(), v_uid)
    )
  ) THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'not_authorized_target',
      'message', 'Not authorized to clear schedule for this person.'
    );
  END IF;

  DELETE FROM public.salary_work_schedule_templates WHERE user_id = v_uid;
  DELETE FROM public.salary_work_schedule_day_overrides WHERE user_id = v_uid;

  v_today := (timezone('America/Denver', now()))::date;
  PERFORM public.sync_salary_clock_sessions_for_user_day(v_uid, v_today);

  RETURN jsonb_build_object('ok', true, 'user_id', v_uid::text);
END;
$$;


ALTER FUNCTION "public"."pay_staff_clear_salary_schedule_by_person_name"("p_person_name" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "pay_staff_clear_salary_schedule_by_person_name"("p_person_name" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."pay_staff_clear_salary_schedule_by_person_name"("p_person_name" "text") IS 'Pay staff / team-lead superintendent: delete salary_work_schedule_templates and salary_work_schedule_day_overrides for the user whose users.name matches p_person_name (trim), then sync_salary_clock_sessions_for_user_day for Denver today.';


--
-- Name: pay_staff_remove_not_coming_in_for_user_day("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pay_staff_remove_not_coming_in_for_user_day"("p_user_id" "uuid", "p_work_date" "date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_deleted integer := 0;
  v_today date;
  v_should_sync boolean;
  v_sync_err text;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'not authenticated' USING ERRCODE = '42501';
  END IF;

  IF NOT (
    public.is_dev()
    OR public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant()
  ) THEN
    RAISE EXCEPTION 'not authorized' USING ERRCODE = '42501';
  END IF;

  IF p_user_id IS NULL OR p_work_date IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'message', 'invalid arguments', 'deleted', 0);
  END IF;

  IF NOT public.salary_schedule_staff_or_self_target(p_user_id) THEN
    RAISE EXCEPTION 'not authorized for this user' USING ERRCODE = '42501';
  END IF;

  WITH d AS (
    DELETE FROM public.user_time_off
    WHERE user_id = p_user_id
      AND start_date = p_work_date
      AND end_date = p_work_date
      AND kind = 'unpaid'
      AND note = 'Not coming in'
    RETURNING 1
  )
  SELECT count(*)::int INTO v_deleted FROM d;

  IF v_deleted = 0 THEN
    RETURN jsonb_build_object('ok', true, 'deleted', 0);
  END IF;

  v_today := (timezone('America/Denver', now()))::date;
  v_should_sync := v_today = p_work_date;

  IF v_should_sync THEN
    BEGIN
      PERFORM public.sync_salary_clock_sessions_for_user_day(p_user_id, p_work_date);
    EXCEPTION
      WHEN OTHERS THEN
        v_sync_err := SQLERRM;
    END;
  END IF;

  IF v_sync_err IS NOT NULL THEN
    RETURN jsonb_build_object('ok', true, 'deleted', v_deleted, 'sync_warning', v_sync_err);
  END IF;
  RETURN jsonb_build_object('ok', true, 'deleted', v_deleted);
END;
$$;


ALTER FUNCTION "public"."pay_staff_remove_not_coming_in_for_user_day"("p_user_id" "uuid", "p_work_date" "date") OWNER TO "postgres";

