COMMENT ON FUNCTION "public"."pay_staff_remove_not_coming_in_for_user_day"("p_user_id" "uuid", "p_work_date" "date") IS 'Pay staff: delete the single-day unpaid "Not coming in" user_time_off entry created from Schedule Dispatch, then resync salary sessions for the day.';


--
-- Name: pay_stub_additional_lines_after_validate_payments_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pay_stub_additional_lines_after_validate_payments_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.validate_pay_stub_payments_vs_net(OLD.pay_stub_id);
  ELSIF TG_OP = 'UPDATE' AND NEW.pay_stub_id IS DISTINCT FROM OLD.pay_stub_id THEN
    PERFORM public.validate_pay_stub_payments_vs_net(OLD.pay_stub_id);
    PERFORM public.validate_pay_stub_payments_vs_net(NEW.pay_stub_id);
  ELSE
    PERFORM public.validate_pay_stub_payments_vs_net(NEW.pay_stub_id);
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


