ALTER FUNCTION "public"."pay_stub_deductions_after_validate_payments_fn"() OWNER TO "postgres";

--
-- Name: pay_stub_deductions_enforce_gross_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pay_stub_deductions_enforce_gross_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_gross numeric;
  v_sum_excl numeric;
  v_new_total numeric;
  v_stub uuid;
BEGIN
  v_stub := COALESCE(NEW.pay_stub_id, OLD.pay_stub_id);

  SELECT gross_pay INTO v_gross FROM public.pay_stubs WHERE id = v_stub;
  IF v_gross IS NULL THEN
    RAISE EXCEPTION 'pay stub not found for pay_stub_id %', v_stub;
  END IF;

  IF TG_OP = 'INSERT' THEN
    SELECT COALESCE(SUM(amount), 0) INTO v_sum_excl
    FROM public.pay_stub_deductions
    WHERE pay_stub_id = NEW.pay_stub_id;
    v_new_total := v_sum_excl + NEW.amount;
  ELSIF TG_OP = 'UPDATE' THEN
    SELECT COALESCE(SUM(amount), 0) INTO v_sum_excl
    FROM public.pay_stub_deductions
    WHERE pay_stub_id = NEW.pay_stub_id
      AND id <> NEW.id;
    v_new_total := v_sum_excl + NEW.amount;
  ELSIF TG_OP = 'DELETE' THEN
    SELECT COALESCE(SUM(amount), 0) INTO v_sum_excl
    FROM public.pay_stub_deductions
    WHERE pay_stub_id = OLD.pay_stub_id
      AND id <> OLD.id;
    v_new_total := v_sum_excl;
  ELSE
    RETURN COALESCE(NEW, OLD);
  END IF;

  IF v_new_total > v_gross + 0.01 THEN
    RAISE EXCEPTION 'pay_stub_deductions total would exceed gross pay for stub %', v_stub;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."pay_stub_deductions_enforce_gross_fn"() OWNER TO "postgres";

--
-- Name: pay_stub_payments_enforce_total_fn(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pay_stub_payments_enforce_total_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_gross numeric;
  v_ded numeric;
  v_add numeric;
  v_net numeric;
  v_sum_excl numeric;
BEGIN
  SELECT gross_pay INTO v_gross FROM public.pay_stubs WHERE id = NEW.pay_stub_id;
  IF v_gross IS NULL THEN
    RAISE EXCEPTION 'pay stub not found for pay_stub_id %', NEW.pay_stub_id;
  END IF;

  SELECT COALESCE(SUM(amount), 0) INTO v_ded FROM public.pay_stub_deductions WHERE pay_stub_id = NEW.pay_stub_id;
  SELECT COALESCE(SUM(line_total), 0) INTO v_add FROM public.pay_stub_additional_lines WHERE pay_stub_id = NEW.pay_stub_id;
  v_net := v_gross - v_ded + v_add;

  IF TG_OP = 'INSERT' THEN
    SELECT COALESCE(SUM(amount), 0) INTO v_sum_excl
    FROM public.pay_stub_payments
    WHERE pay_stub_id = NEW.pay_stub_id;
  ELSE
    SELECT COALESCE(SUM(amount), 0) INTO v_sum_excl
    FROM public.pay_stub_payments
    WHERE pay_stub_id = NEW.pay_stub_id
      AND id <> OLD.id;
  END IF;

  IF v_sum_excl + NEW.amount > v_net + 0.01 THEN
    RAISE EXCEPTION 'pay_stub_payments total would exceed net pay for stub %', NEW.pay_stub_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."pay_stub_payments_enforce_total_fn"() OWNER TO "postgres";

--
-- Name: people_hours_subtract_approved_hours("uuid", "text", "date", numeric, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."people_hours_subtract_approved_hours"("p_user_id" "uuid", "p_person_name" "text", "p_work_date" "date", "p_hours" numeric, "p_entered_by" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_pid uuid;
  v_new numeric;
BEGIN
  IF p_hours IS NULL OR p_hours <= 0 THEN
    RETURN;
  END IF;

  v_pid := public.resolve_pay_person_id_from_clock_user(p_user_id, p_person_name);

  UPDATE public.people_hours ph
  SET hours = ph.hours - p_hours,
      entered_by = COALESCE(p_entered_by, ph.entered_by)
  WHERE ph.work_date = p_work_date
    AND (
      (v_pid IS NOT NULL AND ph.person_id = v_pid)
      OR (v_pid IS NULL AND ph.person_name = p_person_name)
    )
  RETURNING ph.hours INTO v_new;

  IF FOUND THEN
    IF v_new <= 0 THEN
      DELETE FROM public.people_hours ph2
      WHERE ph2.work_date = p_work_date
        AND (
          (v_pid IS NOT NULL AND ph2.person_id = v_pid)
          OR (v_pid IS NULL AND ph2.person_name = p_person_name)
        );
    END IF;
  END IF;
END;
$$;


