-- Name: FUNCTION "people_hours_subtract_approved_hours"("p_user_id" "uuid", "p_person_name" "text", "p_work_date" "date", "p_hours" numeric, "p_entered_by" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
