--
-- Name: prevent_bid_number_update_by_estimator_primary(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prevent_bid_number_update_by_estimator_primary"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  user_role text;
BEGIN
  IF OLD.bid_number IS DISTINCT FROM NEW.bid_number THEN
    SELECT role INTO user_role FROM users WHERE id = auth.uid();
    IF user_role IN ('estimator', 'primary') THEN
      RAISE EXCEPTION 'Only dev, master_technician, and assistant can edit bid number';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


