--
-- Name: record_estimate_public_link_view("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_estimate_public_link_view"("p_estimate_id" "uuid", "p_client_ip" "text" DEFAULT ''::"text", "p_user_agent" "text" DEFAULT ''::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ip text := NULLIF(btrim(COALESCE(p_client_ip, '')), '');
  v_ua text := NULLIF(btrim(COALESCE(p_user_agent, '')), '');
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.estimates e
    WHERE e.id = p_estimate_id AND e.status = 'sent'
  ) THEN
    RETURN;
  END IF;

  PERFORM pg_advisory_xact_lock(hashtext(p_estimate_id::text));

  IF EXISTS (
    SELECT 1 FROM public.estimate_customer_events ece
    WHERE ece.estimate_id = p_estimate_id
      AND ece.event_type = 'public_link_view'
      AND ece.occurred_at > now() - interval '5 seconds'
      AND ece.client_ip IS NOT DISTINCT FROM v_ip
      AND ece.user_agent IS NOT DISTINCT FROM v_ua
  ) THEN
    RETURN;
  END IF;

  INSERT INTO public.estimate_customer_events (
    estimate_id,
    event_type,
    source,
    client_ip,
    user_agent,
    metadata
  )
  VALUES (
    p_estimate_id,
    'public_link_view',
    'get-estimate-for-customer',
    v_ip,
    v_ua,
    '{}'::jsonb
  );
END;
$$;


ALTER FUNCTION "public"."record_estimate_public_link_view"("p_estimate_id" "uuid", "p_client_ip" "text", "p_user_agent" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "record_estimate_public_link_view"("p_estimate_id" "uuid", "p_client_ip" "text", "p_user_agent" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."record_estimate_public_link_view"("p_estimate_id" "uuid", "p_client_ip" "text", "p_user_agent" "text") IS 'Appends public_link_view when customer GET loads sent quote; skips duplicate same IP/UA within 5s; Edge service_role only.';


--
-- Name: record_ncns_and_reject_sessions_for_day("uuid", "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_ncns_and_reject_sessions_for_day"("p_subject_user_id" "uuid", "p_work_date" "date", "p_details" "text" DEFAULT NULL::"text") RETURNS TABLE("rejected_count" integer, "had_approved_sessions" boolean, "error_message" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_pay boolean;
  v_count int;
  v_had_approved boolean;
  v_has_open boolean;
  v_bad_name boolean;
  v_rejected int := 0;
  v_session RECORD;
  v_hours numeric;
BEGIN
  v_pay :=
    public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant();

  IF NOT v_pay THEN
    IF NOT public.is_team_lead_for_member(auth.uid(), p_subject_user_id) THEN
      RETURN QUERY SELECT 0, false, 'Access denied'::text;
      RETURN;
    END IF;
  END IF;

  SELECT
    COUNT(*)::int,
    COALESCE(BOOL_OR(cs.approved_at IS NOT NULL), false),
    COALESCE(BOOL_OR(cs.clocked_out_at IS NULL), false),
    COALESCE(
      BOOL_OR(
        trim(u.name) IS NULL
        OR trim(u.name) = ''
      ),
      false
    )
  INTO v_count, v_had_approved, v_has_open, v_bad_name
  FROM public.clock_sessions cs
  INNER JOIN public.users u ON u.id = cs.user_id
  WHERE cs.user_id = p_subject_user_id
    AND cs.work_date = p_work_date
    AND cs.rejected_at IS NULL
    AND cs.revoked_at IS NULL;

  IF v_count IS NULL OR v_count = 0 THEN
    IF EXISTS (
      SELECT 1
      FROM public.job_schedule_blocks jsb
      WHERE jsb.assignee_user_id = p_subject_user_id
        AND jsb.work_date = p_work_date
      LIMIT 1
    ) THEN
      IF EXISTS (
        SELECT 1
        FROM public.attendance_incidents ai
        WHERE ai.subject_user_id = p_subject_user_id
          AND ai.work_date = p_work_date
          AND ai.incident_type = 'no_call_no_show'
        LIMIT 1
      ) THEN
        RETURN QUERY SELECT 0, false, 'NCNS already recorded for this day'::text;
        RETURN;
      END IF;

      INSERT INTO public.attendance_incidents (
        subject_user_id,
        work_date,
        created_by_user_id,
        metadata,
        details
      )
      VALUES (
        p_subject_user_id,
        p_work_date,
        auth.uid(),
        jsonb_build_object(
          'had_approved_sessions', false,
          'source', 'my_time_day_editor',
          'scheduled_without_clock', true,
          'rejected_session_count', 0
        ),
        NULLIF(TRIM(p_details), '')
      );

      RETURN QUERY SELECT 0, false, NULL::text;
      RETURN;
    END IF;

    RETURN QUERY SELECT 0, COALESCE(v_had_approved, false), 'No sessions or schedule for this day'::text;
    RETURN;
  END IF;

  IF v_bad_name THEN
    RETURN QUERY SELECT 0, v_had_approved, 'User has no name for one or more sessions'::text;
    RETURN;
  END IF;

  IF v_has_open THEN
    RETURN QUERY SELECT 0, v_had_approved, 'Clock out all sessions before recording NCNS'::text;
    RETURN;
  END IF;

  FOR v_session IN
    SELECT
      cs.id,
      cs.user_id,
      cs.clocked_in_at,
      cs.clocked_out_at,
      cs.work_date,
      cs.approved_at,
      trim(u.name) AS person_name,
      cs.job_ledger_id,
      cs.bid_id
    FROM public.clock_sessions cs
    INNER JOIN public.users u ON u.id = cs.user_id
    WHERE cs.user_id = p_subject_user_id
      AND cs.work_date = p_work_date
      AND cs.rejected_at IS NULL
      AND cs.revoked_at IS NULL
      AND cs.clocked_out_at IS NOT NULL
    ORDER BY cs.clocked_in_at ASC, cs.id ASC
  LOOP
    IF NOT v_pay THEN
      IF NOT public.is_team_lead_for_member(auth.uid(), v_session.user_id) THEN
        RETURN QUERY SELECT 0, v_had_approved, 'Access denied'::text;
        RETURN;
      END IF;
    END IF;

    v_hours :=
      EXTRACT(EPOCH FROM (v_session.clocked_out_at - v_session.clocked_in_at)) / 3600.0;

    IF v_session.approved_at IS NOT NULL AND v_hours > 0 THEN
      PERFORM public.people_hours_subtract_approved_hours(
        v_session.user_id,
        v_session.person_name,
        v_session.work_date,
        v_hours,
        auth.uid()
      );
    END IF;

    UPDATE public.clock_sessions
    SET
      approved_at = NULL,
      approved_by = NULL,
      revoked_at = NULL,
      revoked_by = NULL,
      rejected_at = NOW(),
      rejected_by = auth.uid()
    WHERE id = v_session.id;

    v_rejected := v_rejected + 1;

    IF v_session.job_ledger_id IS NOT NULL THEN
      PERFORM public.sync_crew_jobs_from_clock(v_session.person_name, v_session.work_date);
    END IF;
    IF v_session.bid_id IS NOT NULL THEN
      PERFORM public.sync_crew_bids_from_clock(v_session.person_name, v_session.work_date);
    END IF;
  END LOOP;

  INSERT INTO public.attendance_incidents (
    subject_user_id,
    work_date,
    created_by_user_id,
    metadata,
    details
  )
  VALUES (
    p_subject_user_id,
    p_work_date,
    auth.uid(),
    jsonb_build_object(
      'had_approved_sessions', v_had_approved,
      'source', 'my_time_day_editor'
    ),
    NULLIF(TRIM(p_details), '')
  );

  RETURN QUERY SELECT v_rejected, v_had_approved, NULL::text;
END;
$$;


ALTER FUNCTION "public"."record_ncns_and_reject_sessions_for_day"("p_subject_user_id" "uuid", "p_work_date" "date", "p_details" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "record_ncns_and_reject_sessions_for_day"("p_subject_user_id" "uuid", "p_work_date" "date", "p_details" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."record_ncns_and_reject_sessions_for_day"("p_subject_user_id" "uuid", "p_work_date" "date", "p_details" "text") IS 'Record NCNS incident and reject all closed sessions for user/day; unwinds people_hours for approved sessions (person_id-aware).';


--
-- Name: recurring_job_report_schedules_check_days_of_week(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."recurring_job_report_schedules_check_days_of_week"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.days_of_week IS NULL THEN
    RAISE EXCEPTION 'recurring_job_report_schedules.days_of_week must not be null';
  END IF;
  IF cardinality(NEW.days_of_week) NOT BETWEEN 1 AND 7 THEN
    RAISE EXCEPTION 'recurring_job_report_schedules.days_of_week must list 1 to 7 days';
  END IF;
  IF EXISTS (SELECT 1 FROM unnest(NEW.days_of_week) AS x(v) WHERE v < 0 OR v > 6) THEN
    RAISE EXCEPTION 'recurring_job_report_schedules.days_of_week must use 0=Sun … 6=Sat';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."recurring_job_report_schedules_check_days_of_week"() OWNER TO "postgres";

--
-- Name: refresh_jobs_ledger_last_work_date("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."refresh_jobs_ledger_last_work_date"("p_job_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_max date;
BEGIN
  IF p_job_id IS NULL THEN
    RETURN;
  END IF;

  SELECT MAX(cs.work_date) INTO v_max
  FROM public.clock_sessions cs
  WHERE cs.job_ledger_id = p_job_id
    AND cs.approved_at IS NOT NULL
    AND cs.rejected_at IS NULL
    AND cs.revoked_at IS NULL;

  UPDATE public.jobs_ledger jl
  SET last_work_date = v_max
  WHERE jl.id = p_job_id;
END;
$$;


ALTER FUNCTION "public"."refresh_jobs_ledger_last_work_date"("p_job_id" "uuid") OWNER TO "postgres";

