-- Name: FUNCTION "refresh_jobs_ledger_last_work_date"("p_job_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."refresh_jobs_ledger_last_work_date"("p_job_id" "uuid") IS 'Definer: recompute jobs_ledger.last_work_date from qualifying clock_sessions for one job.';


--
-- Name: remove_jobs_ledger_payment_and_reconcile("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."remove_jobs_ledger_payment_and_reconcile"("p_payment_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_job_id uuid;
  v_invoice_id uuid;
  v_inv_amount numeric;
  v_stripe_trim text;
  v_sum numeric;
  v_applied numeric;
  v_rev numeric;
  v_pm numeric;
  v_job_status text;
  v_status_rpc jsonb;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('error', 'Not authenticated');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RETURN jsonb_build_object('error', 'Not authorized');
  END IF;

  SELECT p.job_id, p.invoice_id
  INTO v_job_id, v_invoice_id
  FROM public.jobs_ledger_payments p
  WHERE p.id = p_payment_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Payment not found');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.jobs_ledger j
    WHERE j.id = v_job_id
      AND (
        j.master_user_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = auth.uid() AND assistant_id = j.master_user_id
        )
        OR EXISTS (
          SELECT 1 FROM public.master_assistants
          WHERE master_id = j.master_user_id AND assistant_id = auth.uid()
        )
        OR public.assistants_share_master(auth.uid(), j.master_user_id)
      )
  ) THEN
    RETURN jsonb_build_object('error', 'Not authorized to update this job');
  END IF;

  IF v_invoice_id IS NOT NULL THEN
    SELECT
      i.amount,
      coalesce(nullif(trim(i.stripe_invoice_id), ''), '')
    INTO v_inv_amount, v_stripe_trim
    FROM public.jobs_ledger_invoices i
    WHERE i.id = v_invoice_id;

    IF NOT FOUND THEN
      RETURN jsonb_build_object('error', 'Invoice not found');
    END IF;

    IF length(v_stripe_trim) > 0 THEN
      RETURN jsonb_build_object(
        'error',
        'Stripe-hosted invoice payments cannot be removed here; use Stripe reversal flows.'
      );
    END IF;
  END IF;

  DELETE FROM public.jobs_ledger_payments
  WHERE id = p_payment_id AND job_id = v_job_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Payment could not be deleted');
  END IF;

  SELECT coalesce(sum(amount), 0) INTO v_sum
  FROM public.jobs_ledger_payments
  WHERE job_id = v_job_id;

  UPDATE public.jobs_ledger
  SET payments_made = v_sum, updated_at = now()
  WHERE id = v_job_id;

  IF v_invoice_id IS NOT NULL THEN
    SELECT coalesce(sum(amount), 0) INTO v_applied
    FROM public.jobs_ledger_payments
    WHERE invoice_id = v_invoice_id;

    IF v_applied + 0.0001 >= coalesce(v_inv_amount, 0) THEN
      UPDATE public.jobs_ledger_invoices
      SET status = 'paid'
      WHERE id = v_invoice_id AND status = 'billed';
    ELSIF v_applied + 0.0001 < coalesce(v_inv_amount, 0) THEN
      UPDATE public.jobs_ledger_invoices
      SET status = 'billed'
      WHERE id = v_invoice_id AND status = 'paid';
    END IF;
  END IF;

  SELECT jl.revenue, jl.payments_made, jl.status
  INTO v_rev, v_pm, v_job_status
  FROM public.jobs_ledger jl
  WHERE jl.id = v_job_id;

  IF coalesce(v_job_status, '') = 'paid' AND coalesce(v_rev, 0) > coalesce(v_pm, 0) + 0.01 THEN
    v_status_rpc := public.update_job_status(v_job_id, 'billed');
    IF v_status_rpc ? 'error' THEN
      RETURN jsonb_build_object(
        'ok', true,
        'warning', coalesce(v_status_rpc ->> 'error', 'Could not move job back to Billed'),
        'payments_made', v_sum
      );
    END IF;
  END IF;

  RETURN jsonb_build_object('ok', true, 'payments_made', v_sum);
END;
$$;


ALTER FUNCTION "public"."remove_jobs_ledger_payment_and_reconcile"("p_payment_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "remove_jobs_ledger_payment_and_reconcile"("p_payment_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."remove_jobs_ledger_payment_and_reconcile"("p_payment_id" "uuid") IS 'Deletes one jobs_ledger_payments row for non-Stripe-hosted invoices only; recomputes jobs_ledger.payments_made; syncs jobs_ledger_invoices paid/billed from remaining invoice-linked payments; may move job paid→billed via update_job_status. Frees Mercury allocation capacity when mercury_transaction_id was set. Roles: dev/master_technician/assistant/primary with job access.';


--
-- Name: replace_estimate_catalog_payload("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."replace_estimate_catalog_payload"("p_payload" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_payload_ids uuid[];
  v_id_total int;
  v_id_distinct int;
  r_live record;
  v_elem jsonb;
  v_idx int;
  v_id uuid;
  v_line text;
  v_desc text;
  v_qty numeric;
  v_unit int;
  v_amt int;
  v_row public.estimate_catalog_items%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT public.user_can_manage_estimate_catalog() THEN
    RAISE EXCEPTION 'Not allowed to manage estimate catalog';
  END IF;

  IF p_payload IS NULL OR jsonb_typeof(p_payload) <> 'array' THEN
    RAISE EXCEPTION 'payload must be a JSON array';
  END IF;

  SELECT COUNT(*)::int
  INTO v_id_total
  FROM jsonb_array_elements(p_payload) elem
  WHERE elem ? 'id'
    AND nullif(trim(elem->>'id'), '') IS NOT NULL;

  SELECT COUNT(DISTINCT (trim(elem->>'id'))::uuid)::int
  INTO v_id_distinct
  FROM jsonb_array_elements(p_payload) elem
  WHERE elem ? 'id'
    AND nullif(trim(elem->>'id'), '') IS NOT NULL;

  IF v_id_total <> v_id_distinct THEN
    RAISE EXCEPTION 'Duplicate catalog ids in payload';
  END IF;

  SELECT COALESCE(
    array_agg(DISTINCT (trim(elem->>'id'))::uuid) FILTER (WHERE nullif(trim(elem->>'id'), '') IS NOT NULL),
    ARRAY[]::uuid[]
  )
  INTO v_payload_ids
  FROM jsonb_array_elements(p_payload) elem
  WHERE elem ? 'id'
    AND nullif(trim(elem->>'id'), '') IS NOT NULL;

  FOR r_live IN
    SELECT *
    FROM public.estimate_catalog_items
    WHERE deleted_at IS NULL
  LOOP
    IF NOT (r_live.id = ANY (v_payload_ids)) THEN
      INSERT INTO public.estimate_catalog_item_events (
        item_id,
        editor_user_id,
        action,
        prev_line_item,
        prev_description,
        prev_quantity,
        prev_unit_price_cents,
        prev_amount_cents,
        new_line_item,
        new_description,
        new_quantity,
        new_unit_price_cents,
        new_amount_cents
      )
      VALUES (
        r_live.id,
        v_uid,
        'delete',
        r_live.line_item,
        r_live.description,
        r_live.quantity,
        r_live.unit_price_cents,
        r_live.amount_cents,
        NULL,
        NULL,
        NULL,
        NULL,
        NULL
      );

      UPDATE public.estimate_catalog_items
      SET deleted_at = now(),
          updated_at = now()
      WHERE id = r_live.id;
    END IF;
  END LOOP;

  FOR v_elem, v_idx IN
    SELECT elem, ord::int
    FROM jsonb_array_elements(p_payload) WITH ORDINALITY AS t(elem, ord)
  LOOP
    v_line := trim(COALESCE(v_elem->>'line_item', ''));
    v_desc := trim(COALESCE(v_elem->>'description', ''));

    BEGIN
      IF v_elem ? 'quantity' AND nullif(trim(v_elem->>'quantity'), '') IS NOT NULL THEN
        v_qty := (v_elem->>'quantity')::numeric;
      ELSE
        v_qty := 1::numeric;
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_qty := 1::numeric;
    END;

    IF v_qty <= 0 THEN
      v_qty := 1::numeric;
    END IF;

    v_unit := GREATEST(
      0,
      COALESCE((v_elem->>'unit_price_cents')::numeric, 0)::integer
    );

    -- Legacy payload: only amount_cents (line total), qty 1.
    IF v_unit = 0
      AND v_elem ? 'amount_cents'
      AND COALESCE((v_elem->>'amount_cents')::numeric, 0) > 0    THEN
      v_unit := GREATEST(
        0,
        COALESCE((v_elem->>'amount_cents')::numeric, 0)::integer
      );
      v_qty := 1::numeric;
    END IF;

    v_amt := GREATEST(0, ROUND((v_qty * v_unit)::numeric)::integer);

    IF v_line = '' AND v_desc = '' AND v_amt = 0 THEN
      CONTINUE;
    END IF;

    IF v_elem ? 'id' AND nullif(trim(v_elem->>'id'), '') IS NOT NULL THEN
      v_id := trim(v_elem->>'id')::uuid;

      SELECT *
      INTO v_row
      FROM public.estimate_catalog_items
      WHERE id = v_id;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Unknown catalog id %', v_id;
      END IF;

      IF v_row.deleted_at IS NOT NULL THEN
        INSERT INTO public.estimate_catalog_item_events (
          item_id,
          editor_user_id,
          action,
          prev_line_item,
          prev_description,
          prev_quantity,
          prev_unit_price_cents,
          prev_amount_cents,
          new_line_item,
          new_description,
          new_quantity,
          new_unit_price_cents,
          new_amount_cents
        )
        VALUES (
          v_id,
          v_uid,
          'restore',
          NULL,
          NULL,
          NULL,
          NULL,
          NULL,
          v_line,
          v_desc,
          v_qty,
          v_unit,
          v_amt
        );

        UPDATE public.estimate_catalog_items
        SET line_item = v_line,
            description = v_desc,
            quantity = v_qty,
            unit_price_cents = v_unit,
            amount_cents = v_amt,
            sort_order = v_idx,
            deleted_at = NULL,
            updated_at = now()
        WHERE id = v_id;
      ELSE
        IF v_row.line_item IS DISTINCT FROM v_line
          OR v_row.description IS DISTINCT FROM v_desc
          OR v_row.quantity IS DISTINCT FROM v_qty
          OR v_row.unit_price_cents IS DISTINCT FROM v_unit
        THEN
          INSERT INTO public.estimate_catalog_item_events (
            item_id,
            editor_user_id,
            action,
            prev_line_item,
            prev_description,
            prev_quantity,
            prev_unit_price_cents,
            prev_amount_cents,
            new_line_item,
            new_description,
            new_quantity,
            new_unit_price_cents,
            new_amount_cents
          )
          VALUES (
            v_id,
            v_uid,
            'update',
            v_row.line_item,
            v_row.description,
            v_row.quantity,
            v_row.unit_price_cents,
            v_row.amount_cents,
            v_line,
            v_desc,
            v_qty,
            v_unit,
            v_amt
          );
        END IF;

        UPDATE public.estimate_catalog_items
        SET line_item = v_line,
            description = v_desc,
            quantity = v_qty,
            unit_price_cents = v_unit,
            amount_cents = v_amt,
            sort_order = v_idx,
            updated_at = now()
        WHERE id = v_id;
      END IF;
    ELSE
      INSERT INTO public.estimate_catalog_items (
        line_item,
        description,
        quantity,
        unit_price_cents,
        amount_cents,
        sort_order
      )
      VALUES (
        v_line,
        v_desc,
        v_qty,
        v_unit,
        v_amt,
        v_idx
      )
      RETURNING id INTO v_id;

      INSERT INTO public.estimate_catalog_item_events (
        item_id,
        editor_user_id,
        action,
        prev_line_item,
        prev_description,
        prev_quantity,
        prev_unit_price_cents,
        prev_amount_cents,
        new_line_item,
        new_description,
        new_quantity,
        new_unit_price_cents,
        new_amount_cents
      )
      VALUES (
        v_id,
        v_uid,
        'create',
        NULL,
        NULL,
        NULL,
        NULL,
        NULL,
        v_line,
        v_desc,
        v_qty,
        v_unit,
        v_amt
      );
    END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."replace_estimate_catalog_payload"("p_payload" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "replace_estimate_catalog_payload"("p_payload" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."replace_estimate_catalog_payload"("p_payload" "jsonb") IS 'Replaces live catalog from JSON array [{ id?, line_item, description, quantity, unit_price_cents }]; amount_cents derived as round(quantity*unit_price); legacy { description, amount_cents } treated as qty 1; soft-deletes missing ids; writes audit events.';


--
-- Name: replace_mercury_job_splits_for_linked_card_as_staff("uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."replace_mercury_job_splits_for_linked_card_as_staff"("p_for_user_id" "uuid", "p_mercury_transaction_id" "uuid", "p_rows" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tx_amount numeric(18, 4);
  v_raw jsonb;
  v_card uuid;
  v_sum numeric(18, 4);
  v_len int;
  elem jsonb;
  v_note text;
  v_job uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: not authenticated';
  END IF;

  IF NOT (
    public.is_dev()
    OR EXISTS (
      SELECT 1 FROM public.users u
      WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant')
    )
  ) THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: not authorized';
  END IF;

  IF NOT public.staff_can_view_user_for_tally_followup(auth.uid(), p_for_user_id) THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: not authorized for this user';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.users u WHERE u.id = p_for_user_id) THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: target user not found';
  END IF;

  IF p_rows IS NULL OR jsonb_typeof(p_rows) <> 'array' THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: p_rows must be a JSON array';
  END IF;

  SELECT t.amount, t.raw INTO v_tx_amount, v_raw
  FROM public.mercury_transactions t
  WHERE t.id = p_mercury_transaction_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: transaction not found';
  END IF;

  v_card := public.mercury_debit_card_id_from_raw(v_raw);
  IF v_card IS NULL THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: transaction has no debit card on file';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.mercury_debit_card_user_links l
    WHERE l.user_id = p_for_user_id AND l.mercury_debit_card_id = v_card
  ) THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: not authorized for this transaction';
  END IF;

  v_len := jsonb_array_length(p_rows);

  SELECT COALESCE(SUM((e->>'amount')::numeric(18, 4)), 0) INTO v_sum
  FROM jsonb_array_elements(p_rows) AS e;

  IF v_len > 0 AND v_sum IS DISTINCT FROM v_tx_amount THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: allocation sum must equal transaction amount';
  END IF;

  FOR elem IN SELECT * FROM jsonb_array_elements(p_rows)
  LOOP
    v_job := (elem->>'job_id')::uuid;
    IF NOT EXISTS (SELECT 1 FROM public.jobs_ledger jl WHERE jl.id = v_job) THEN
      RAISE EXCEPTION 'replace_mercury_job_splits_for_linked_card_as_staff: invalid job';
    END IF;
  END LOOP;

  DELETE FROM public.mercury_transaction_job_allocations
  WHERE mercury_transaction_id = p_mercury_transaction_id;

  FOR elem IN SELECT * FROM jsonb_array_elements(p_rows)
  LOOP
    v_note := NULLIF(trim(both FROM elem->>'note'), '');
    INSERT INTO public.mercury_transaction_job_allocations (
      mercury_transaction_id,
      job_id,
      amount,
      note,
      created_by
    )
    VALUES (
      p_mercury_transaction_id,
      (elem->>'job_id')::uuid,
      (elem->>'amount')::numeric(18, 4),
      v_note,
      auth.uid()
    );
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."replace_mercury_job_splits_for_linked_card_as_staff"("p_for_user_id" "uuid", "p_mercury_transaction_id" "uuid", "p_rows" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "replace_mercury_job_splits_for_linked_card_as_staff"("p_for_user_id" "uuid", "p_mercury_transaction_id" "uuid", "p_rows" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."replace_mercury_job_splits_for_linked_card_as_staff"("p_for_user_id" "uuid", "p_mercury_transaction_id" "uuid", "p_rows" "jsonb") IS 'Dev/master/assistant: replace job splits for a Mercury tx on p_for_user_id''s linked card if staff_can_view_user_for_tally_followup. Any jobs_ledger job_id is allowed (subcontractor targets are not team-gated).';


--
-- Name: replace_mercury_job_splits_for_my_linked_card("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."replace_mercury_job_splits_for_my_linked_card"("p_mercury_transaction_id" "uuid", "p_rows" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tx_amount numeric(18, 4);
  v_raw jsonb;
  v_card uuid;
  v_sum numeric(18, 4);
  v_len int;
  elem jsonb;
  v_note text;
  v_role text;
  v_job uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: not authenticated';
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = auth.uid();
  IF v_role IS NULL THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: user not found';
  END IF;

  IF p_rows IS NULL OR jsonb_typeof(p_rows) <> 'array' THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: p_rows must be a JSON array';
  END IF;

  SELECT t.amount, t.raw INTO v_tx_amount, v_raw
  FROM public.mercury_transactions t
  WHERE t.id = p_mercury_transaction_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: transaction not found';
  END IF;

  v_card := public.mercury_debit_card_id_from_raw(v_raw);
  IF v_card IS NULL THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: transaction has no debit card on file';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.mercury_debit_card_user_links l
    WHERE l.user_id = auth.uid() AND l.mercury_debit_card_id = v_card
  ) THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: not authorized for this transaction';
  END IF;

  v_len := jsonb_array_length(p_rows);

  SELECT COALESCE(SUM((e->>'amount')::numeric(18, 4)), 0) INTO v_sum
  FROM jsonb_array_elements(p_rows) AS e;

  IF v_len > 0 AND v_sum IS DISTINCT FROM v_tx_amount THEN
    RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: allocation sum must equal transaction amount';
  END IF;

  FOR elem IN SELECT * FROM jsonb_array_elements(p_rows)
  LOOP
    v_job := (elem->>'job_id')::uuid;
    IF NOT EXISTS (SELECT 1 FROM public.jobs_ledger jl WHERE jl.id = v_job) THEN
      RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: invalid job';
    END IF;
    IF v_role IN ('helpers', 'subcontractor') THEN
      IF NOT EXISTS (
        SELECT 1 FROM public.jobs_ledger_team_members jtm
        WHERE jtm.job_id = v_job AND jtm.user_id = auth.uid()
      ) THEN
        RAISE EXCEPTION 'replace_mercury_job_splits_for_my_linked_card: job not on your team';
      END IF;
    END IF;
  END LOOP;

  DELETE FROM public.mercury_transaction_job_allocations
  WHERE mercury_transaction_id = p_mercury_transaction_id;

  FOR elem IN SELECT * FROM jsonb_array_elements(p_rows)
  LOOP
    v_note := NULLIF(trim(both FROM elem->>'note'), '');
    INSERT INTO public.mercury_transaction_job_allocations (
      mercury_transaction_id,
      job_id,
      amount,
      note,
      created_by
    )
    VALUES (
      p_mercury_transaction_id,
      (elem->>'job_id')::uuid,
      (elem->>'amount')::numeric(18, 4),
      v_note,
      auth.uid()
    );
  END LOOP;
END;
$$;


