--
-- Name: FUNCTION "replace_mercury_job_splits_for_my_linked_card"("p_mercury_transaction_id" "uuid", "p_rows" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."replace_mercury_job_splits_for_my_linked_card"("p_mercury_transaction_id" "uuid", "p_rows" "jsonb") IS 'Card-linked user: replace job splits for a transaction on their linked debit card; does not change attributions. Subcontractors: jobs must be on their team.';


