--
-- Name: reporting_window_calendar_civil_day("text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reporting_window_calendar_civil_day"("p_timezone" "text", "p_civil_day" "date") RETURNS TABLE("window_start_utc" timestamp with time zone, "window_end_utc" timestamp with time zone, "reporting_date" "date")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH z AS (
    SELECT COALESCE(NULLIF(trim(p_timezone), ''), 'America/Chicago') AS tznm
  )
  SELECT
    (p_civil_day::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_start_utc,
    (((p_civil_day + INTERVAL '1 day')::date)::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_end_utc,
    p_civil_day AS reporting_date
  FROM z;
$$;


ALTER FUNCTION "public"."reporting_window_calendar_civil_day"("p_timezone" "text", "p_civil_day" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "reporting_window_calendar_civil_day"("p_timezone" "text", "p_civil_day" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."reporting_window_calendar_civil_day"("p_timezone" "text", "p_civil_day" "date") IS 'Recurring job report: activity on one civil calendar day in p_timezone; reporting_date = that day.';


--
-- Name: reporting_window_calendar_week_containing_anchor("text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reporting_window_calendar_week_containing_anchor"("p_timezone" "text", "p_anchor_date" "date" DEFAULT NULL::"date") RETURNS TABLE("window_start_utc" timestamp with time zone, "window_end_utc" timestamp with time zone, "reporting_date" "date")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH z AS (
    SELECT COALESCE(NULLIF(trim(p_timezone), ''), 'America/Chicago') AS tznm
  ),
  a AS (
    SELECT COALESCE(
      p_anchor_date,
      (timezone((SELECT tznm FROM z), now()))::date
    )::date AS anchor
  ),
  w AS (
    SELECT
      (aa.anchor - ((EXTRACT(DOW FROM aa.anchor))::bigint * INTERVAL '1 day'))::date AS week_sun
    FROM a AS aa
  )
  SELECT
    ((w.week_sun)::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_start_utc,
    (((w.week_sun + 7)::date)::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_end_utc,
    w.week_sun AS reporting_date
  FROM w;
$$;


ALTER FUNCTION "public"."reporting_window_calendar_week_containing_anchor"("p_timezone" "text", "p_anchor_date" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "reporting_window_calendar_week_containing_anchor"("p_timezone" "text", "p_anchor_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."reporting_window_calendar_week_containing_anchor"("p_timezone" "text", "p_anchor_date" "date") IS 'Recurring job report weekly window: Sunday 00:00 through next Sunday 00:00 (exclusive end) in p_timezone; reporting_date = week Sunday for dispatch_log idempotency.';


--
-- Name: reporting_window_calendar_week_prior_to_anchor("text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reporting_window_calendar_week_prior_to_anchor"("p_timezone" "text", "p_anchor_date" "date" DEFAULT NULL::"date") RETURNS TABLE("window_start_utc" timestamp with time zone, "window_end_utc" timestamp with time zone, "reporting_date" "date")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH z AS (
    SELECT COALESCE(NULLIF(trim(p_timezone), ''), 'America/Chicago') AS tznm
  ),
  a AS (
    SELECT COALESCE(
      p_anchor_date,
      (timezone((SELECT tznm FROM z), now()))::date
    )::date AS anchor
    FROM z
  ),
  w AS (
    SELECT
      (
        (
          aa.anchor -
          ((EXTRACT(DOW FROM aa.anchor))::bigint * INTERVAL '1 day')
        )::date
        - 7
      ) AS prior_week_sun
    FROM a AS aa
  )
  SELECT
    ((w.prior_week_sun)::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_start_utc,
    (((w.prior_week_sun + 7)::date)::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_end_utc,
    w.prior_week_sun AS reporting_date
  FROM w;
$$;


ALTER FUNCTION "public"."reporting_window_calendar_week_prior_to_anchor"("p_timezone" "text", "p_anchor_date" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "reporting_window_calendar_week_prior_to_anchor"("p_timezone" "text", "p_anchor_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."reporting_window_calendar_week_prior_to_anchor"("p_timezone" "text", "p_anchor_date" "date") IS 'Recurring job report: full calendar week BEFORE the Sun-Sat week containing anchor; reporting_date = that week Sunday (dispatch dedup).';


--
-- Name: reporting_window_for_recurring_job_email("text", "text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reporting_window_for_recurring_job_email"("p_timezone" "text", "p_preset" "text", "p_anchor_date" "date" DEFAULT NULL::"date") RETURNS TABLE("window_start_utc" timestamp with time zone, "window_end_utc" timestamp with time zone, "reporting_date" "date")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH z AS (
    SELECT COALESCE(NULLIF(trim(p_timezone), ''), 'America/Chicago') AS tznm
  ),
  b AS (
    SELECT (
      COALESCE(p_anchor_date, (timezone(z.tznm, now()))::date) - INTERVAL '1 day'
    )::date AS rpt
    FROM z
    WHERE lower(trim(coalesce(p_preset, ''))) IN ('prior_calendar_day', 'calendar_yesterday')
  )
  SELECT
    (b.rpt::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_start_utc,
    (((b.rpt + INTERVAL '1 day')::date)::timestamp AT TIME ZONE (SELECT tznm FROM z))::timestamptz AS window_end_utc,
    b.rpt AS reporting_date
  FROM b;
$$;


ALTER FUNCTION "public"."reporting_window_for_recurring_job_email"("p_timezone" "text", "p_preset" "text", "p_anchor_date" "date") OWNER TO "postgres";

--
-- Name: FUNCTION "reporting_window_for_recurring_job_email"("p_timezone" "text", "p_preset" "text", "p_anchor_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."reporting_window_for_recurring_job_email"("p_timezone" "text", "p_preset" "text", "p_anchor_date" "date") IS 'Reporting UTC window: prior_calendar_day or calendar_yesterday = full civil day before anchor in zone.';


--
-- Name: resolve_pay_person_id_from_clock_user("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_pay_person_id_from_clock_user"("p_user_id" "uuid", "p_display_name" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
  v_cnt int;
BEGIN
  IF p_user_id IS NOT NULL THEN
    SELECT p.id INTO v_id
    FROM public.people p
    WHERE p.archived_at IS NULL
      AND p.account_user_id = p_user_id
    ORDER BY p.id
    LIMIT 1;
    IF v_id IS NOT NULL THEN
      RETURN v_id;
    END IF;
  END IF;

  IF p_display_name IS NULL OR btrim(p_display_name) = '' THEN
    RETURN NULL;
  END IF;

  SELECT COUNT(*) INTO v_cnt
  FROM public.people p
  WHERE p.archived_at IS NULL
    AND btrim(p.name) = btrim(p_display_name);

  IF v_cnt = 1 THEN
    SELECT p.id INTO v_id
    FROM public.people p
    WHERE p.archived_at IS NULL
      AND btrim(p.name) = btrim(p_display_name)
    LIMIT 1;
    RETURN v_id;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."resolve_pay_person_id_from_clock_user"("p_user_id" "uuid", "p_display_name" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "resolve_pay_person_id_from_clock_user"("p_user_id" "uuid", "p_display_name" "text"); Type: COMMENT; Schema: public; Owner: postgres
