COMMENT ON FUNCTION "public"."resolve_pay_person_id_from_clock_user"("p_user_id" "uuid", "p_display_name" "text") IS 'Resolve roster id for pay: people.account_user_id first, else unique trim(name) match among active people.';


--
-- Name: restore_rejected_clock_sessions("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."restore_rejected_clock_sessions"("p_session_ids" "uuid"[]) RETURNS TABLE("restored_count" integer, "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_restored int := 0;
  v_session RECORD;
  v_pay boolean;
  v_dev boolean;
  v_hours numeric;
  v_new_hours numeric;
BEGIN
  v_pay := public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant();
  v_dev := public.is_dev();

  FOR v_session IN
    SELECT
      cs.id,
      cs.user_id,
      cs.clocked_in_at,
      cs.clocked_out_at,
      cs.work_date,
      trim(u.name) AS person_name,
      cs.approved_at,
      cs.job_ledger_id,
      cs.bid_id
    FROM public.clock_sessions cs
    JOIN public.users u ON u.id = cs.user_id
    WHERE cs.id = ANY(p_session_ids)
      AND cs.clocked_out_at IS NOT NULL
      AND cs.rejected_at IS NOT NULL
  LOOP
    IF NOT v_pay AND NOT v_dev THEN
      IF NOT public.is_team_lead_for_member(auth.uid(), v_session.user_id) THEN
        RETURN QUERY SELECT 0, 'Access denied'::text;
        RETURN;
      END IF;
    END IF;

    IF v_session.person_name IS NULL OR v_session.person_name = '' THEN
      RETURN QUERY SELECT 0, ('User has no name for session ' || v_session.id::text)::text;
      RETURN;
    END IF;

    IF v_session.approved_at IS NOT NULL THEN
      v_hours := EXTRACT(EPOCH FROM (v_session.clocked_out_at - v_session.clocked_in_at)) / 3600.0;
      IF v_hours > 0 THEN
        UPDATE public.people_hours
        SET hours = hours - v_hours,
            entered_by = auth.uid()
        WHERE person_name = v_session.person_name
          AND work_date = v_session.work_date
        RETURNING hours INTO v_new_hours;

        IF FOUND THEN
          IF v_new_hours <= 0 THEN
            DELETE FROM public.people_hours
            WHERE person_name = v_session.person_name
              AND work_date = v_session.work_date;
          END IF;
        END IF;
      END IF;

      UPDATE public.clock_sessions
      SET approved_at = NULL, approved_by = NULL
      WHERE id = v_session.id;

      IF v_session.job_ledger_id IS NOT NULL THEN
        PERFORM public.sync_crew_jobs_from_clock(v_session.person_name, v_session.work_date);
      END IF;
      IF v_session.bid_id IS NOT NULL THEN
        PERFORM public.sync_crew_bids_from_clock(v_session.person_name, v_session.work_date);
      END IF;
    END IF;

    UPDATE public.clock_sessions
    SET rejected_at = NULL, rejected_by = NULL
    WHERE id = v_session.id;

    v_restored := v_restored + 1;
  END LOOP;

  RETURN QUERY SELECT v_restored, NULL::text;
END;
$$;


ALTER FUNCTION "public"."restore_rejected_clock_sessions"("p_session_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "restore_rejected_clock_sessions"("p_session_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."restore_rejected_clock_sessions"("p_session_ids" "uuid"[]) IS 'Clear rejection (return to Pending). If session was still approved, unwind people_hours and crew sync like revoke first. Pay, dev, or team lead. SECURITY DEFINER; auth enforced inside.';


--
-- Name: return_collect_payment_to_dispatch("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."return_collect_payment_to_dispatch"("p_job_id" "uuid", "p_note" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
  v_note text;
  v_row public.job_collect_payment_flows%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('error', 'not_authenticated');
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = v_uid;
  IF v_role IS DISTINCT FROM 'subcontractor' THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger_team_members jtm
    INNER JOIN public.jobs_ledger jl ON jl.id = jtm.job_id
    WHERE jtm.user_id = v_uid
      AND jl.id = p_job_id
      AND jl.status = 'ready_to_bill'
  ) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  v_note := NULLIF(trim(COALESCE(p_note, '')), '');
  IF v_note IS NULL OR length(v_note) < 3 THEN
    RETURN jsonb_build_object('error', 'Describe the issue (at least 3 characters).');
  END IF;

  SELECT * INTO v_row
  FROM public.job_collect_payment_flows
  WHERE job_id = p_job_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'No collect payment flow for this job.');
  END IF;

  IF v_row.status IS DISTINCT FROM 'approved_for_terminal' THEN
    RETURN jsonb_build_object(
      'error',
      'Payment is not at the collect step. Refresh and try again.'
    );
  END IF;

  UPDATE public.job_collect_payment_flows
  SET
    initiated_by_user_id = v_uid,
    status = 'pending_dispatch',
    certify_mode = 'returned_from_terminal',
    correction_notes = v_note,
    certified_at = now(),
    dispatch_reviewed_at = NULL,
    dispatch_reviewed_by = NULL,
    dispatch_notes = NULL,
    jobs_ledger_invoice_id = NULL,
    stripe_invoice_id = NULL,
    stripe_payment_intent_id = NULL,
    last_error = NULL
  WHERE job_id = p_job_id;

  RETURN jsonb_build_object('ok', true, 'status', 'pending_dispatch');
END;
$$;


ALTER FUNCTION "public"."return_collect_payment_to_dispatch"("p_job_id" "uuid", "p_note" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "return_collect_payment_to_dispatch"("p_job_id" "uuid", "p_note" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."return_collect_payment_to_dispatch"("p_job_id" "uuid", "p_note" "text") IS 'Subcontractor: send collect payment back to dispatch from approved_for_terminal with a note; sets initiated_by_user_id to actor.';


--
-- Name: revert_stripe_oob_invoice_payment("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."revert_stripe_oob_invoice_payment"("p_invoice_id" "uuid", "p_reason" "text", "p_stripe_invoice_status_after" "text" DEFAULT NULL::"text", "p_stripe_credit_note_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_job_id uuid;
  v_applied_sum numeric;
  v_inv_amt numeric;
  v_new_pm numeric;
  v_job_status text;
  v_rev numeric;
  v_stripe_sid text;
  v_status_json jsonb;
  r_trim text := trim(COALESCE(p_reason, ''));
  v_stripe_after text := NULLIF(trim(COALESCE(p_stripe_invoice_status_after, '')), '');
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('error', 'Not authenticated');
  END IF;

  IF length(r_trim) < 3 THEN
    RETURN jsonb_build_object('error', 'Reason is required (at least 3 characters)');
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RETURN jsonb_build_object('error', 'Not authorized');
  END IF;

  SELECT
    i.id,
    i.job_id,
    i.amount,
    i.status,
    i.stripe_invoice_id
  INTO v_invoice
  FROM public.jobs_ledger_invoices i
  WHERE i.id = p_invoice_id;

  IF v_invoice.id IS NULL THEN
    RETURN jsonb_build_object('error', 'Invoice not found');
  END IF;

  IF v_invoice.status IS DISTINCT FROM 'paid' THEN
    RETURN jsonb_build_object('error', 'Invoice must be Paid to unwind Stripe out-of-band payment');
  END IF;

  v_stripe_sid := NULLIF(trim(COALESCE(v_invoice.stripe_invoice_id, '')), '');
  IF v_stripe_sid IS NULL THEN
    RETURN jsonb_build_object('error', 'Invoice has no Stripe invoice id');
  END IF;

  v_job_id := v_invoice.job_id;

  IF NOT EXISTS (
    SELECT 1 FROM public.jobs_ledger j
    WHERE j.id = v_job_id
    AND (
      j.master_user_id = auth.uid()
      OR public.is_dev()
      OR EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
      OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = j.master_user_id)
      OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = j.master_user_id AND assistant_id = auth.uid())
      OR public.assistants_share_master(auth.uid(), j.master_user_id)
    )
  ) THEN
    RETURN jsonb_build_object('error', 'Not authorized to update this job');
  END IF;

  SELECT COALESCE(SUM(amount), 0) INTO v_applied_sum
  FROM public.jobs_ledger_payments
  WHERE invoice_id = p_invoice_id;

  v_inv_amt := COALESCE(v_invoice.amount, 0);

  IF v_applied_sum <= 0 THEN
    RETURN jsonb_build_object('error', 'No applied payments found for this invoice');
  END IF;

  -- v1: full invoice allocation only (same as record-OOB full balance)
  IF v_applied_sum + 0.01 < v_inv_amt THEN
    RETURN jsonb_build_object(
      'error',
      'Only full invoice out-of-band allocations can be unwound (applied sum does not match invoice amount)'
    );
  END IF;

  DELETE FROM public.jobs_ledger_payments
  WHERE invoice_id = p_invoice_id;

  SELECT COALESCE(SUM(amount), 0) INTO v_new_pm
  FROM public.jobs_ledger_payments
  WHERE job_id = v_job_id;

  SELECT jl.status, COALESCE(jl.revenue, 0)
  INTO v_job_status, v_rev
  FROM public.jobs_ledger jl
  WHERE jl.id = v_job_id;

  UPDATE public.jobs_ledger
  SET
    payments_made = v_new_pm,
    updated_at = NOW()
  WHERE id = v_job_id;

  UPDATE public.jobs_ledger_invoices
  SET
    status = 'billed',
    stripe_invoice_status = COALESCE(v_stripe_after, stripe_invoice_status)
  WHERE id = p_invoice_id;

  IF v_job_status = 'paid' AND v_rev > COALESCE(v_new_pm, 0) + 0.01 THEN
    SELECT public.update_job_status(v_job_id, 'billed') INTO v_status_json;
    IF v_status_json IS NOT NULL AND v_status_json->>'error' IS NOT NULL THEN
      RETURN jsonb_build_object(
        'error',
        COALESCE(v_status_json->>'error', 'Failed to move job back to Billed'),
        'detail',
        'Ledger payments were removed; fix job status manually if needed'
      );
    END IF;
  END IF;

  INSERT INTO public.stripe_oob_payment_reverts (
    invoice_id,
    job_id,
    reason,
    stripe_credit_note_id,
    created_by_user_id
  )
  VALUES (
    p_invoice_id,
    v_job_id,
    r_trim,
    NULLIF(trim(COALESCE(p_stripe_credit_note_id, '')), ''),
    auth.uid()
  );

  UPDATE public.job_collect_payment_flows
  SET
    status = 'approved_for_terminal',
    last_error = NULL
  WHERE trim(stripe_invoice_id) = v_stripe_sid
    AND status = 'terminal_completed';

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION "public"."revert_stripe_oob_invoice_payment"("p_invoice_id" "uuid", "p_reason" "text", "p_stripe_invoice_status_after" "text", "p_stripe_credit_note_id" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "revert_stripe_oob_invoice_payment"("p_invoice_id" "uuid", "p_reason" "text", "p_stripe_invoice_status_after" "text", "p_stripe_credit_note_id" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."revert_stripe_oob_invoice_payment"("p_invoice_id" "uuid", "p_reason" "text", "p_stripe_invoice_status_after" "text", "p_stripe_credit_note_id" "text") IS 'After Stripe credit note for OOB-paid invoice: remove invoice-linked payments, set invoice billed, sync payments_made, paid→billed when needed, audit row, reset collect flow.';


--
-- Name: revoke_clock_sessions("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."revoke_clock_sessions"("p_session_ids" "uuid"[]) RETURNS TABLE("revoked_count" integer, "error_message" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_revoked int := 0;
  v_session RECORD;
  v_hours numeric;
  v_new_hours numeric;
  v_pay boolean;
  v_person_id uuid;
BEGIN
  v_pay :=
    public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant();

  FOR v_session IN
    SELECT cs.id, cs.user_id, cs.clocked_in_at, cs.clocked_out_at, cs.work_date, trim(u.name) AS person_name, cs.job_ledger_id, cs.bid_id
    FROM public.clock_sessions cs
    JOIN public.users u ON u.id = cs.user_id
    WHERE cs.id = ANY(p_session_ids)
      AND cs.clocked_out_at IS NOT NULL
      AND cs.approved_at IS NOT NULL
  LOOP
    IF NOT v_pay THEN
      IF NOT public.is_team_lead_for_member(auth.uid(), v_session.user_id) THEN
        RETURN QUERY SELECT 0, 'Access denied'::text;
        RETURN;
      END IF;
    END IF;

    IF v_session.person_name IS NULL OR v_session.person_name = '' THEN
      RETURN QUERY SELECT 0, ('User has no name for session ' || v_session.id::text)::text;
      RETURN;
    END IF;

    v_hours := EXTRACT(EPOCH FROM (v_session.clocked_out_at - v_session.clocked_in_at)) / 3600.0;
    IF v_hours <= 0 THEN
      CONTINUE;
    END IF;

    v_person_id := public.resolve_pay_person_id_from_clock_user(v_session.user_id, v_session.person_name);

    UPDATE public.people_hours
    SET hours = hours - v_hours,
        entered_by = auth.uid()
    WHERE work_date = v_session.work_date
      AND (
        (v_person_id IS NOT NULL AND person_id = v_person_id)
        OR (v_person_id IS NULL AND person_name = v_session.person_name)
      )
    RETURNING hours INTO v_new_hours;

    IF FOUND THEN
      IF v_new_hours <= 0 THEN
        DELETE FROM public.people_hours
        WHERE work_date = v_session.work_date
          AND (
            (v_person_id IS NOT NULL AND person_id = v_person_id)
            OR (v_person_id IS NULL AND person_name = v_session.person_name)
          );
      END IF;
    END IF;

    UPDATE public.clock_sessions
    SET approved_at = NULL, approved_by = NULL,
        revoked_at = NOW(), revoked_by = auth.uid()
    WHERE id = v_session.id;

    v_revoked := v_revoked + 1;

    IF v_session.job_ledger_id IS NOT NULL THEN
      PERFORM public.sync_crew_jobs_from_clock(v_session.person_name, v_session.work_date);
    END IF;
    IF v_session.bid_id IS NOT NULL THEN
      PERFORM public.sync_crew_bids_from_clock(v_session.person_name, v_session.work_date);
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_revoked, NULL::text;
END;
$$;


ALTER FUNCTION "public"."revoke_clock_sessions"("p_session_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "revoke_clock_sessions"("p_session_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."revoke_clock_sessions"("p_session_ids" "uuid"[]) IS 'Revoke approved clock sessions. Pay access OR team leader for session user. Matches people_hours by person_id when resolvable.';


--
-- Name: salary_force_close_open_sessions_after_shift("uuid", "date", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."salary_force_close_open_sessions_after_shift"("p_user_id" "uuid", "p_work_date" "date", "p_now" timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  r_t record;
  r_o record;
  tz text;
  v_mode text;
  sa_time time;
  sa_dur int;
  sb_time time;
  sb_dur int;
  t_start timestamptz;
  t_end timestamptz;
  t_start2 timestamptz;
  t_end2 timestamptz;
  v_shift_end timestamptz;
  v_override_meaningful boolean;
BEGIN
  IF EXISTS (
    SELECT 1
    FROM public.user_time_off
    WHERE user_id = p_user_id
      AND p_work_date >= start_date
      AND p_work_date <= end_date
  ) THEN
    RETURN;
  END IF;

  SELECT * INTO r_t FROM public.salary_work_schedule_templates WHERE user_id = p_user_id;
  IF NOT FOUND THEN
    RETURN;
  END IF;

  SELECT * INTO r_o
  FROM public.salary_work_schedule_day_overrides
  WHERE user_id = p_user_id AND work_date = p_work_date;

  v_override_meaningful := FOUND AND (r_o.mode IS NOT NULL OR r_o.segment_a_start_local IS NOT NULL);

  IF r_t.exclude_weekends
     AND NOT v_override_meaningful
     AND to_char(p_work_date, 'ID')::int IN (6, 7) THEN
    RETURN;
  END IF;

  tz := COALESCE(r_o.timezone, r_t.timezone, 'America/Chicago');
  v_mode := COALESCE(r_o.mode, r_t.mode);
  sa_time := COALESCE(r_o.segment_a_start_local, r_t.segment_a_start_local);
  sa_dur := COALESCE(r_o.segment_a_duration_minutes, r_t.segment_a_duration_minutes);
  sb_time := COALESCE(r_o.segment_b_start_local, r_t.segment_b_start_local);
  sb_dur := COALESCE(r_o.segment_b_duration_minutes, r_t.segment_b_duration_minutes);

  IF v_mode = 'continuous' THEN
    t_start := (p_work_date::timestamp + sa_time) AT TIME ZONE tz;
    t_end := t_start + (sa_dur || ' minutes')::interval;
    v_shift_end := t_end;
  ELSE
    IF sb_time IS NULL OR sb_dur IS NULL THEN
      RETURN;
    END IF;
    t_start := (p_work_date::timestamp + sa_time) AT TIME ZONE tz;
    t_end := t_start + (sa_dur || ' minutes')::interval;
    t_start2 := (p_work_date::timestamp + sb_time) AT TIME ZONE tz;
    t_end2 := t_start2 + (sb_dur || ' minutes')::interval;
    v_shift_end := GREATEST(t_end, t_end2);
  END IF;

  IF p_now < v_shift_end THEN
    RETURN;
  END IF;

  UPDATE public.clock_sessions
  SET clocked_out_at = v_shift_end
  WHERE user_id = p_user_id
    AND work_date = p_work_date
    AND clocked_out_at IS NULL
    AND rejected_at IS NULL
    AND revoked_at IS NULL;
END;
$$;


ALTER FUNCTION "public"."salary_force_close_open_sessions_after_shift"("p_user_id" "uuid", "p_work_date" "date", "p_now" timestamp with time zone) OWNER TO "postgres";

--
-- Name: FUNCTION "salary_force_close_open_sessions_after_shift"("p_user_id" "uuid", "p_work_date" "date", "p_now" timestamp with time zone); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."salary_force_close_open_sessions_after_shift"("p_user_id" "uuid", "p_work_date" "date", "p_now" timestamp with time zone) IS 'After template shift end, set clocked_out_at on all still-open sessions for user/day (non-rejected/non-revoked), including approved and any origin.';


--
-- Name: salary_schedule_staff_or_self_target("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."salary_schedule_staff_or_self_target"("p_target_user_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    p_target_user_id = auth.uid()
    OR public.is_dev()
    OR public.is_pay_approved_master()
