--
-- Name: search_bids_for_clock("text", "uuid", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_bids_for_clock"("p_search_text" "text" DEFAULT ''::"text", "p_service_type_id" "uuid" DEFAULT NULL::"uuid", "p_service_type_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS TABLE("id" "uuid", "service_type_id" "uuid", "bid_number" "text", "project_name" "text", "address" "text", "customer_name" "text", "service_type_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    b.id,
    b.service_type_id,
    COALESCE(b.bid_number, '')::TEXT,
    COALESCE(b.project_name, '')::TEXT,
    COALESCE(b.address, '')::TEXT,
    COALESCE(c.name, bgb.name, '')::TEXT,
    COALESCE(st.name, '')::TEXT
  FROM public.bids b
  LEFT JOIN public.customers c ON c.id = b.customer_id
  LEFT JOIN public.bids_gc_builders bgb ON bgb.id = b.gc_builder_id
  LEFT JOIN public.service_types st ON st.id = b.service_type_id
  WHERE (
    (p_service_type_ids IS NOT NULL AND coalesce(array_length(p_service_type_ids, 1), 0) > 0 AND b.service_type_id = ANY(p_service_type_ids))
    OR ((p_service_type_ids IS NULL OR coalesce(array_length(p_service_type_ids, 1), 0) = 0) AND (p_service_type_id IS NULL OR b.service_type_id = p_service_type_id))
  )
  AND (
    p_search_text IS NULL OR p_search_text = ''
    OR b.bid_number ILIKE '%' || p_search_text || '%'
    OR (
      length(p_search_text) >= 2
      AND lower(left(p_search_text, 1)) = 'b'
      AND b.bid_number ILIKE '%' || substring(p_search_text from 2) || '%'
    )
    OR b.project_name ILIKE '%' || p_search_text || '%'
    OR b.address ILIKE '%' || p_search_text || '%'
    OR c.name ILIKE '%' || p_search_text || '%'
    OR bgb.name ILIKE '%' || p_search_text || '%'
    OR EXISTS (
      SELECT 1
      FROM public.service_types stp
      WHERE stp.ledger_bid_prefix IS NOT NULL
        AND btrim(stp.ledger_bid_prefix) <> ''
        AND coalesce(p_search_text, '') <> ''
        AND length(p_search_text) > length(btrim(stp.ledger_bid_prefix))
        AND lower(p_search_text) LIKE lower(btrim(stp.ledger_bid_prefix)) || '%'
        AND b.bid_number ILIKE '%' || substring(p_search_text from length(btrim(stp.ledger_bid_prefix)) + 1) || '%'
    )
  )
  ORDER BY b.project_name
  LIMIT 50;
$$;


ALTER FUNCTION "public"."search_bids_for_clock"("p_search_text" "text", "p_service_type_id" "uuid", "p_service_type_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "search_bids_for_clock"("p_search_text" "text", "p_service_type_id" "uuid", "p_service_type_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."search_bids_for_clock"("p_search_text" "text", "p_service_type_id" "uuid", "p_service_type_ids" "uuid"[]) IS 'Search bids for Clock In/Dispatch. B + ledger_bid_prefix stripping; returns service_type_id and service_type_name. SECURITY DEFINER.';


--
-- Name: search_estimates_for_nav("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_estimates_for_nav"("search_text" "text" DEFAULT ''::"text") RETURNS TABLE("id" "uuid", "estimate_number" integer, "title" "text", "customer_name" "text", "subtitle" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH q AS (
    SELECT btrim(COALESCE(search_text, '')) AS t
  )
  SELECT
    e.id,
    e.estimate_number,
    COALESCE(e.title, '')::TEXT,
    COALESCE(c.name, '')::TEXT,
    NULLIF(
      btrim(
        concat_ws(
          ' — ',
          NULLIF(btrim(COALESCE(c.address, '')), ''),
          NULLIF(btrim(COALESCE(e.for_address, '')), ''),
          NULLIF(btrim(COALESCE(e.customer_email, '')), '')
        )
      ),
      ''
    )::TEXT
  FROM public.estimates e
  LEFT JOIN public.customers c ON c.id = e.customer_id
  CROSS JOIN q
  WHERE length(q.t) >= 1
  AND (
    e.estimate_number::text ILIKE '%' || q.t || '%'
    OR (
      length(q.t) >= 2
      AND lower(left(q.t, 1)) = 'e'
      AND e.estimate_number::text ILIKE '%' || substring(q.t from 2) || '%'
    )
    OR e.title ILIKE '%' || q.t || '%'
    OR e.customer_email ILIKE '%' || q.t || '%'
    OR e.for_address ILIKE '%' || q.t || '%'
    OR c.name ILIKE '%' || q.t || '%'
    OR c.address ILIKE '%' || q.t || '%'
  )
  ORDER BY e.updated_at DESC NULLS LAST
  LIMIT 50;
$$;


ALTER FUNCTION "public"."search_estimates_for_nav"("search_text" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "search_estimates_for_nav"("search_text" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."search_estimates_for_nav"("search_text" "text") IS 'Search estimates by quote #, title, customer, address, email. E prefix matches estimate_number. RLS enforced (SECURITY INVOKER).';


--
-- Name: search_jobs_for_reports("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_jobs_for_reports"("search_text" "text" DEFAULT ''::"text") RETURNS TABLE("id" "uuid", "source" "text", "display_name" "text", "hcp_number" "text", "address" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT sub.id, sub.source, sub.display_name, sub.hcp_number, sub.address
  FROM (
    (SELECT jl.id, 'job_ledger'::TEXT AS source, jl.job_name AS display_name, COALESCE(jl.hcp_number, '')::TEXT AS hcp_number, COALESCE(jl.job_address, '')::TEXT AS address
     FROM public.jobs_ledger jl
     WHERE (search_text IS NULL OR search_text = '' OR jl.hcp_number ILIKE '%' || search_text || '%' OR jl.job_name ILIKE '%' || search_text || '%' OR jl.job_address ILIKE '%' || search_text || '%')
     LIMIT 25)
    UNION ALL
    (SELECT p.id, 'project'::TEXT, p.name, COALESCE(p.housecallpro_number, '')::TEXT, COALESCE(p.address, '')::TEXT
     FROM public.projects p
     WHERE (search_text IS NULL OR search_text = '' OR COALESCE(p.housecallpro_number, '') ILIKE '%' || search_text || '%' OR p.name ILIKE '%' || search_text || '%' OR COALESCE(p.address, '') ILIKE '%' || search_text || '%')
     LIMIT 25)
    UNION ALL
    (SELECT b.id, 'bid'::TEXT AS source,
     COALESCE(b.project_name, b.gc_contact_name, 'Bid')::TEXT AS display_name,
     COALESCE(b.bid_number, '')::TEXT AS hcp_number,
     COALESCE(b.address, '')::TEXT AS address
     FROM public.bids b
     WHERE (search_text IS NULL OR search_text = '' OR
       COALESCE(b.bid_number, '') ILIKE '%' || search_text || '%' OR
       COALESCE(b.project_name, '') ILIKE '%' || search_text || '%' OR
       COALESCE(b.address, '') ILIKE '%' || search_text || '%' OR
       COALESCE(b.gc_contact_name, '') ILIKE '%' || search_text || '%')
     LIMIT 25)
  ) sub
  ORDER BY (CASE WHEN sub.hcp_number = '' THEN 1 ELSE 0 END), sub.hcp_number DESC
$$;


ALTER FUNCTION "public"."search_jobs_for_reports"("search_text" "text") OWNER TO "postgres";

