-- Name: FUNCTION "search_jobs_for_reports"("search_text" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."search_jobs_for_reports"("search_text" "text") IS 'New Report search: jobs_ledger, projects, and bids; RLS not applied (SECURITY DEFINER) — use only for typeahead.';


--
-- Name: search_jobs_for_tally_mercury_assign("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_jobs_for_tally_mercury_assign"("search_text" "text" DEFAULT ''::"text") RETURNS TABLE("id" "uuid", "hcp_number" "text", "job_name" "text", "job_address" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    jl.id,
    COALESCE(jl.hcp_number, '')::text,
    COALESCE(jl.job_name, '')::text,
    COALESCE(jl.job_address, '')::text
  FROM public.jobs_ledger jl
  WHERE (
    search_text IS NULL OR search_text = ''
    OR jl.hcp_number ILIKE '%' || search_text || '%'
    OR (
      length(search_text) >= 2
      AND lower(left(search_text, 1)) = 'j'
      AND jl.hcp_number ILIKE '%' || substring(search_text from 2) || '%'
    )
    OR jl.job_name ILIKE '%' || search_text || '%'
    OR jl.job_address ILIKE '%' || search_text || '%'
  )
  AND (
    NOT EXISTS (
      SELECT 1 FROM public.users u
      WHERE u.id = auth.uid() AND u.role IN ('helpers', 'subcontractor')
    )
    OR EXISTS (
      SELECT 1 FROM public.jobs_ledger_team_members jtm
      WHERE jtm.job_id = jl.id AND jtm.user_id = auth.uid()
    )
  )
  ORDER BY (CASE WHEN jl.hcp_number = '' OR jl.hcp_number IS NULL THEN 1 ELSE 0 END), jl.hcp_number DESC
  LIMIT 50;
$$;


ALTER FUNCTION "public"."search_jobs_for_tally_mercury_assign"("search_text" "text") OWNER TO "postgres";

