--
-- Name: FUNCTION "search_jobs_for_tally_mercury_assign_as_user"("p_for_user_id" "uuid", "search_text" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."search_jobs_for_tally_mercury_assign_as_user"("p_for_user_id" "uuid", "search_text" "text") IS 'Staff tally assign: staff_can_view required; dev/is_dev/master_technician/assistant = all jobs_ledger rows matching search_text (LIMIT 50) for any target role; otherwise subcontractor target = team visibility for target, non-sub target = invoker jl visibility.';


--
-- Name: search_jobs_ledger("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_jobs_ledger"("search_text" "text" DEFAULT ''::"text") RETURNS TABLE("id" "uuid", "service_type_id" "uuid", "service_type_name" "text", "hcp_number" "text", "job_name" "text", "job_address" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    jl.id,
    jl.service_type_id,
    COALESCE(stj.name, '')::TEXT AS service_type_name,
    COALESCE(jl.hcp_number, '')::TEXT,
    COALESCE(jl.job_name, '')::TEXT,
    COALESCE(jl.job_address, '')::TEXT
  FROM public.jobs_ledger jl
  LEFT JOIN public.service_types stj ON stj.id = jl.service_type_id
  WHERE (
    search_text IS NULL OR search_text = ''
    OR jl.hcp_number ILIKE '%' || search_text || '%'
    OR (
      length(search_text) >= 2
      AND lower(left(search_text, 1)) = 'j'
      AND jl.hcp_number ILIKE '%' || substring(search_text from 2) || '%'
    )
    OR jl.job_name ILIKE '%' || search_text || '%'
    OR jl.job_address ILIKE '%' || search_text || '%'
    OR EXISTS (
      SELECT 1
      FROM public.service_types st
      WHERE st.ledger_job_prefix IS NOT NULL
        AND btrim(st.ledger_job_prefix) <> ''
        AND coalesce(search_text, '') <> ''
        AND length(search_text) > length(btrim(st.ledger_job_prefix))
        AND lower(search_text) LIKE lower(btrim(st.ledger_job_prefix)) || '%'
        AND jl.hcp_number ILIKE '%' || substring(search_text from length(btrim(st.ledger_job_prefix)) + 1) || '%'
    )
  )
  ORDER BY (CASE WHEN jl.hcp_number = '' OR jl.hcp_number IS NULL THEN 1 ELSE 0 END), jl.hcp_number DESC
  LIMIT 50;
$$;


ALTER FUNCTION "public"."search_jobs_ledger"("search_text" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "search_jobs_ledger"("search_text" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."search_jobs_ledger"("search_text" "text") IS 'Search jobs_ledger by HCP, job name, or address. J prefix and ledger_job_prefix normalized; returns service_type_id and service_type_name.';


--
-- Name: service_apply_agreed_write_down_from_stripe("uuid", numeric, "text", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."service_apply_agreed_write_down_from_stripe"("p_invoice_id" "uuid", "p_new_amount" numeric, "p_note" "text", "p_stripe_credit_note_id" "text", "p_actor_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_applied numeric;
  v_old numeric;
  v_note_trim text;
  v_cn_trim text;
  v_eps constant numeric := 0.005;
BEGIN
  IF p_actor_user_id IS NULL THEN
    RETURN jsonb_build_object('error', 'Missing actor user id');
  END IF;

  v_note_trim := NULLIF(trim(COALESCE(p_note, '')), '');
  IF v_note_trim IS NULL OR length(v_note_trim) < 3 THEN
    RETURN jsonb_build_object('error', 'Note is required (at least 3 characters)');
  END IF;

  v_cn_trim := NULLIF(trim(COALESCE(p_stripe_credit_note_id, '')), '');
  IF v_cn_trim IS NULL OR v_cn_trim !~ '^cn_' THEN
    RETURN jsonb_build_object('error', 'Valid Stripe credit note id (cn_…) is required');
  END IF;

  IF p_new_amount IS NULL OR p_new_amount <= 0 THEN
    RETURN jsonb_build_object('error', 'New amount must be positive');
  END IF;

  SELECT
    i.id,
    i.job_id,
    i.amount,
    i.status,
    i.stripe_invoice_id
  INTO v_invoice
  FROM public.jobs_ledger_invoices i
  WHERE i.id = p_invoice_id;

  IF v_invoice.id IS NULL THEN
    RETURN jsonb_build_object('error', 'Invoice not found');
  END IF;

  IF v_invoice.status <> 'billed' THEN
    RETURN jsonb_build_object('error', 'Invoice must be in Billed status');
  END IF;

  IF COALESCE(trim(v_invoice.stripe_invoice_id), '') = '' THEN
    RETURN jsonb_build_object('error', 'Invoice has no Stripe invoice');
  END IF;

  v_old := round(coalesce(v_invoice.amount, 0), 2);
  IF p_new_amount > v_old + v_eps THEN
    RETURN jsonb_build_object('error', 'New amount cannot exceed the current billed amount');
  END IF;

  SELECT coalesce(sum(amount), 0) INTO v_applied
  FROM public.jobs_ledger_payments
  WHERE invoice_id = p_invoice_id;

  IF p_new_amount + v_eps < round(v_applied, 2) THEN
    RETURN jsonb_build_object(
      'error',
      'New amount cannot be less than payments already applied to this invoice'
    );
  END IF;

  UPDATE public.jobs_ledger_invoices
  SET
    amount = round(p_new_amount, 2),
    agreed_write_down_previous_amount = v_old,
    agreed_write_down_note = v_note_trim,
    agreed_write_down_at = now(),
    agreed_write_down_by = p_actor_user_id,
    agreed_write_down_stripe_credit_note_id = v_cn_trim,
    status = CASE
      WHEN round(v_applied, 2) >= round(p_new_amount, 2) - v_eps THEN 'paid'::text
      ELSE status
    END
  WHERE id = p_invoice_id;

  IF round(v_applied, 2) >= round(p_new_amount, 2) - v_eps THEN
    UPDATE public.jobs_ledger j
    SET
      status = CASE
        WHEN coalesce(j.revenue, 0) <= coalesce(j.payments_made, 0) + v_eps THEN 'paid'::text
        ELSE j.status
      END,
      updated_at = now()
    WHERE j.id = v_invoice.job_id;
  END IF;

  RETURN jsonb_build_object('ok', true);
END;
$$;


ALTER FUNCTION "public"."service_apply_agreed_write_down_from_stripe"("p_invoice_id" "uuid", "p_new_amount" numeric, "p_note" "text", "p_stripe_credit_note_id" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "service_apply_agreed_write_down_from_stripe"("p_invoice_id" "uuid", "p_new_amount" numeric, "p_note" "text", "p_stripe_credit_note_id" "text", "p_actor_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."service_apply_agreed_write_down_from_stripe"("p_invoice_id" "uuid", "p_new_amount" numeric, "p_note" "text", "p_stripe_credit_note_id" "text", "p_actor_user_id" "uuid") IS 'Called from Edge after Stripe Credit Note; service_role only. Syncs jobs_ledger_invoices.amount and audit fields.';


