--
-- Name: set_mercury_transaction_ar_returned("uuid", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_mercury_transaction_ar_returned"("p_mercury_transaction_id" "uuid", "p_returned" boolean) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'set_mercury_transaction_ar_returned: not authenticated';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users u
    WHERE u.id = auth.uid()
      AND u.role IN ('dev', 'master_technician', 'assistant', 'primary')
  ) THEN
    RAISE EXCEPTION 'set_mercury_transaction_ar_returned: not authorized';
  END IF;

  IF p_mercury_transaction_id IS NULL THEN
    RAISE EXCEPTION 'set_mercury_transaction_ar_returned: mercury transaction required';
  END IF;

  IF p_returned THEN
    INSERT INTO public.mercury_transaction_ar_returned (mercury_transaction_id, returned, updated_by)
    VALUES (p_mercury_transaction_id, true, auth.uid())
    ON CONFLICT (mercury_transaction_id) DO UPDATE SET
      returned = excluded.returned,
      updated_at = now(),
      updated_by = excluded.updated_by;
  ELSE
    DELETE FROM public.mercury_transaction_ar_returned
    WHERE mercury_transaction_id = p_mercury_transaction_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."set_mercury_transaction_ar_returned"("p_mercury_transaction_id" "uuid", "p_returned" boolean) OWNER TO "postgres";

--
-- Name: FUNCTION "set_mercury_transaction_ar_returned"("p_mercury_transaction_id" "uuid", "p_returned" boolean); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."set_mercury_transaction_ar_returned"("p_mercury_transaction_id" "uuid", "p_returned" boolean) IS 'Jobs AR Bank Payments: mark or unmark a Mercury transaction as returned (bounced deposit). Dev/master/assistant/primary only.';


--
-- Name: set_mercury_transaction_duplicate("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_mercury_transaction_duplicate"("p_duplicate_id" "uuid", "p_keeper_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  uid uuid := auth.uid();
begin
  if uid is null then
    raise exception 'set_mercury_transaction_duplicate: not authenticated';
  end if;
  if not exists (
    select 1 from public.users u
    where u.id = uid and u.role in ('dev', 'master_technician', 'assistant')
  ) then
    raise exception 'set_mercury_transaction_duplicate: not authorized';
  end if;
  if p_duplicate_id = p_keeper_id then
    raise exception 'set_mercury_transaction_duplicate: a transaction cannot be a duplicate of itself';
  end if;
  if not exists (select 1 from public.mercury_transactions where id = p_keeper_id) then
    raise exception 'set_mercury_transaction_duplicate: keeper transaction not found';
  end if;
  if exists (
    select 1 from public.mercury_transactions
    where id = p_keeper_id and duplicate_of_transaction_id is not null
  ) then
    raise exception 'set_mercury_transaction_duplicate: keeper is itself marked a duplicate';
  end if;
  update public.mercury_transactions
    set duplicate_of_transaction_id = p_keeper_id
    where id = p_duplicate_id;
  if not found then
    raise exception 'set_mercury_transaction_duplicate: duplicate transaction not found';
  end if;
end;
$$;


ALTER FUNCTION "public"."set_mercury_transaction_duplicate"("p_duplicate_id" "uuid", "p_keeper_id" "uuid") OWNER TO "postgres";

