--
-- Name: split_job_ledger_fixtures_to_new_job("uuid", "uuid"[], "text", "text", "text", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."split_job_ledger_fixtures_to_new_job"("p_source_job_id" "uuid", "p_fixture_ids" "uuid"[], "p_new_hcp" "text", "p_new_job_name" "text", "p_new_job_address" "text", "p_clock_session_ids" "uuid"[] DEFAULT ARRAY[]::"uuid"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_src public.jobs_ledger%ROWTYPE;
  v_new_job_id uuid;
  v_split_revenue numeric(14, 2);
  v_total_fixtures int;
  v_move_n int;
  v_new_hcp text;
  v_new_name text;
  v_new_addr text;
  v_blocked_reason text;
  v_bad_fixture int;
  v_bad_session int;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'code', 'not_authenticated', 'error', 'Not authenticated');
  END IF;

  v_new_hcp := trim(COALESCE(p_new_hcp, ''));
  v_new_name := trim(COALESCE(p_new_job_name, ''));
  v_new_addr := trim(COALESCE(p_new_job_address, ''));

  IF p_source_job_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'code', 'invalid_args', 'error', 'Source job is required');
  END IF;

  IF p_fixture_ids IS NULL OR cardinality(p_fixture_ids) = 0 THEN
    RETURN jsonb_build_object('ok', false, 'code', 'invalid_args', 'error', 'Select at least one Specific Work line to move');
  END IF;

  IF v_new_hcp = '' OR v_new_name = '' OR v_new_addr = '' THEN
    RETURN jsonb_build_object('ok', false, 'code', 'invalid_args', 'error', 'New HCP, job name, and address are required');
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.jobs_ledger WHERE id = p_source_job_id) THEN
    RETURN jsonb_build_object('ok', false, 'code', 'not_found', 'error', 'Job not found');
  END IF;

  IF NOT (
    EXISTS (
      SELECT 1 FROM public.users
      WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant')
    )
    AND EXISTS (
      SELECT 1 FROM public.jobs_ledger jl
      WHERE jl.id = p_source_job_id
      AND (
        jl.master_user_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = jl.master_user_id)
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = jl.master_user_id AND assistant_id = auth.uid())
        OR public.assistants_share_master(auth.uid(), jl.master_user_id)
      )
    )
  ) THEN
    RETURN jsonb_build_object('ok', false, 'code', 'not_authorized', 'error', 'Not authorized to split this job');
  END IF;

  SELECT CASE
    WHEN jl.status IS DISTINCT FROM 'working' THEN 'Only Working jobs can be split with this tool.'
    WHEN COALESCE(jl.payments_made, 0) <> 0 THEN 'Clear or resolve recorded payments on this job before splitting.'
    WHEN EXISTS (SELECT 1 FROM public.jobs_ledger_invoices i WHERE i.job_id = p_source_job_id) THEN
      'Remove or resolve invoices on this job before splitting.'
    WHEN EXISTS (SELECT 1 FROM public.jobs_ledger_payments p WHERE p.job_id = p_source_job_id) THEN
      'Remove or resolve payments on this job before splitting.'
    WHEN EXISTS (SELECT 1 FROM public.job_collect_payment_flows c WHERE c.job_id = p_source_job_id) THEN
      'Finish or cancel the in-app collect payment flow for this job before splitting.'
    ELSE NULL
  END INTO v_blocked_reason
  FROM public.jobs_ledger jl
  WHERE jl.id = p_source_job_id;

  IF v_blocked_reason IS NOT NULL THEN
    RETURN jsonb_build_object('ok', false, 'code', 'billing_blocked', 'error', v_blocked_reason);
  END IF;

  SELECT COUNT(*) INTO v_total_fixtures
  FROM public.jobs_ledger_fixtures f
  WHERE f.job_id = p_source_job_id;

  SELECT COUNT(DISTINCT x.id)::int INTO v_move_n
  FROM unnest(p_fixture_ids) AS x(id);

  IF v_total_fixtures = 0 THEN
    RETURN jsonb_build_object('ok', false, 'code', 'invalid_args', 'error', 'Source job has no Specific Work lines to split.');
  END IF;

  IF v_move_n >= v_total_fixtures THEN
    RETURN jsonb_build_object(
      'ok', false,
      'code', 'invalid_args',
      'error',
      'Leave at least one Specific Work line on the original job, or use Combine / Migrate instead of split.'
    );
  END IF;

  SELECT COUNT(*) INTO v_bad_fixture
  FROM unnest(p_fixture_ids) AS x(id)
  LEFT JOIN public.jobs_ledger_fixtures f ON f.id = x.id AND f.job_id = p_source_job_id
  WHERE f.id IS NULL;

  IF v_bad_fixture > 0 THEN
    RETURN jsonb_build_object('ok', false, 'code', 'invalid_fixtures', 'error', 'One or more lines are missing or do not belong to this job.');
  END IF;

  IF p_clock_session_ids IS NOT NULL AND cardinality(p_clock_session_ids) > 0 THEN
    SELECT COUNT(*) INTO v_bad_session
    FROM unnest(p_clock_session_ids) AS x(id)
    LEFT JOIN public.clock_sessions cs ON cs.id = x.id AND cs.job_ledger_id = p_source_job_id
    WHERE cs.id IS NULL;

    IF v_bad_session > 0 THEN
      RETURN jsonb_build_object(
        'ok', false,
        'code', 'invalid_sessions',
        'error',
        'One or more clock sessions are missing or not linked to this job.'
      );
    END IF;
  END IF;

  SELECT COALESCE(
    ROUND(
      SUM(
        CASE
          WHEN trim(COALESCE(f.name, '')) = '' THEN 0::numeric
          ELSE
            (
              CASE
                WHEN f.count IS NOT NULL AND f.count > 0 THEN f.count::numeric
                ELSE 1::numeric
              END
            ) * COALESCE(f.line_unit_price, 0::numeric)
        END
      )::numeric,
      2
    ),
    0::numeric
  ) INTO v_split_revenue
  FROM public.jobs_ledger_fixtures f
  WHERE f.job_id = p_source_job_id AND f.id = ANY (p_fixture_ids);

  BEGIN
    SELECT * INTO v_src FROM public.jobs_ledger jl WHERE jl.id = p_source_job_id FOR UPDATE;

    INSERT INTO public.jobs_ledger (
      master_user_id,
      customer_id,
      customer_name,
      customer_email,
      customer_phone,
      project_id,
      service_type_id,
      bid_id,
      hcp_number,
      job_name,
      job_address,
      google_drive_link,
      job_plans_link,
      job_pictures_link,
      status,
      revenue,
      payments_made,
      pct_complete,
      last_bill_date,
      last_work_date
    )
    VALUES (
      v_src.master_user_id,
      v_src.customer_id,
      v_src.customer_name,
      v_src.customer_email,
      v_src.customer_phone,
      v_src.project_id,
      v_src.service_type_id,
      v_src.bid_id,
      v_new_hcp,
      v_new_name,
      v_new_addr,
      v_src.google_drive_link,
      v_src.job_plans_link,
      v_src.job_pictures_link,
      'working',
      v_split_revenue,
      0,
      NULL,
      NULL,
      NULL
    )
    RETURNING id INTO v_new_job_id;

    UPDATE public.jobs_ledger_fixtures f
    SET job_id = v_new_job_id
    WHERE f.id = ANY (p_fixture_ids);

    IF p_clock_session_ids IS NOT NULL AND cardinality(p_clock_session_ids) > 0 THEN
      UPDATE public.clock_sessions cs
      SET job_ledger_id = v_new_job_id
      WHERE cs.id = ANY (p_clock_session_ids);
    END IF;

    UPDATE public.jobs_ledger jl
    SET revenue = GREATEST(0::numeric, COALESCE(jl.revenue, 0) - v_split_revenue)
    WHERE jl.id = p_source_job_id;

    INSERT INTO public.jobs_ledger_team_members (job_id, user_id)
    SELECT v_new_job_id, jtm.user_id
    FROM public.jobs_ledger_team_members jtm
    WHERE jtm.job_id = p_source_job_id
    ON CONFLICT (job_id, user_id) DO NOTHING;

    RETURN jsonb_build_object('ok', true, 'new_job_id', v_new_job_id, 'split_revenue', v_split_revenue);
  EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'code', 'split_failed', 'error', SQLERRM);
  END;
END;
$$;


ALTER FUNCTION "public"."split_job_ledger_fixtures_to_new_job"("p_source_job_id" "uuid", "p_fixture_ids" "uuid"[], "p_new_hcp" "text", "p_new_job_name" "text", "p_new_job_address" "text", "p_clock_session_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "split_job_ledger_fixtures_to_new_job"("p_source_job_id" "uuid", "p_fixture_ids" "uuid"[], "p_new_hcp" "text", "p_new_job_name" "text", "p_new_job_address" "text", "p_clock_session_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."split_job_ledger_fixtures_to_new_job"("p_source_job_id" "uuid", "p_fixture_ids" "uuid"[], "p_new_hcp" "text", "p_new_job_name" "text", "p_new_job_address" "text", "p_clock_session_ids" "uuid"[]) IS 'Creates a new working jobs_ledger row (copied customer/project/trade links), moves selected fixtures and optional clock_sessions, adjusts revenue on both jobs, copies team members. Source must be working with no invoices/payments/collect flow.';


--
-- Name: split_own_clock_session_cluster("uuid"[], "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."split_own_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb") RETURNS TABLE("inserted_ids" "uuid"[], "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_tz text := 'America/Chicago';
  v_today date;
  v_week_start date;
  v_week_end date;
  v_prev_week_start date;
  v_prev_week_end date;
  v_cnt int;
  v_first public.clock_sessions%ROWTYPE;
  v_last public.clock_sessions%ROWTYPE;
  v_prev public.clock_sessions%ROWTYPE;
  v_rec public.clock_sessions%ROWTYPE;
  v_first_iter boolean := true;
  v_gap_ok boolean;
  v_n int;
  v_i int;
  v_elem jsonb;
  v_in timestamptz;
  v_out timestamptz;
  v_out_null boolean;
  v_notes text;
  v_person_name text;
  v_hours numeric;
  v_new_hours numeric;
  v_eps double precision := 1.0;
  v_min_h numeric := 0.01;
  v_prev_out timestamptz;
  v_is_open_block boolean;
  v_ids uuid[] := ARRAY[]::uuid[];
  v_new_id uuid;
  v_work date;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Not authenticated'::text;
    RETURN;
  END IF;

  IF p_session_ids IS NULL OR array_length(p_session_ids, 1) IS NULL OR array_length(p_session_ids, 1) < 1 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least one session id'::text;
    RETURN;
  END IF;

  IF jsonb_typeof(p_segments) <> 'array' OR jsonb_array_length(p_segments) < 2 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least two segments'::text;
    RETURN;
  END IF;

  SELECT count(DISTINCT x)::int INTO v_cnt FROM unnest(p_session_ids) AS x;
  IF v_cnt <> array_length(p_session_ids, 1) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Duplicate session ids'::text;
    RETURN;
  END IF;

  SELECT count(*)::int INTO v_cnt FROM public.clock_sessions WHERE id = ANY (p_session_ids);
  IF v_cnt <> array_length(p_session_ids, 1) THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'One or more sessions not found'::text;
    RETURN;
  END IF;

  v_today := (now() AT TIME ZONE v_tz)::date;
  v_week_start := v_today - EXTRACT(DOW FROM v_today)::integer;
  v_week_end := v_week_start + 6;
  v_prev_week_start := v_week_start - 7;
  v_prev_week_end := v_week_end - 7;

  v_prev := NULL;
  FOR v_rec IN
    SELECT * FROM public.clock_sessions
    WHERE id = ANY (p_session_ids)
    ORDER BY clocked_in_at ASC
    FOR UPDATE
  LOOP
    IF v_rec.user_id <> v_uid THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Access denied'::text;
      RETURN;
    END IF;
    IF v_rec.rejected_at IS NOT NULL THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Rejected sessions cannot be split'::text;
      RETURN;
    END IF;
    IF v_rec.revoked_at IS NOT NULL THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Revoked sessions cannot be split'::text;
      RETURN;
    END IF;

    IF NOT (
      (v_rec.work_date >= v_week_start AND v_rec.work_date <= v_week_end)
      OR (v_rec.work_date >= v_prev_week_start AND v_rec.work_date <= v_prev_week_end)
    ) THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Session is outside the editable this or last week (America/Chicago)'::text;
      RETURN;
    END IF;

    IF v_first_iter THEN
      v_first := v_rec;
      v_first_iter := false;
    ELSE
      IF v_prev.job_ledger_id IS NOT DISTINCT FROM v_rec.job_ledger_id
         AND v_prev.bid_id IS NOT DISTINCT FROM v_rec.bid_id THEN
        NULL;
      ELSE
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Cluster sessions must share the same job and bid'::text;
        RETURN;
      END IF;
      IF v_prev.clocked_out_at IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final session in a cluster may be open'::text;
        RETURN;
      END IF;
      v_gap_ok := v_rec.clocked_in_at <= v_prev.clocked_out_at + interval '1 second';
      IF NOT v_gap_ok THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Sessions in cluster must be contiguous'::text;
        RETURN;
      END IF;
    END IF;
    v_prev := v_rec;
    v_last := v_rec;
  END LOOP;

  v_is_open_block := v_last.clocked_out_at IS NULL;
  v_n := jsonb_array_length(p_segments);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    IF v_elem IS NULL OR jsonb_typeof(v_elem) <> 'object' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Invalid segment payload'::text;
      RETURN;
    END IF;

    IF v_elem->>'clocked_in_at' IS NULL OR v_elem->>'clocked_in_at' = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment needs clocked_in_at'::text;
      RETURN;
    END IF;

    v_in := (v_elem->>'clocked_in_at')::timestamptz;

    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;

    v_notes := trim(both from coalesce(v_elem->>'notes', ''));
    IF v_notes = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Notes are required for each segment'::text;
      RETURN;
    END IF;

    IF v_i = 0 THEN
      IF abs(EXTRACT(EPOCH FROM (v_in - v_first.clocked_in_at))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'First segment must start at the original clock-in time'::text;
        RETURN;
      END IF;
    ELSE
      IF v_prev_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the last segment may be open (no clock-out)'::text;
        RETURN;
      END IF;
      IF abs(EXTRACT(EPOCH FROM (v_in - v_prev_out))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Segments must be contiguous'::text;
        RETURN;
      END IF;
    END IF;

    IF NOT v_is_open_block THEN
      IF v_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'All segments must be closed for a closed block'::text;
        RETURN;
      END IF;
      IF v_in >= v_out THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment must have clock-out after clock-in'::text;
        RETURN;
      END IF;
      IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
        RETURN;
      END IF;
      IF v_out > now() THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
        RETURN;
      END IF;
      v_prev_out := v_out;
    ELSE
      IF v_i < v_n - 1 THEN
        IF v_out IS NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final segment may be open for an open block'::text;
          RETURN;
        END IF;
        IF v_in >= v_out THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each closed part must have clock-out after clock-in'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
          RETURN;
        END IF;
        IF v_out > now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
          RETURN;
        END IF;
        v_prev_out := v_out;
      ELSE
        IF v_out IS NOT NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Final segment of an open block must stay open'::text;
          RETURN;
        END IF;
        IF v_in >= now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must start before now'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (now() - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must be at least 0.01 hours so far'::text;
          RETURN;
        END IF;
        v_prev_out := NULL;
      END IF;
    END IF;
  END LOOP;

  IF NOT v_is_open_block THEN
    IF abs(EXTRACT(EPOCH FROM (v_prev_out - v_last.clocked_out_at))) > v_eps THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Last segment must end at the original clock-out time'::text;
      RETURN;
    END IF;
  END IF;

  FOR v_rec IN
    SELECT * FROM public.clock_sessions
    WHERE id = ANY (p_session_ids)
    ORDER BY clocked_in_at ASC
  LOOP
    IF v_rec.approved_at IS NOT NULL AND v_rec.clocked_out_at IS NOT NULL THEN
      SELECT trim(both from u.name) INTO v_person_name
      FROM public.users u
      WHERE u.id = v_rec.user_id;

      IF v_person_name IS NULL OR v_person_name = '' THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'User has no name'::text;
        RETURN;
      END IF;

      v_hours := EXTRACT(EPOCH FROM (v_rec.clocked_out_at - v_rec.clocked_in_at)) / 3600.0;
      IF v_hours > 0 THEN
        PERFORM public.people_hours_subtract_approved_hours(
          v_rec.user_id,
          v_person_name,
          v_rec.work_date,
          v_hours,
          v_uid
        );
      END IF;

      IF v_rec.job_ledger_id IS NOT NULL THEN
        PERFORM public.sync_crew_jobs_from_clock(v_person_name, v_rec.work_date);
      END IF;
      IF v_rec.bid_id IS NOT NULL THEN
        PERFORM public.sync_crew_bids_from_clock(v_person_name, v_rec.work_date);
      END IF;
    END IF;
  END LOOP;

  DELETE FROM public.clock_sessions WHERE id = ANY (p_session_ids);

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    v_in := (v_elem->>'clocked_in_at')::timestamptz;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;
    v_notes := trim(both from coalesce(v_elem->>'notes', ''));

    v_work := (v_in AT TIME ZONE v_tz)::date;

    INSERT INTO public.clock_sessions (
      user_id,
      clocked_in_at,
      clocked_out_at,
      work_date,
      notes,
      job_ledger_id,
      bid_id,
      origin,
      salary_segment_index,
      clock_in_lat,
      clock_in_lng,
      clock_out_lat,
      clock_out_lng
    )
    VALUES (
      v_first.user_id,
      v_in,
      v_out,
      v_work,
      v_notes,
      v_first.job_ledger_id,
      v_first.bid_id,
      CASE
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NOT NULL THEN 'user_punch'
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NULL THEN 'salary_schedule'
        ELSE v_first.origin
      END,
      CASE
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NOT NULL THEN NULL
        WHEN v_first.origin = 'salary_schedule' AND v_first.salary_segment_index IS NULL AND v_n >= 2 THEN (v_i + 1)::smallint
        ELSE NULL
      END,
      NULL,
      NULL,
      NULL,
      NULL
    )
    RETURNING id INTO v_new_id;

    v_ids := array_append(v_ids, v_new_id);
  END LOOP;

  UPDATE public.clock_sessions
  SET clock_in_lat = v_first.clock_in_lat,
      clock_in_lng = v_first.clock_in_lng
  WHERE id = v_ids[1];

  FOR v_i IN REVERSE (v_n - 1) .. 0 LOOP
    v_elem := p_segments -> v_i;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      UPDATE public.clock_sessions
      SET clock_out_lat = v_last.clock_out_lat,
          clock_out_lng = v_last.clock_out_lng
      WHERE id = v_ids[v_i + 1];
      EXIT;
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_ids, NULL::text;
END;
$$;


ALTER FUNCTION "public"."split_own_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "split_own_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."split_own_clock_session_cluster"("p_session_ids" "uuid"[], "p_segments" "jsonb") IS 'Replace N contiguous same-job/bid clock sessions (owner) with M segments; current or previous Chicago week; approved rollback per removed row; new rows pending. Indexed salary_schedule children become user_punch.';


--
-- Name: split_own_clock_session_segments("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."split_own_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb") RETURNS TABLE("inserted_ids" "uuid"[], "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid;
  v_parent public.clock_sessions%ROWTYPE;
  v_tz text := 'America/Chicago';
  v_today date;
  v_week_start date;
  v_week_end date;
  v_n int;
  v_i int;
  v_elem jsonb;
  v_in timestamptz;
  v_out timestamptz;
  v_out_null boolean;
  v_notes text;
  v_person_name text;
  v_hours numeric;
  v_new_hours numeric;
  v_eps double precision := 1.0;
  v_min_h numeric := 0.01;
  v_prev_out timestamptz;
  v_is_open_parent boolean;
  v_ids uuid[] := ARRAY[]::uuid[];
  v_new_id uuid;
  v_work date;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Not authenticated'::text;
    RETURN;
  END IF;

  IF jsonb_typeof(p_segments) <> 'array' OR jsonb_array_length(p_segments) < 2 THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Expected at least two segments'::text;
    RETURN;
  END IF;

  v_today := (now() AT TIME ZONE v_tz)::date;
  v_week_start := v_today - EXTRACT(DOW FROM v_today)::integer;
  v_week_end := v_week_start + 6;

  SELECT * INTO v_parent
  FROM public.clock_sessions
  WHERE id = p_session_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Session not found'::text;
    RETURN;
  END IF;

  IF v_parent.user_id <> v_uid THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Access denied'::text;
    RETURN;
  END IF;

  IF v_parent.rejected_at IS NOT NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Rejected sessions cannot be split'::text;
    RETURN;
  END IF;

  IF v_parent.revoked_at IS NOT NULL THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Revoked sessions cannot be split'::text;
    RETURN;
  END IF;

  IF v_parent.work_date < v_week_start OR v_parent.work_date > v_week_end THEN
    RETURN QUERY SELECT ARRAY[]::uuid[], 'Session is outside the editable current week'::text;
    RETURN;
  END IF;

  v_is_open_parent := v_parent.clocked_out_at IS NULL;
  v_n := jsonb_array_length(p_segments);

  -- Validate each segment and contiguous coverage
  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    IF v_elem IS NULL OR jsonb_typeof(v_elem) <> 'object' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Invalid segment payload'::text;
      RETURN;
    END IF;

    IF v_elem->>'clocked_in_at' IS NULL OR v_elem->>'clocked_in_at' = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment needs clocked_in_at'::text;
      RETURN;
    END IF;

    v_in := (v_elem->>'clocked_in_at')::timestamptz;

    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;

    v_notes := trim(both from coalesce(v_elem->>'notes', ''));
    IF v_notes = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Notes are required for each segment'::text;
      RETURN;
    END IF;

    IF v_i = 0 THEN
      IF abs(EXTRACT(EPOCH FROM (v_in - v_parent.clocked_in_at))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'First segment must start at the original clock-in time'::text;
        RETURN;
      END IF;
    ELSE
      IF v_prev_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the last segment may be open (no clock-out)'::text;
        RETURN;
      END IF;
      IF abs(EXTRACT(EPOCH FROM (v_in - v_prev_out))) > v_eps THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Segments must be contiguous'::text;
        RETURN;
      END IF;
    END IF;

    IF NOT v_is_open_parent THEN
      IF v_out IS NULL THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'All segments must be closed for a closed session'::text;
        RETURN;
      END IF;
      IF v_in >= v_out THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each segment must have clock-out after clock-in'::text;
        RETURN;
      END IF;
      IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
        RETURN;
      END IF;
      IF v_out > now() THEN
        RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
        RETURN;
      END IF;
      v_prev_out := v_out;
    ELSE
      -- Open parent
      IF v_i < v_n - 1 THEN
        IF v_out IS NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Only the final segment may be open for an open session'::text;
          RETURN;
        END IF;
        IF v_in >= v_out THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each closed part must have clock-out after clock-in'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (v_out - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Each part must be at least 0.01 hours'::text;
          RETURN;
        END IF;
        IF v_out > now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Clock-out cannot be in the future'::text;
          RETURN;
        END IF;
        v_prev_out := v_out;
      ELSE
        IF v_out IS NOT NULL THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Final segment of an open session must stay open'::text;
          RETURN;
        END IF;
        IF v_in >= now() THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must start before now'::text;
          RETURN;
        END IF;
        IF (EXTRACT(EPOCH FROM (now() - v_in)) / 3600.0) < v_min_h THEN
          RETURN QUERY SELECT ARRAY[]::uuid[], 'Open segment must be at least 0.01 hours so far'::text;
          RETURN;
        END IF;
        v_prev_out := NULL;
      END IF;
    END IF;
  END LOOP;

  IF NOT v_is_open_parent THEN
    IF abs(EXTRACT(EPOCH FROM (v_prev_out - v_parent.clocked_out_at))) > v_eps THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'Last segment must end at the original clock-out time'::text;
      RETURN;
    END IF;
  END IF;

  -- Roll back approved hours (same as revoke, without setting revoked_at — we delete the row)
  IF v_parent.approved_at IS NOT NULL AND v_parent.clocked_out_at IS NOT NULL THEN
    SELECT trim(both from u.name) INTO v_person_name
    FROM public.users u
    WHERE u.id = v_parent.user_id;

    IF v_person_name IS NULL OR v_person_name = '' THEN
      RETURN QUERY SELECT ARRAY[]::uuid[], 'User has no name'::text;
      RETURN;
    END IF;

    v_hours := EXTRACT(EPOCH FROM (v_parent.clocked_out_at - v_parent.clocked_in_at)) / 3600.0;
    IF v_hours > 0 THEN
      PERFORM public.people_hours_subtract_approved_hours(
        v_parent.user_id,
        v_person_name,
        v_parent.work_date,
        v_hours,
        v_uid
      );
    END IF;

    IF v_parent.job_ledger_id IS NOT NULL THEN
      PERFORM public.sync_crew_jobs_from_clock(v_person_name, v_parent.work_date);
    END IF;
    IF v_parent.bid_id IS NOT NULL THEN
      PERFORM public.sync_crew_bids_from_clock(v_person_name, v_parent.work_date);
    END IF;
  END IF;

  DELETE FROM public.clock_sessions WHERE id = p_session_id;

  FOR v_i IN 0 .. (v_n - 1) LOOP
    v_elem := p_segments -> v_i;
    v_in := (v_elem->>'clocked_in_at')::timestamptz;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      v_out := (v_elem->>'clocked_out_at')::timestamptz;
    ELSE
      v_out := NULL;
    END IF;
    v_notes := trim(both from coalesce(v_elem->>'notes', ''));

    v_work := (v_in AT TIME ZONE v_tz)::date;

    INSERT INTO public.clock_sessions (
      user_id,
      clocked_in_at,
      clocked_out_at,
      work_date,
      notes,
      job_ledger_id,
      bid_id,
      origin,
      salary_segment_index,
      clock_in_lat,
      clock_in_lng,
      clock_out_lat,
      clock_out_lng
    )
    VALUES (
      v_parent.user_id,
      v_in,
      v_out,
      v_work,
      v_notes,
      v_parent.job_ledger_id,
      v_parent.bid_id,
      CASE
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NOT NULL THEN 'user_punch'
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NULL THEN 'salary_schedule'
        ELSE v_parent.origin
      END,
      CASE
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NOT NULL THEN NULL
        WHEN v_parent.origin = 'salary_schedule' AND v_parent.salary_segment_index IS NULL AND v_n >= 2 THEN (v_i + 1)::smallint
        ELSE NULL
      END,
      NULL,
      NULL,
      NULL,
      NULL
    )
    RETURNING id INTO v_new_id;

    v_ids := array_append(v_ids, v_new_id);
  END LOOP;

  UPDATE public.clock_sessions
  SET clock_in_lat = v_parent.clock_in_lat,
      clock_in_lng = v_parent.clock_in_lng
  WHERE id = v_ids[1];

  FOR v_i IN REVERSE (v_n - 1) .. 0 LOOP
    v_elem := p_segments -> v_i;
    v_out_null := (v_elem->'clocked_out_at' IS NULL)
      OR (v_elem->>'clocked_out_at' IS NOT NULL AND v_elem->>'clocked_out_at' = '');
    IF NOT v_out_null THEN
      UPDATE public.clock_sessions
      SET clock_out_lat = v_parent.clock_out_lat,
          clock_out_lng = v_parent.clock_out_lng
      WHERE id = v_ids[v_i + 1];
      EXIT;
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_ids, NULL::text;
END;
$$;


ALTER FUNCTION "public"."split_own_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "split_own_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."split_own_clock_session_segments"("p_session_id" "uuid", "p_segments" "jsonb") IS 'Replace own clock session with N contiguous segments inside the original span; current week (America/Chicago). Approved sessions: people_hours rollback + crew sync, then delete; new rows pending. Indexed salary_schedule children become user_punch.';


--
-- Name: staff_can_view_user_for_tally_followup("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."staff_can_view_user_for_tally_followup"("p_viewer" "uuid", "p_target" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role text;
BEGIN
  IF p_viewer IS NULL OR p_target IS NULL THEN
    RETURN false;
  END IF;
  IF p_viewer = p_target THEN
    RETURN true;
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = p_viewer;
  IF v_role IS NULL THEN
    RETURN false;
  END IF;

  IF public.is_dev() OR v_role = 'dev' THEN
    RETURN true;
  END IF;

  IF v_role = 'master_technician' THEN
    RETURN EXISTS (
      SELECT 1 FROM public.master_assistants ma
      WHERE ma.master_id = p_viewer AND ma.assistant_id = p_target
    )
    OR EXISTS (
      SELECT 1
      FROM public.jobs_ledger jl
      INNER JOIN public.jobs_ledger_team_members jtm
        ON jtm.job_id = jl.id AND jtm.user_id = p_target
      WHERE jl.master_user_id = p_viewer
    );
  END IF;

  IF v_role = 'assistant' THEN
    RETURN public.assistants_share_master(p_viewer, p_target)
      OR EXISTS (
        SELECT 1 FROM public.master_assistants ma
        WHERE ma.master_id = p_target AND ma.assistant_id = p_viewer
      )
      OR EXISTS (
        SELECT 1
        FROM public.jobs_ledger jl
        INNER JOIN public.jobs_ledger_team_members jtm
          ON jtm.job_id = jl.id AND jtm.user_id = p_target
        WHERE jl.master_user_id IN (
          SELECT ma2.master_id
          FROM public.master_assistants ma2
          WHERE ma2.assistant_id = p_viewer
        )
      );
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."staff_can_view_user_for_tally_followup"("p_viewer" "uuid", "p_target" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "staff_can_view_user_for_tally_followup"("p_viewer" "uuid", "p_target" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."staff_can_view_user_for_tally_followup"("p_viewer" "uuid", "p_target" "uuid") IS 'Whether p_viewer may list or assign tally for p_target''s linked-card Mercury rows: dev/is_dev() any target; master_technician adopted assistants or team on viewer''s jobs; assistant adopting masters + assistants_share_master + team on jobs for any adopted master; otherwise false.';


--
-- Name: subcontractor_can_read_jobs_ledger_row("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."subcontractor_can_read_jobs_ledger_row"("p_job_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    EXISTS (
      SELECT 1 FROM public.users
      WHERE id = auth.uid() AND role IN ('helpers', 'subcontractor')
    )
    AND (
      EXISTS (
        SELECT 1 FROM public.jobs_ledger_team_members jtm
        WHERE jtm.job_id = p_job_id AND jtm.user_id = auth.uid()
      )
      OR EXISTS (
        SELECT 1 FROM public.job_schedule_blocks jsb
        WHERE jsb.job_id = p_job_id AND jsb.assignee_user_id = auth.uid()
      )
    );
$$;


ALTER FUNCTION "public"."subcontractor_can_read_jobs_ledger_row"("p_job_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "subcontractor_can_read_jobs_ledger_row"("p_job_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."subcontractor_can_read_jobs_ledger_row"("p_job_id" "uuid") IS 'True when caller is helpers/subcontractor and on job team or is Dispatch assignee for p_job_id. SECURITY DEFINER avoids jobs_ledger RLS recursion.';


--
-- Name: submit_collect_payment_certification("uuid", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."submit_collect_payment_certification"("p_job_id" "uuid", "p_mode" "text", "p_correction_notes" "text" DEFAULT NULL::"text", "p_per_line_notes" "jsonb" DEFAULT NULL::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
  v_notes text;
  v_rtb_invoice_id uuid;
  v_row public.job_collect_payment_flows%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('error', 'not_authenticated');
  END IF;

  SELECT u.role INTO v_role FROM public.users u WHERE u.id = v_uid;
  IF v_role IS NULL OR v_role NOT IN ('subcontractor', 'helpers') THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  IF p_mode IS NULL OR p_mode NOT IN ('clean', 'correction_requested') THEN
    RETURN jsonb_build_object('error', 'Invalid certify mode');
  END IF;

  v_notes := NULLIF(trim(COALESCE(p_correction_notes, '')), '');
  IF p_mode = 'correction_requested' AND (v_notes IS NULL OR length(v_notes) < 3) THEN
    RETURN jsonb_build_object('error', 'Describe the correction needed (at least 3 characters).');
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.jobs_ledger_team_members jtm
    INNER JOIN public.jobs_ledger jl ON jl.id = jtm.job_id
    WHERE jtm.user_id = v_uid
      AND jl.id = p_job_id
      AND jl.status = 'ready_to_bill'
  ) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  SELECT i.id INTO v_rtb_invoice_id
  FROM public.jobs_ledger_invoices i
  WHERE i.job_id = p_job_id
    AND i.status = 'ready_to_bill'
  ORDER BY i.created_at DESC NULLS LAST
  LIMIT 1;

  SELECT * INTO v_row FROM public.job_collect_payment_flows WHERE job_id = p_job_id FOR UPDATE;

  IF FOUND THEN
    IF v_row.status = 'approved_for_terminal' THEN
      RETURN jsonb_build_object('error', 'Payment is approved for terminal. Complete collection or ask office to reset.');
    END IF;
    IF v_row.status NOT IN (
      'draft',
      'pending_dispatch',
      'terminal_completed',
      'failed',
      'cancelled'
    ) THEN
      RETURN jsonb_build_object('error', 'Invalid flow state for submit');
    END IF;

    UPDATE public.job_collect_payment_flows
    SET
      initiated_by_user_id = v_uid,
      jobs_ledger_invoice_id = v_rtb_invoice_id,
      status = 'pending_dispatch',
      certify_mode = p_mode,
      correction_notes = CASE WHEN p_mode = 'correction_requested' THEN v_notes ELSE NULL END,
      per_line_notes = p_per_line_notes,
      certified_at = now(),
      dispatch_reviewed_at = NULL,
      dispatch_reviewed_by = NULL,
      dispatch_notes = NULL,
      stripe_payment_intent_id = NULL,
      stripe_invoice_id = NULL,
      last_error = NULL
    WHERE job_id = p_job_id;

    RETURN jsonb_build_object('ok', true, 'status', 'pending_dispatch');
  END IF;

  INSERT INTO public.job_collect_payment_flows (
    job_id,
    initiated_by_user_id,
    jobs_ledger_invoice_id,
    status,
    certify_mode,
    correction_notes,
    per_line_notes,
    certified_at
  )
  VALUES (
    p_job_id,
    v_uid,
    v_rtb_invoice_id,
    'pending_dispatch',
    p_mode,
    CASE WHEN p_mode = 'correction_requested' THEN v_notes ELSE NULL END,
    p_per_line_notes,
    now()
  );

  RETURN jsonb_build_object('ok', true, 'status', 'pending_dispatch');
END;
$$;


ALTER FUNCTION "public"."submit_collect_payment_certification"("p_job_id" "uuid", "p_mode" "text", "p_correction_notes" "text", "p_per_line_notes" "jsonb") OWNER TO "postgres";

--
-- Name: FUNCTION "submit_collect_payment_certification"("p_job_id" "uuid", "p_mode" "text", "p_correction_notes" "text", "p_per_line_notes" "jsonb"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."submit_collect_payment_certification"("p_job_id" "uuid", "p_mode" "text", "p_correction_notes" "text", "p_per_line_notes" "jsonb") IS 'Helpers/subcontractor: certify or request correction; sets flow to pending_dispatch.';


