--
-- Name: superintendent_report_job_anchor_allowed("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."superintendent_report_job_anchor_allowed"("p_job_ledger_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    SET "row_security" TO 'off'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.jobs_ledger jl
    WHERE jl.id = p_job_ledger_id
      AND (
        (
          jl.project_id IS NOT NULL
          AND public.can_access_project_row(jl.project_id)
        )
        OR EXISTS (
          SELECT 1
          FROM public.jobs_ledger_team_members jtm
          WHERE jtm.job_id = jl.id
            AND jtm.user_id = auth.uid()
        )
      )
  );
$$;


ALTER FUNCTION "public"."superintendent_report_job_anchor_allowed"("p_job_ledger_id" "uuid") OWNER TO "postgres";

