--
-- Name: sync_denormalized_pay_names_from_people(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_denormalized_pay_names_from_people"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' AND NEW.name IS DISTINCT FROM OLD.name THEN
    UPDATE public.people_pay_config
    SET person_name = btrim(NEW.name)
    WHERE person_id = NEW.id;

    UPDATE public.people_hours
    SET person_name = btrim(NEW.name)
    WHERE person_id = NEW.id;
  END IF;
  RETURN NEW;
END;
$$;


