--
-- Name: sync_salary_clock_sessions_for_user_day("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_salary_clock_sessions_for_user_day"("p_user_id" "uuid", "p_work_date" "date") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT (
    auth.uid() = p_user_id
    OR public.is_dev()
    OR public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant()
  ) THEN
    RAISE EXCEPTION 'not authorized' USING ERRCODE = '42501';
  END IF;
  PERFORM public.salary_sync_one_user_clock_sessions(p_user_id, p_work_date - 1, now());
  PERFORM public.salary_sync_one_user_clock_sessions(p_user_id, p_work_date, now());
END;
$$;


