--
-- Name: sync_supply_house_invoice_paid_at(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_supply_house_invoice_paid_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.is_paid = true AND NEW.paid_at IS NULL THEN
      NEW.paid_at = NOW();
    END IF;
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF NEW.is_paid = true AND OLD.is_paid = false THEN
      IF NEW.paid_at IS NULL OR NEW.paid_at IS NOT DISTINCT FROM OLD.paid_at THEN
        NEW.paid_at = NOW();
      END IF;
    ELSIF NEW.is_paid = false AND OLD.is_paid = true THEN
      NEW.paid_at = NULL;
    END IF;
    RETURN NEW;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_supply_house_invoice_paid_at"() OWNER TO "postgres";

--
-- Name: team_feedback_aggregates_by_manager(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."team_feedback_aggregates_by_manager"() RETURNS TABLE("cycle_period_start" "date", "manager_user_id" "uuid", "submission_count" bigint, "avg_likert_1" numeric, "avg_likert_2" numeric, "avg_likert_3" numeric, "avg_likert_4" numeric, "avg_likert_5" numeric, "avg_overall_1_10" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF public.is_dev() THEN
    RETURN QUERY
    SELECT
      s.cycle_period_start,
      s.manager_user_id,
      COUNT(*)::bigint,
      ROUND(AVG(s.manager_likert_1)::numeric, 2),
      ROUND(AVG(s.manager_likert_2)::numeric, 2),
      ROUND(AVG(s.manager_likert_3)::numeric, 2),
      ROUND(AVG(s.manager_likert_4)::numeric, 2),
      ROUND(AVG(s.manager_likert_5)::numeric, 2),
      ROUND(AVG(s.manager_overall_1_10)::numeric, 2)
    FROM public.team_feedback_submissions s
    WHERE s.manager_likert_1 IS NOT NULL
      AND s.cycle_period_start IS NOT NULL
    GROUP BY s.cycle_period_start, s.manager_user_id;
    RETURN;
  END IF;

  IF NOT public.is_pay_approved_master() THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    s.cycle_period_start,
    s.manager_user_id,
    COUNT(*)::bigint,
    ROUND(AVG(s.manager_likert_1)::numeric, 2),
    ROUND(AVG(s.manager_likert_2)::numeric, 2),
    ROUND(AVG(s.manager_likert_3)::numeric, 2),
    ROUND(AVG(s.manager_likert_4)::numeric, 2),
    ROUND(AVG(s.manager_likert_5)::numeric, 2),
    ROUND(AVG(s.manager_overall_1_10)::numeric, 2)
  FROM public.team_feedback_submissions s
  WHERE s.manager_likert_1 IS NOT NULL
    AND s.cycle_period_start IS NOT NULL
    AND s.manager_user_id = auth.uid()
  GROUP BY s.cycle_period_start, s.manager_user_id;
END;
$$;


ALTER FUNCTION "public"."team_feedback_aggregates_by_manager"() OWNER TO "postgres";

