--
-- Name: track_price_history(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."track_price_history"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  change_percent NUMERIC(10, 2);
  old_price_val NUMERIC(10, 2);
BEGIN
  -- Determine old price based on trigger type
  IF TG_OP = 'INSERT' THEN
    old_price_val := NULL;
    change_percent := NULL;
  ELSIF TG_OP = 'UPDATE' THEN
    old_price_val := OLD.price;
    -- Calculate percentage change if old price exists and is greater than 0
    IF old_price_val IS NOT NULL AND old_price_val > 0 THEN
      change_percent := ((NEW.price - old_price_val) / old_price_val) * 100;
    ELSE
      change_percent := NULL;
    END IF;
  END IF;

  -- Insert history record
  INSERT INTO public.material_part_price_history (
    part_id,
    supply_house_id,
    old_price,
    new_price,
    price_change_percent,
    effective_date,
    changed_by
  ) VALUES (
    NEW.part_id,
    NEW.supply_house_id,
    old_price_val,
    NEW.price,
    change_percent,
    NEW.effective_date,
    auth.uid()
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."track_price_history"() OWNER TO "postgres";

--
-- Name: FUNCTION "track_price_history"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."track_price_history"() IS 'Automatically tracks price changes in material_part_price_history table when prices are inserted or updated. Calculates percentage change when old price exists.';


--
-- Name: update_bids_count_rows_order("uuid", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_bids_count_rows_order"("p_bid_id" "uuid", "p_ordered_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.can_access_bid_for_pricing(p_bid_id) THEN
    RAISE EXCEPTION 'Access denied to bid';
  END IF;

  -- Update sequence_order for each id by its index (0-based) in the array
  UPDATE public.bids_count_rows bcr
  SET sequence_order = ord.seq - 1
  FROM unnest(p_ordered_ids) WITH ORDINALITY AS ord(id, seq)
  WHERE bcr.id = ord.id AND bcr.bid_id = p_bid_id;
END;
$$;


ALTER FUNCTION "public"."update_bids_count_rows_order"("p_bid_id" "uuid", "p_ordered_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: FUNCTION "update_bids_count_rows_order"("p_bid_id" "uuid", "p_ordered_ids" "uuid"[]); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."update_bids_count_rows_order"("p_bid_id" "uuid", "p_ordered_ids" "uuid"[]) IS 'Batch-update sequence_order for count rows. Used by Bids Counts drag reorder.';


--
-- Name: update_bids_count_rows_order("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_bids_count_rows_order"("p_bids_count_id" "uuid", "p_new_order" integer) RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_bid_id uuid;
  v_old_order int;
  v_min_order int;
  v_max_order int;
BEGIN
  SELECT bid_id, "order" INTO v_bid_id, v_old_order
  FROM public.bids_count
  WHERE id = p_bids_count_id;

  IF v_bid_id IS NULL THEN
    RETURN;
  END IF;

  IF p_new_order = v_old_order THEN
    RETURN;
  END IF;

  SELECT COALESCE(MIN("order"), 0), COALESCE(MAX("order"), 0)
  INTO v_min_order, v_max_order
  FROM public.bids_count
  WHERE bid_id = v_bid_id;

  p_new_order := GREATEST(v_min_order, LEAST(v_max_order, p_new_order));

  IF p_new_order < v_old_order THEN
    UPDATE public.bids_count
    SET "order" = "order" + 1
    WHERE bid_id = v_bid_id
      AND "order" >= p_new_order
      AND "order" < v_old_order;
  ELSE
    UPDATE public.bids_count
    SET "order" = "order" - 1
    WHERE bid_id = v_bid_id
      AND "order" > v_old_order
      AND "order" <= p_new_order;
  END IF;

  UPDATE public.bids_count
  SET "order" = p_new_order
  WHERE id = p_bids_count_id;
END;
$$;


ALTER FUNCTION "public"."update_bids_count_rows_order"("p_bids_count_id" "uuid", "p_new_order" integer) OWNER TO "postgres";

