-- Name: FUNCTION "update_bids_count_rows_order"("p_bids_count_id" "uuid", "p_new_order" integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."update_bids_count_rows_order"("p_bids_count_id" "uuid", "p_new_order" integer) IS 'Reorders a bids_count row within its bid. Shifts other rows to make room.';


--
-- Name: update_contract_book_entry("uuid", "text", "text", "text", "text"[], "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_contract_book_entry"("p_contract_template_document_id" "uuid", "p_document_name" "text", "p_book_body_html" "text", "p_book_body_format" "text", "p_tags" "text"[], "p_canonical_document_url" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_old_name text;
  v_template_id uuid;
  v_trim_name text;
  v_canon text;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT (
    public.is_dev()
    OR public.is_pay_approved_master()
    OR public.is_assistant_of_pay_approved_master()
    OR public.is_assistant()
  ) THEN
    RAISE EXCEPTION 'Not allowed';
  END IF;

  SELECT c.document_name, c.template_id
  INTO v_old_name, v_template_id
  FROM public.contract_template_documents c
  WHERE c.id = p_contract_template_document_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Contract template document not found';
  END IF;

  v_trim_name := trim(p_document_name);
  IF v_trim_name = '' THEN
    RAISE EXCEPTION 'Document name is required';
  END IF;

  v_canon := NULLIF(trim(p_canonical_document_url), '');

  IF EXISTS (
    SELECT 1
    FROM public.contract_template_documents d
    WHERE d.template_id = v_template_id
      AND d.id <> p_contract_template_document_id
      AND lower(trim(d.document_name)) = lower(v_trim_name)
  ) THEN
    RAISE EXCEPTION 'A document with this name already exists for that template.';
  END IF;

  IF v_trim_name IS DISTINCT FROM v_old_name THEN
    BEGIN
      UPDATE public.person_contract_documents p
      SET
        document_name = v_trim_name,
        updated_at = NOW()
      WHERE p.document_name = v_old_name
        AND EXISTS (
          SELECT 1
          FROM public.person_contract_assignments a
          WHERE a.template_id = v_template_id
            AND a.person_name = p.person_name
        );
    EXCEPTION
      WHEN unique_violation THEN
        RAISE EXCEPTION 'A contract with this name already exists for one or more people; resolve the conflict in People → Contracts.';
    END;
  END IF;

  UPDATE public.contract_template_documents
  SET
    document_name = v_trim_name,
    book_body_html = p_book_body_html,
    book_body_format = p_book_body_format,
    tags = p_tags,
    canonical_document_url = v_canon
  WHERE id = p_contract_template_document_id;

  PERFORM public.create_pending_contract_versions_after_book_save(p_contract_template_document_id);
END;
$$;


ALTER FUNCTION "public"."update_contract_book_entry"("p_contract_template_document_id" "uuid", "p_document_name" "text", "p_book_body_html" "text", "p_book_body_format" "text", "p_tags" "text"[], "p_canonical_document_url" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "update_contract_book_entry"("p_contract_template_document_id" "uuid", "p_document_name" "text", "p_book_body_html" "text", "p_book_body_format" "text", "p_tags" "text"[], "p_canonical_document_url" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."update_contract_book_entry"("p_contract_template_document_id" "uuid", "p_document_name" "text", "p_book_body_html" "text", "p_book_body_format" "text", "p_tags" "text"[], "p_canonical_document_url" "text") IS 'Updates a Contract Book row; renames matching person rows when document_name changes; then creates pending re-sign rows for signed assignees. Does not overwrite existing unsigned person rows. Pay-staff only. SECURITY DEFINER.';


--
-- Name: update_job_status("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_job_status"("p_job_id" "uuid", "p_to_status" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_status TEXT;
  v_master_id UUID;
  v_can_update BOOLEAN := false;
  v_deleted_rtb INTEGER := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('error', 'Not authenticated');
  END IF;

  SELECT jl.status, jl.master_user_id INTO v_current_status, v_master_id
  FROM public.jobs_ledger jl
  WHERE jl.id = p_job_id;

  IF v_current_status IS NULL THEN
    RETURN jsonb_build_object('error', 'Job not found');
  END IF;

  IF p_to_status = 'ready_to_bill' THEN
    IF v_current_status = 'working' THEN
      v_can_update :=
        (
          EXISTS (SELECT 1 FROM public.jobs_ledger_team_members WHERE job_id = p_job_id AND user_id = auth.uid())
          AND NOT EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'helpers')
        )
        OR (EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
          AND (v_master_id = auth.uid()
            OR public.is_dev()
            OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
            OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
            OR public.assistants_share_master(auth.uid(), v_master_id)))
        OR (EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'superintendent')
          AND EXISTS (
            SELECT 1 FROM public.jobs_ledger jl2
            JOIN public.projects p ON p.id = jl2.project_id
            WHERE jl2.id = p_job_id
              AND (EXISTS (SELECT 1 FROM public.project_superintendents WHERE project_id = p.id AND superintendent_id = auth.uid())
                OR EXISTS (SELECT 1 FROM public.master_superintendents WHERE master_id = p.master_user_id AND superintendent_id = auth.uid()))
          ));
    ELSIF v_current_status = 'billed' THEN
      v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
        AND (v_master_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), v_master_id));
    ELSE
      RETURN jsonb_build_object('error', 'Job must be in Working or Billed to mark Ready for Billing');
    END IF;
  ELSIF p_to_status = 'billed' THEN
    IF v_current_status = 'ready_to_bill' THEN
      v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
        AND (v_master_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), v_master_id));
    ELSIF v_current_status = 'paid' THEN
      -- Revert: paid -> billed (dev/master/assistant/primary with job access)
      v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant', 'primary'))
        AND (v_master_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'primary')
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), v_master_id));
    ELSE
      RETURN jsonb_build_object('error', 'Job must be in Ready to Bill or Paid to mark as Billed');
    END IF;
  ELSIF p_to_status = 'paid' THEN
    IF v_current_status <> 'billed' THEN
      RETURN jsonb_build_object('error', 'Job must be in Billed to mark as Paid');
    END IF;
    v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
      AND (v_master_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
        OR public.assistants_share_master(auth.uid(), v_master_id));
  ELSIF p_to_status = 'working' THEN
    IF v_current_status = 'ready_to_bill' THEN
      -- Revert: ready_to_bill -> working (office only; deletes RTB drafts below)
      v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
        AND (v_master_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), v_master_id));
    ELSIF v_current_status = 'waiting' THEN
      -- Manual promote: waiting -> working (office only; no side effects)
      v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
        AND (v_master_id = auth.uid()
          OR public.is_dev()
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
          OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
          OR public.assistants_share_master(auth.uid(), v_master_id));
    ELSE
      RETURN jsonb_build_object('error', 'Job must be in Ready to Bill or Waiting to move to Working');
    END IF;
  ELSIF p_to_status = 'waiting' THEN
    -- Send back: working -> waiting (office only; no side effects)
    IF v_current_status <> 'working' THEN
      RETURN jsonb_build_object('error', 'Job must be in Working to send back to Waiting');
    END IF;
    v_can_update := EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role IN ('dev', 'master_technician', 'assistant'))
      AND (v_master_id = auth.uid()
        OR public.is_dev()
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = auth.uid() AND assistant_id = v_master_id)
        OR EXISTS (SELECT 1 FROM public.master_assistants WHERE master_id = v_master_id AND assistant_id = auth.uid())
        OR public.assistants_share_master(auth.uid(), v_master_id));
  ELSE
    RETURN jsonb_build_object('error', 'Invalid status');
  END IF;

  IF NOT v_can_update THEN
    RETURN jsonb_build_object('error', 'Not authorized to update job status');
  END IF;

  IF p_to_status = 'working' AND v_current_status = 'ready_to_bill' THEN
    DELETE FROM public.jobs_ledger_invoices
    WHERE job_id = p_job_id
      AND status = 'ready_to_bill';
    GET DIAGNOSTICS v_deleted_rtb = ROW_COUNT;
  END IF;

  UPDATE public.jobs_ledger SET status = p_to_status, updated_at = NOW() WHERE id = p_job_id;

  INSERT INTO public.job_status_events (job_id, from_status, to_status, changed_by_user_id)
  VALUES (p_job_id, v_current_status, p_to_status, auth.uid());

  RETURN jsonb_build_object('ok', true, 'deleted_ready_to_bill_invoices', v_deleted_rtb);
END;
$$;


ALTER FUNCTION "public"."update_job_status"("p_job_id" "uuid", "p_to_status" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "update_job_status"("p_job_id" "uuid", "p_to_status" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."update_job_status"("p_job_id" "uuid", "p_to_status" "text") IS 'Updates job status. Forward: waiting->working (office; also auto via clock-out trigger), working->ready_to_bill (team/office/superintendent; helpers cannot use team path), ready_to_bill->billed, billed->paid (office). Revert: working->waiting, ready_to_bill->working (deletes RTB draft invoices), billed->ready_to_bill, paid->billed (dev/master/assistant/primary with job access).';


--
-- Name: update_step_assigned_to("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_step_assigned_to"("p_step_id" "uuid", "p_assigned_to_name" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Access check: dev, master, owner, adopted, shared, OR assistant (assigned or can_access)
  IF NOT (
    public.can_access_project_via_step(p_step_id)
    OR (
      EXISTS (SELECT 1 FROM public.users WHERE id = auth.uid() AND role = 'assistant')
      AND (
        EXISTS (
          SELECT 1 FROM public.project_workflow_steps s
          JOIN public.users u ON u.id = auth.uid() AND u.name IS NOT NULL
            AND LOWER(TRIM(u.name)) = LOWER(TRIM(s.assigned_to_name))
          WHERE s.id = p_step_id
        )
        OR public.can_access_project_via_workflow(
          (SELECT workflow_id FROM public.project_workflow_steps WHERE id = p_step_id)
        )
      )
    )
  ) THEN
    RAISE EXCEPTION 'Permission denied';
  END IF;

  UPDATE public.project_workflow_steps
  SET assigned_to_name = p_assigned_to_name
  WHERE id = p_step_id;
END;
$$;


