--
-- Name: upsert_mercury_org_transaction_note("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_mercury_org_transaction_note"("p_mercury_transaction_id" "uuid", "p_body" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  uid uuid := auth.uid();
  v_body text := trim(both FROM coalesce(p_body, ''));
BEGIN
  IF uid IS NULL THEN
    RAISE EXCEPTION 'upsert_mercury_org_transaction_note: not authenticated';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.users
    WHERE id = uid AND role IN ('dev', 'master_technician', 'assistant')
  ) THEN
    RAISE EXCEPTION 'upsert_mercury_org_transaction_note: not authorized';
  END IF;

  IF char_length(v_body) > 2000 THEN
    RAISE EXCEPTION 'upsert_mercury_org_transaction_note: note too long';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.mercury_transactions t WHERE t.id = p_mercury_transaction_id
  ) THEN
    RAISE EXCEPTION 'upsert_mercury_org_transaction_note: transaction not found';
  END IF;

  IF v_body = '' THEN
    DELETE FROM public.mercury_transaction_org_notes
    WHERE mercury_transaction_id = p_mercury_transaction_id;
    RETURN;
  END IF;

  INSERT INTO public.mercury_transaction_org_notes (
    mercury_transaction_id,
    body,
    updated_at,
    updated_by
  )
  VALUES (p_mercury_transaction_id, v_body, now(), uid)
  ON CONFLICT (mercury_transaction_id)
  DO UPDATE SET
    body = excluded.body,
    updated_at = now(),
    updated_by = uid;
END;
$$;


ALTER FUNCTION "public"."upsert_mercury_org_transaction_note"("p_mercury_transaction_id" "uuid", "p_body" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "upsert_mercury_org_transaction_note"("p_mercury_transaction_id" "uuid", "p_body" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."upsert_mercury_org_transaction_note"("p_mercury_transaction_id" "uuid", "p_body" "text") IS 'Insert/update/delete (empty body) organization Banking note for a Mercury transaction. Roles: dev, master_technician, assistant.';


--
-- Name: upsert_mercury_tally_transaction_note("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_mercury_tally_transaction_note"("p_mercury_transaction_id" "uuid", "p_body" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  uid uuid := auth.uid();
  v_body text := trim(both FROM coalesce(p_body, ''));
BEGIN
  IF uid IS NULL THEN
    RAISE EXCEPTION 'upsert_mercury_tally_transaction_note: not authenticated';
  END IF;

  IF char_length(v_body) > 2000 THEN
    RAISE EXCEPTION 'upsert_mercury_tally_transaction_note: note too long';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.mercury_transactions t
    INNER JOIN public.mercury_debit_card_user_links l
      ON l.user_id = uid
      AND l.mercury_debit_card_id = public.mercury_debit_card_id_from_raw(t.raw)
    WHERE t.id = p_mercury_transaction_id
  ) THEN
    RAISE EXCEPTION 'upsert_mercury_tally_transaction_note: transaction not visible for tally';
  END IF;

  IF v_body = '' THEN
    DELETE FROM public.mercury_tally_transaction_notes
    WHERE mercury_transaction_id = p_mercury_transaction_id
      AND user_id = uid;
    RETURN;
  END IF;

  INSERT INTO public.mercury_tally_transaction_notes (
    mercury_transaction_id,
    user_id,
    body,
    updated_at
  )
  VALUES (p_mercury_transaction_id, uid, v_body, now())
  ON CONFLICT (mercury_transaction_id, user_id)
  DO UPDATE SET
    body = excluded.body,
    updated_at = now();
END;
$$;


ALTER FUNCTION "public"."upsert_mercury_tally_transaction_note"("p_mercury_transaction_id" "uuid", "p_body" "text") OWNER TO "postgres";

