--
-- Name: user_review_rows("date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."user_review_rows"("p_start_ymd" "date" DEFAULT NULL::"date", "p_end_ymd" "date" DEFAULT NULL::"date") RETURNS TABLE("id" "uuid", "amount" numeric, "counterparty_id" "uuid", "counterparty_name" "text", "created_at" timestamp with time zone, "currency" "text", "dashboard_link" "text", "external_memo" "text", "kind" "text", "mercury_account_id" "uuid", "mercury_category" "jsonb", "mercury_id" "uuid", "note" "text", "posted_at" timestamp with time zone, "status" "text", "synced_at" timestamp with time zone, "user_id" "uuid", "user_name" "text", "person_id" "uuid", "person_name" "text", "label_id" "uuid")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select
    t.id, t.amount, t.counterparty_id, t.counterparty_name, t.created_at, t.currency,
    t.dashboard_link, t.external_memo, t.kind, t.mercury_account_id, t.mercury_category,
    t.mercury_id, t.note, t.posted_at, t.status, t.synced_at,
    att.user_id, u.name as user_name, att.person_id, p.name as person_name,
    a.label_id
  from public.mercury_transactions t
  left join public.mercury_transaction_attributions att on att.mercury_transaction_id = t.id
  left join public.users  u on u.id = att.user_id
  left join public.people p on p.id = att.person_id
  left join public.mercury_transaction_drag_sort_assignments a on a.mercury_transaction_id = t.id
  where t.duplicate_of_transaction_id is null
    and (
      p_start_ymd is null
      or (
        t.posted_at is not null
        and (t.posted_at at time zone 'America/Chicago')::date between p_start_ymd and p_end_ymd
      )
    )
  order by t.posted_at desc nulls last, t.id desc;
$$;


ALTER FUNCTION "public"."user_review_rows"("p_start_ymd" "date", "p_end_ymd" "date") OWNER TO "postgres";

--
-- Name: validate_pay_stub_payments_vs_net("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."validate_pay_stub_payments_vs_net"("p_stub" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_gross numeric;
  v_ded numeric;
  v_add numeric;
  v_paid numeric;
  v_net numeric;
BEGIN
  IF p_stub IS NULL THEN
    RETURN;
  END IF;
  SELECT gross_pay INTO v_gross FROM public.pay_stubs WHERE id = p_stub;
  IF v_gross IS NULL THEN
    RETURN;
  END IF;
  SELECT COALESCE(SUM(amount), 0) INTO v_ded FROM public.pay_stub_deductions WHERE pay_stub_id = p_stub;
  SELECT COALESCE(SUM(line_total), 0) INTO v_add FROM public.pay_stub_additional_lines WHERE pay_stub_id = p_stub;
  SELECT COALESCE(SUM(amount), 0) INTO v_paid FROM public.pay_stub_payments WHERE pay_stub_id = p_stub;
  v_net := v_gross - v_ded + v_add;
  IF v_paid > v_net + 0.01 THEN
    RAISE EXCEPTION 'pay_stub_payments total (%) exceeds net pay (%) for stub %', v_paid, v_net, p_stub;
  END IF;
END;
$$;


ALTER FUNCTION "public"."validate_pay_stub_payments_vs_net"("p_stub" "uuid") OWNER TO "postgres";

