--

CREATE TABLE IF NOT EXISTS "public"."mercury_drag_sort_labels" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "name" "text" NOT NULL,
    "sort_order" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "schedule_c_line" "text",
    "description" "text",
    "is_system_default" boolean DEFAULT false NOT NULL,
    "default_key" "text",
    "account_type" "text",
    CONSTRAINT "mercury_drag_sort_labels_account_type_chk" CHECK ((("account_type" IS NULL) OR ("account_type" = ANY (ARRAY['asset'::"text", 'liability'::"text", 'equity'::"text", 'income'::"text", 'expense'::"text", 'transfer'::"text"])))),
    CONSTRAINT "mercury_drag_sort_labels_default_key_len_chk" CHECK ((("default_key" IS NULL) OR (("char_length"("default_key") >= 1) AND ("char_length"("default_key") <= 64)))),
    CONSTRAINT "mercury_drag_sort_labels_description_len_chk" CHECK ((("description" IS NULL) OR ("char_length"("description") <= 2000))),
    CONSTRAINT "mercury_drag_sort_labels_name_check" CHECK ((("char_length"(TRIM(BOTH FROM "name")) >= 1) AND ("char_length"("name") <= 120))),
    CONSTRAINT "mercury_drag_sort_labels_schedule_c_line_len_chk" CHECK ((("schedule_c_line" IS NULL) OR (("char_length"(TRIM(BOTH FROM "schedule_c_line")) >= 1) AND ("char_length"("schedule_c_line") <= 32)))),
    CONSTRAINT "mercury_drag_sort_labels_system_default_key_consistency_chk" CHECK (((("is_system_default" = false) AND ("default_key" IS NULL)) OR (("is_system_default" = true) AND ("default_key" IS NOT NULL))))
);


