--
-- Name: salary_work_schedule_day_overrides; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."salary_work_schedule_day_overrides" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "work_date" "date" NOT NULL,
    "timezone" "text",
    "mode" "text",
    "segment_a_start_local" time without time zone,
    "segment_a_duration_minutes" integer,
    "segment_b_start_local" time without time zone,
    "segment_b_duration_minutes" integer,
    "use_split_focus" boolean,
    "job_ledger_id" "uuid",
    "bid_id" "uuid",
    "segment_b_job_ledger_id" "uuid",
    "segment_b_bid_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "salary_override_continuous_duration" CHECK ((("mode" IS NULL) OR ("mode" = 'split'::"text") OR ("segment_a_duration_minutes" IS NULL) OR ("segment_a_duration_minutes" = 480))),
    CONSTRAINT "salary_override_split_requires_b" CHECK ((("mode" IS NULL) OR ("mode" = 'continuous'::"text") OR (("segment_b_start_local" IS NOT NULL) AND ("segment_b_duration_minutes" IS NOT NULL)))),
    CONSTRAINT "salary_override_split_sum" CHECK ((("mode" IS NULL) OR ("mode" = 'continuous'::"text") OR ("segment_a_duration_minutes" IS NULL) OR ("segment_b_duration_minutes" IS NULL) OR (("segment_a_duration_minutes" + "segment_b_duration_minutes") = 480))),
    CONSTRAINT "salary_work_schedule_day_overr_segment_a_duration_minutes_check" CHECK ((("segment_a_duration_minutes" IS NULL) OR (("segment_a_duration_minutes" > 0) AND (("segment_a_duration_minutes" % 15) = 0)))),
    CONSTRAINT "salary_work_schedule_day_overr_segment_b_duration_minutes_check" CHECK ((("segment_b_duration_minutes" IS NULL) OR (("segment_b_duration_minutes" > 0) AND (("segment_b_duration_minutes" % 15) = 0)))),
    CONSTRAINT "salary_work_schedule_day_overrides_mode_check" CHECK ((("mode" IS NULL) OR ("mode" = ANY (ARRAY['continuous'::"text", 'split'::"text"]))))
);


ALTER TABLE "public"."salary_work_schedule_day_overrides" OWNER TO "postgres";

--
-- Name: TABLE "salary_work_schedule_day_overrides"; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE "public"."salary_work_schedule_day_overrides" IS 'Per-day overrides; NULL field means inherit template. Owners may write today (Chicago date) only; pay roles any date.';


--
-- Name: salary_work_schedule_templates; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."salary_work_schedule_templates" (
    "user_id" "uuid" NOT NULL,
    "timezone" "text" DEFAULT 'America/Chicago'::"text" NOT NULL,
    "mode" "text" NOT NULL,
    "segment_a_start_local" time without time zone NOT NULL,
    "segment_a_duration_minutes" integer DEFAULT 480 NOT NULL,
    "segment_b_start_local" time without time zone,
    "segment_b_duration_minutes" integer,
    "use_split_focus" boolean DEFAULT false NOT NULL,
    "job_ledger_id" "uuid",
    "bid_id" "uuid",
    "segment_b_job_ledger_id" "uuid",
    "segment_b_bid_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "exclude_weekends" boolean DEFAULT true NOT NULL,
    CONSTRAINT "salary_template_continuous_duration" CHECK ((("mode" = 'split'::"text") OR ("segment_a_duration_minutes" = 480))),
    CONSTRAINT "salary_template_split_requires_b" CHECK ((("mode" = 'continuous'::"text") OR (("segment_b_start_local" IS NOT NULL) AND ("segment_b_duration_minutes" IS NOT NULL)))),
    CONSTRAINT "salary_template_split_sum" CHECK ((("mode" = 'continuous'::"text") OR (("segment_a_duration_minutes" + "segment_b_duration_minutes") = 480))),
    CONSTRAINT "salary_work_schedule_templates_mode_check" CHECK (("mode" = ANY (ARRAY['continuous'::"text", 'split'::"text"]))),
    CONSTRAINT "salary_work_schedule_templates_segment_a_duration_minutes_check" CHECK ((("segment_a_duration_minutes" > 0) AND (("segment_a_duration_minutes" % 15) = 0))),
    CONSTRAINT "salary_work_schedule_templates_segment_b_duration_minutes_check" CHECK ((("segment_b_duration_minutes" IS NULL) OR (("segment_b_duration_minutes" > 0) AND (("segment_b_duration_minutes" % 15) = 0))))
);


ALTER TABLE "public"."salary_work_schedule_templates" OWNER TO "postgres";

