    CONSTRAINT "schedule_share_recurring_days_nonempty" CHECK ((("cardinality"("days_of_week") >= 1) AND ("cardinality"("days_of_week") <= 7))),
    CONSTRAINT "schedule_share_recurring_scope_check" CHECK (("scope" = ANY (ARRAY['none'::"text", 'next_day'::"text", 'rest_of_week'::"text"])))
);


