    "answers" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "submitted_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "writeups_disclosure_when_submitted" CHECK ((("status" = 'draft'::"text") OR ("disclosure" IS NOT NULL))),
    CONSTRAINT "writeups_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'submitted'::"text"]))),
    CONSTRAINT "writeups_submitted_at_when_submitted" CHECK (((("status" = 'submitted'::"text") AND ("submitted_at" IS NOT NULL)) OR (("status" = 'draft'::"text") AND ("submitted_at" IS NULL))))
);


