--
-- Name: projects Assistants and above can insert projects; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Assistants and above can insert projects" ON "public"."projects" FOR INSERT WITH CHECK (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role", 'assistant'::"public"."user_role"]))))) AND ((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR ((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'assistant'::"public"."user_role")))) AND (EXISTS ( SELECT 1
   FROM "public"."master_assistants"
  WHERE (("master_assistants"."master_id" = "projects"."master_user_id") AND ("master_assistants"."assistant_id" = ( SELECT "auth"."uid"() AS "uid")))))))));


--
-- Name: projects Assistants and above can update projects; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Assistants and above can update projects" ON "public"."projects" FOR UPDATE USING (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role", 'assistant'::"public"."user_role"]))))) AND (("master_user_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (EXISTS ( SELECT 1
   FROM "public"."master_assistants"
  WHERE (("master_assistants"."master_id" = "projects"."master_user_id") AND ("master_assistants"."assistant_id" = ( SELECT "auth"."uid"() AS "uid")))))))) WITH CHECK (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role", 'assistant'::"public"."user_role"]))))) AND ((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (("master_user_id" IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM "public"."master_assistants"
  WHERE (("master_assistants"."master_id" = "projects"."master_user_id") AND ("master_assistants"."assistant_id" = ( SELECT "auth"."uid"() AS "uid"))))))) AND (EXISTS ( SELECT 1
   FROM "public"."customers"
  WHERE (("customers"."id" = "projects"."customer_id") AND (("customers"."master_user_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
           FROM "public"."users"
          WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (EXISTS ( SELECT 1
           FROM "public"."master_assistants"
          WHERE (("master_assistants"."master_id" = "customers"."master_user_id") AND ("master_assistants"."assistant_id" = ( SELECT "auth"."uid"() AS "uid")))))))))));


