--
-- Name: purchase_orders Devs and masters can add notes to finalized purchase orders; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Devs and masters can add notes to finalized purchase orders" ON "public"."purchase_orders" FOR UPDATE USING (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) AND (("created_by" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'dev'::"public"."user_role"))))) AND ("status" = 'finalized'::"text") AND ("notes" IS NULL))) WITH CHECK (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) AND (("created_by" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'dev'::"public"."user_role"))))) AND ("status" = 'finalized'::"text") AND ("notes" IS NOT NULL) AND ("notes_added_by" = ( SELECT "auth"."uid"() AS "uid")) AND ("notes_added_at" IS NOT NULL)));


