   FROM ("public"."project_workflows" "pw"
     JOIN "public"."projects" "p" ON (("p"."id" = "pw"."project_id")))
  WHERE (("pw"."id" = "workflow_projections"."workflow_id") AND (("p"."master_user_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
           FROM "public"."users" "u"
          WHERE (("u"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("u"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (EXISTS ( SELECT 1
           FROM "public"."master_assistants" "ma"
          WHERE (("ma"."master_id" = "p"."master_user_id") AND ("ma"."assistant_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
           FROM "public"."master_shares" "ms"
          WHERE (("ms"."sharing_master_id" = "p"."master_user_id") AND ("ms"."viewing_master_id" = ( SELECT "auth"."uid"() AS "uid")))))))))));


