--
-- Name: project_workflow_steps Subcontractors can update their assigned project_workflow_steps; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Subcontractors can update their assigned project_workflow_steps" ON "public"."project_workflow_steps" FOR UPDATE USING ((("assigned_to_name" IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM "public"."users" "u"
  WHERE (("u"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("u"."role" = ANY (ARRAY['helpers'::"public"."user_role", 'subcontractor'::"public"."user_role"])) AND ("u"."name" IS NOT NULL) AND ("lower"(TRIM(BOTH FROM "u"."name")) = "lower"(TRIM(BOTH FROM "project_workflow_steps"."assigned_to_name")))))))) WITH CHECK ((("assigned_to_name" IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM "public"."users" "u"
  WHERE (("u"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("u"."role" = ANY (ARRAY['helpers'::"public"."user_role", 'subcontractor'::"public"."user_role"])) AND ("u"."name" IS NOT NULL) AND ("lower"(TRIM(BOTH FROM "u"."name")) = "lower"(TRIM(BOTH FROM "project_workflow_steps"."assigned_to_name"))))))));


