CREATE POLICY "Superintendent can do all on reports (assigned projects)" ON "public"."reports" USING (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'superintendent'::"public"."user_role")))) AND ((("project_id" IS NOT NULL) AND "public"."can_access_project_row"("project_id")) OR (("job_ledger_id" IS NOT NULL) AND "public"."superintendent_report_job_anchor_allowed"("job_ledger_id")) OR (("bid_id" IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM "public"."bids" "b"
  WHERE (("b"."id" = "reports"."bid_id") AND "public"."superintendent_can_access_bid"("b".*)))))))) WITH CHECK (((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'superintendent'::"public"."user_role")))) AND ((("project_id" IS NOT NULL) AND "public"."can_access_project_row"("project_id")) OR (("job_ledger_id" IS NOT NULL) AND "public"."superintendent_report_job_anchor_allowed"("job_ledger_id")) OR (("bid_id" IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM "public"."bids" "b"
  WHERE (("b"."id" = "reports"."bid_id") AND "public"."superintendent_can_access_bid"("b".*))))))));


