--
-- Name: project_workflows Users can insert workflows for projects they have access to; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Users can insert workflows for projects they have access to" ON "public"."project_workflows" FOR INSERT WITH CHECK ((((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role", 'assistant'::"public"."user_role"]))))) AND (EXISTS ( SELECT 1
   FROM "public"."projects" "p"
  WHERE (("p"."id" = "project_workflows"."project_id") AND (("p"."master_user_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
           FROM "public"."users" "u"
          WHERE (("u"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("u"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (EXISTS ( SELECT 1
           FROM "public"."master_assistants" "ma"
          WHERE (("ma"."master_id" = "p"."master_user_id") AND ("ma"."assistant_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
           FROM "public"."master_shares" "ms"
          WHERE (("ms"."sharing_master_id" = "p"."master_user_id") AND ("ms"."viewing_master_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
           FROM "public"."customers" "c"
          WHERE (("c"."id" = "p"."customer_id") AND (("c"."master_user_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
                   FROM "public"."users" "u2"
                  WHERE (("u2"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("u2"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (EXISTS ( SELECT 1
                   FROM "public"."master_assistants" "ma2"
                  WHERE (("ma2"."master_id" = "c"."master_user_id") AND ("ma2"."assistant_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
                   FROM "public"."master_shares" "ms2"
                  WHERE (("ms2"."sharing_master_id" = "c"."master_user_id") AND ("ms2"."viewing_master_id" = ( SELECT "auth"."uid"() AS "uid")))))))))))))) OR ((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'superintendent'::"public"."user_role")))) AND "public"."can_access_project_row"("project_id"))));


