--
-- Name: project_workflow_steps Users can see steps for workflows they have access to; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Users can see steps for workflows they have access to" ON "public"."project_workflow_steps" FOR SELECT USING (("public"."is_dev"() OR (EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'master_technician'::"public"."user_role")))) OR ((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'assistant'::"public"."user_role")))) AND "public"."can_access_project_via_workflow"("workflow_id")) OR ((EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = 'superintendent'::"public"."user_role")))) AND "public"."can_access_project_via_workflow"("workflow_id")) OR (("assigned_to_name" IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['helpers'::"public"."user_role", 'subcontractor'::"public"."user_role"])) AND ("users"."name" IS NOT NULL) AND ("lower"(TRIM(BOTH FROM "users"."name")) = "lower"(TRIM(BOTH FROM "project_workflow_steps"."assigned_to_name")))))))));


--
-- Name: customers Users can see their own customers or customers from masters who; Type: POLICY; Schema: public; Owner: postgres
