CREATE POLICY "Users can see their own customers or customers from masters who" ON "public"."customers" FOR SELECT USING ((("master_user_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."users"
  WHERE (("users"."id" = ( SELECT "auth"."uid"() AS "uid")) AND ("users"."role" = ANY (ARRAY['dev'::"public"."user_role", 'master_technician'::"public"."user_role"]))))) OR (EXISTS ( SELECT 1
   FROM "public"."master_assistants"
  WHERE (("master_assistants"."master_id" = "customers"."master_user_id") AND ("master_assistants"."assistant_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM "public"."master_shares"
  WHERE (("master_shares"."sharing_master_id" = "customers"."master_user_id") AND ("master_shares"."viewing_master_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM "public"."users"
